import type { AlliedFlashcardDeck } from "./allied-health-flashcards";

export const rrtFlashcardDecks: AlliedFlashcardDeck[] = [
  {
    id: "abg-interpretation",
    name: "ABG Interpretation",
    description: "Arterial blood gas normal ranges, systematic interpretation steps, compensation rules, and clinical ABG scenarios for TMC/CSE exam prep",
    category: "ABG & Acid-Base",
    tier: "allied",
    cards: [
      { id: 1, front: "What is the normal range for arterial pH?", back: "7.35–7.45. pH < 7.35 = acidosis. pH > 7.45 = alkalosis. pH < 6.8 or > 7.8 is generally incompatible with life.", difficulty: 1, clinicalPearl: "Always start ABG interpretation by looking at pH first — it tells you the primary disorder direction." },
      { id: 2, front: "What is the normal range for PaCO₂?", back: "35–45 mmHg. PaCO₂ is the respiratory component. ↑ PaCO₂ (>45) = respiratory acidosis (hypoventilation). ↓ PaCO₂ (<35) = respiratory alkalosis (hyperventilation).", difficulty: 1 },
      { id: 3, front: "What is the normal range for HCO₃⁻?", back: "22–26 mEq/L. HCO₃⁻ is the metabolic component. ↓ HCO₃⁻ (<22) = metabolic acidosis. ↑ HCO₃⁻ (>26) = metabolic alkalosis.", difficulty: 1 },
      { id: 4, front: "What is the normal range for PaO₂?", back: "80–100 mmHg on room air. PaO₂ < 80 mmHg = hypoxemia. PaO₂ < 60 mmHg = severe hypoxemia (triggers respiratory failure criteria). Expected PaO₂ decreases with age: PaO₂ ≈ 104.2 − (0.27 × age).", difficulty: 1 },
      { id: 5, front: "What is the normal SaO₂ range?", back: "95–100%. SaO₂ < 90% corresponds roughly to PaO₂ < 60 mmHg (the steep portion of the oxyhemoglobin dissociation curve). SaO₂ < 88% in COPD patients is the threshold for supplemental O₂.", difficulty: 1 },
      { id: 6, front: "What are the 5 steps for systematic ABG interpretation?", back: "1) Evaluate pH (acidosis vs alkalosis). 2) Evaluate PaCO₂ (respiratory component). 3) Evaluate HCO₃⁻ (metabolic component). 4) Determine primary disorder (which component matches pH direction). 5) Assess compensation (full, partial, or uncompensated).", difficulty: 2, clinicalPearl: "Always match pH to the component that explains it — if pH is low and CO₂ is high, the primary disorder is respiratory acidosis, even if HCO₃⁻ is also abnormal." },
      { id: 7, front: "How do you identify respiratory acidosis on an ABG?", back: "pH < 7.35, PaCO₂ > 45 mmHg. Caused by hypoventilation (CO₂ retention). Common causes: COPD exacerbation, opioid/sedative overdose, neuromuscular disease (Guillain-Barré, myasthenia gravis), obesity hypoventilation syndrome.", difficulty: 1 },
      { id: 8, front: "How do you identify respiratory alkalosis on an ABG?", back: "pH > 7.45, PaCO₂ < 35 mmHg. Caused by hyperventilation (CO₂ blow-off). Common causes: anxiety/pain, early hypoxemia, pulmonary embolism, fever, sepsis, mechanical over-ventilation, pregnancy.", difficulty: 1 },
      { id: 9, front: "How do you identify metabolic acidosis on an ABG?", back: "pH < 7.35, HCO₃⁻ < 22 mEq/L. Caused by acid gain or bicarbonate loss. Common causes: DKA, lactic acidosis, renal failure, diarrhea, salicylate toxicity. Respiratory compensation: hyperventilation (Kussmaul breathing) to lower CO₂.", difficulty: 1 },
      { id: 10, front: "How do you identify metabolic alkalosis on an ABG?", back: "pH > 7.45, HCO₃⁻ > 26 mEq/L. Caused by acid loss or base gain. Common causes: prolonged vomiting/NG suction (HCl loss), diuretic use, excessive NaHCO₃ administration, hypokalemia. Respiratory compensation: hypoventilation to retain CO₂.", difficulty: 1 },
      { id: 11, front: "What is full compensation on an ABG?", back: "pH returns to normal range (7.35–7.45) while PaCO₂ and HCO₃⁻ remain abnormal. The body has compensated enough to normalize pH. Example: chronic COPD patient with pH 7.37, PaCO₂ 60, HCO₃⁻ 34 = fully compensated respiratory acidosis.", difficulty: 2 },
      { id: 12, front: "What is partial compensation on an ABG?", back: "pH is still abnormal but trending toward normal, with both PaCO₂ and HCO₃⁻ abnormal (the compensating system has started to respond but hasn't normalized pH). Example: pH 7.30, PaCO₂ 55, HCO₃⁻ 28.", difficulty: 2 },
      { id: 13, front: "What is uncompensated on an ABG?", back: "pH is abnormal, one component (CO₂ or HCO₃⁻) is abnormal, and the other is still within normal range. The compensating system has not yet responded. Example: pH 7.28, PaCO₂ 60, HCO₃⁻ 24 = uncompensated respiratory acidosis.", difficulty: 2 },
      { id: 14, front: "How does the body compensate for respiratory acidosis?", back: "Kidneys retain HCO₃⁻ and excrete H⁺. Acute: HCO₃⁻ rises 1 mEq/L per 10 mmHg rise in PaCO₂. Chronic: HCO₃⁻ rises 3.5 mEq/L per 10 mmHg rise in PaCO₂. Renal compensation takes 24–72 hours to become significant.", difficulty: 2, clinicalPearl: "If HCO₃⁻ is elevated with high CO₂, this indicates chronic (compensated) respiratory acidosis — don't just correct CO₂ rapidly or you'll cause post-hypercapnic alkalosis." },
      { id: 15, front: "How does the body compensate for metabolic acidosis?", back: "Lungs hyperventilate to blow off CO₂. Winter's formula predicts expected PaCO₂: PaCO₂ = (1.5 × HCO₃⁻) + 8 ± 2. If actual PaCO₂ differs from predicted, a concurrent respiratory disorder exists.", difficulty: 2 },
      { id: 16, front: "What is Winter's formula and when is it used?", back: "Expected PaCO₂ = (1.5 × HCO₃⁻) + 8 ± 2. Used in metabolic acidosis to determine if respiratory compensation is appropriate. If actual PaCO₂ > expected → concurrent respiratory acidosis. If actual PaCO₂ < expected → concurrent respiratory alkalosis.", difficulty: 3, clinicalPearl: "Winter's formula is essential for detecting mixed acid-base disorders. Always calculate it when metabolic acidosis is present." },
      { id: 17, front: "What is the anion gap and how is it calculated?", back: "Anion Gap = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L (or 10–14 with older methods). Elevated AG indicates accumulation of unmeasured anions (organic acids). Use MUDPILES mnemonic for causes.", difficulty: 2 },
      { id: 18, front: "What does the MUDPILES mnemonic stand for?", back: "Causes of elevated anion gap metabolic acidosis: Methanol, Uremia, DKA (diabetic ketoacidosis), Propylene glycol, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates.", difficulty: 2 },
      { id: 19, front: "What causes a normal anion gap (non-gap) metabolic acidosis?", back: "HCO₃⁻ loss with Cl⁻ retention (hyperchloremic). Causes include diarrhea, renal tubular acidosis (RTA), carbonic anhydrase inhibitors (acetazolamide), normal saline over-resuscitation, ureteral diversions.", difficulty: 2 },
      { id: 20, front: "What is the P/F ratio (PaO₂/FiO₂) and how is it used?", back: "PaO₂ divided by FiO₂ (as decimal). Normal: 400–500. Mild ARDS: 200–300. Moderate ARDS: 100–200. Severe ARDS: < 100. Example: PaO₂ 80 on FiO₂ 0.40 → P/F = 200 (moderate ARDS).", difficulty: 2, clinicalPearl: "P/F ratio standardizes oxygenation assessment across different FiO₂ levels — essential for ARDS classification per Berlin criteria." },
      { id: 21, front: "What is the A-a gradient (P(A-a)O₂) and how is it calculated?", back: "P(A-a)O₂ = PAO₂ − PaO₂. Calculate PAO₂ using alveolar gas equation: PAO₂ = (FiO₂ × (Pbar − PH₂O)) − (PaCO₂ / 0.8). Normal A-a gradient: (Age/4) + 4. On room air at sea level: PAO₂ ≈ 150 − (PaCO₂ × 1.25).", difficulty: 3 },
      { id: 22, front: "What does an elevated A-a gradient indicate?", back: "A problem at the alveolar-capillary level: V/Q mismatch, shunt (intrapulmonary or intracardiac), or diffusion impairment. A normal A-a gradient with hypoxemia suggests hypoventilation or low FiO₂ (high altitude) as the cause.", difficulty: 2 },
      { id: 23, front: "What ABG values indicate acute respiratory failure?", back: "Type I (hypoxemic): PaO₂ < 60 mmHg on room air. Type II (hypercapnic): PaCO₂ > 50 mmHg with pH < 7.35. Combined: both criteria present. Always correlate with clinical picture — chronic COPD patients may have baseline elevated CO₂.", difficulty: 2 },
      { id: 24, front: "How do you differentiate acute from chronic respiratory acidosis on ABG?", back: "Acute: pH drops 0.08 per 10 mmHg rise in CO₂; HCO₃⁻ rises ~1 per 10 CO₂. Chronic: pH drops only 0.03 per 10 mmHg rise in CO₂; HCO₃⁻ rises ~3.5 per 10 CO₂. Chronic = kidneys have had time to compensate.", difficulty: 3 },
      { id: 25, front: "A patient with DKA has pH 7.22, PaCO₂ 24, HCO₃⁻ 10. Interpret this ABG.", back: "Primary metabolic acidosis (pH ↓, HCO₃⁻ ↓↓) with respiratory compensation (PaCO₂ ↓ from hyperventilation). Check Winter's: expected PaCO₂ = (1.5 × 10) + 8 ± 2 = 21–25. Actual 24 is within range → appropriate compensation, no mixed disorder.", difficulty: 2 },
      { id: 26, front: "A COPD patient has pH 7.38, PaCO₂ 58, HCO₃⁻ 33. Interpret this ABG.", back: "Fully compensated respiratory acidosis. CO₂ is elevated (chronic hypoventilation) but pH is normal because kidneys have retained HCO₃⁻ over time. This is a typical baseline ABG for a stable COPD patient.", difficulty: 2 },
      { id: 27, front: "A patient on a ventilator has pH 7.52, PaCO₂ 28, HCO₃⁻ 24. What should you do?", back: "Uncompensated respiratory alkalosis — the patient is being over-ventilated. Action: decrease minute ventilation by reducing respiratory rate or tidal volume. HCO₃⁻ is normal, confirming the problem is purely respiratory.", difficulty: 2 },
      { id: 28, front: "What is a mixed acid-base disorder?", back: "Two or more primary acid-base disturbances occurring simultaneously. Example: metabolic acidosis + respiratory acidosis in a cardiac arrest patient. Clues: pH severely abnormal, compensation formulas don't match, or both CO₂ and HCO₃⁻ move in same direction relative to pH.", difficulty: 3 },
      { id: 29, front: "What is the normal base excess (BE) range and what does it indicate?", back: "Normal: −2 to +2 mEq/L. Positive BE (>+2) = metabolic alkalosis (excess base). Negative BE (<−2) = metabolic acidosis (base deficit). BE quantifies the metabolic component independent of respiratory factors.", difficulty: 2 },
      { id: 30, front: "How do you calculate oxygen content (CaO₂)?", back: "CaO₂ = (1.34 × Hgb × SaO₂) + (0.003 × PaO₂). Normal: 16–20 mL O₂/dL. The dissolved O₂ component (0.003 × PaO₂) is minimal; hemoglobin-bound O₂ is the dominant carrier. A low Hgb severely reduces O₂ content even with normal PaO₂.", difficulty: 3, clinicalPearl: "This formula shows why anemia is dangerous — even perfect PaO₂ and SaO₂ can't compensate for critically low hemoglobin." },
      { id: 31, front: "What is the Henderson-Hasselbalch equation?", back: "pH = 6.1 + log([HCO₃⁻] / (0.03 × PaCO₂)). This equation describes the relationship between pH, bicarbonate, and dissolved CO₂. It shows that pH depends on the RATIO of HCO₃⁻ to CO₂, not the absolute values.", difficulty: 3 },
      { id: 32, front: "A patient presents with pH 7.15, PaCO₂ 70, HCO₃⁻ 24. Interpret and identify the urgent concern.", back: "Uncompensated acute respiratory acidosis. Severe CO₂ retention with no metabolic compensation (HCO₃⁻ normal). This indicates acute ventilatory failure. Urgent intervention needed: possible intubation, or BiPAP if the patient can protect their airway.", difficulty: 2 },
      { id: 33, front: "What is the significance of a PaCO₂ that is acutely rising?", back: "Indicates worsening ventilatory failure. Rising PaCO₂ means the patient cannot adequately eliminate CO₂ (minute ventilation is insufficient). Clinical signs: altered mental status, somnolence, use of accessory muscles, diaphoresis. May require escalation to mechanical ventilation.", difficulty: 2 },
      { id: 34, front: "What is the normal pH of venous blood and how does it differ from arterial?", back: "Venous pH: 7.31–7.41 (slightly lower than arterial 7.35–7.45). Venous PaCO₂: 41–51 mmHg (slightly higher). Venous blood has more CO₂ and less O₂ since tissues have extracted O₂ and added CO₂. VBGs can estimate ABG trends but are less accurate for oxygenation.", difficulty: 2 },
      { id: 35, front: "How does temperature affect ABG results?", back: "Hypothermia: gases are more soluble → measured PaCO₂ and PaO₂ appear higher when warmed to 37°C in analyzer. pH appears lower. The alpha-stat method (no temperature correction) is most commonly used in clinical practice. Always note patient temperature on ABG requisition.", difficulty: 3 }
    ]
  },
  {
    id: "acid-base-disorders",
    name: "Acid-Base Disorders",
    description: "Clinical causes, pathophysiology, and management of metabolic and respiratory acid-base disturbances including mixed disorders",
    category: "ABG & Acid-Base",
    tier: "allied",
    cards: [
      { id: 101, front: "What are the common causes of respiratory acidosis?", back: "Acute: opioid/sedative overdose, neuromuscular disease (myasthenia gravis, Guillain-Barré), pneumothorax, severe asthma/COPD exacerbation, upper airway obstruction. Chronic: COPD, obesity hypoventilation syndrome (Pickwickian), kyphoscoliosis, neuromuscular disorders (ALS, muscular dystrophy).", difficulty: 1 },
      { id: 102, front: "What clinical signs indicate respiratory acidosis?", back: "Acute: headache, confusion, drowsiness progressing to coma, tremor, papilledema (from cerebral vasodilation). Chronic: may be asymptomatic if compensated. CO₂ narcosis occurs at very high PaCO₂ (>70-80 mmHg): obtundation, coma.", difficulty: 2 },
      { id: 103, front: "How is acute respiratory acidosis treated?", back: "Treat underlying cause + improve ventilation. Options: relieve obstruction, reverse opioids (naloxone), bronchodilators for bronchospasm, NIV (BiPAP) if patient can protect airway, invasive mechanical ventilation if severe (pH < 7.20 or declining mental status). Avoid correcting chronic CO₂ too rapidly.", difficulty: 2, clinicalPearl: "In chronic respiratory acidosis, rapid CO₂ correction causes post-hypercapnic metabolic alkalosis — reduce PaCO₂ gradually." },
      { id: 104, front: "What are the common causes of respiratory alkalosis?", back: "Anxiety/hyperventilation syndrome, pain, fever, early sepsis, hypoxemia (triggers hyperventilation), PE, CNS disorders (stroke, meningitis), pregnancy (progesterone stimulates ventilation), mechanical over-ventilation, hepatic encephalopathy, salicylate toxicity (early).", difficulty: 1 },
      { id: 105, front: "What clinical signs indicate respiratory alkalosis?", back: "Lightheadedness, perioral/extremity numbness/tingling (due to decreased ionized calcium), carpopedal spasm, palpitations, chest tightness, syncope. Severe: seizures, cardiac arrhythmias. Ionized Ca²⁺ drops because alkalosis increases protein binding of calcium.", difficulty: 2 },
      { id: 106, front: "What are the common causes of metabolic acidosis with an elevated anion gap?", back: "MUDPILES: Methanol ingestion, Uremia (renal failure), DKA/starvation ketoacidosis, Propylene glycol, Isoniazid/Iron, Lactic acidosis (shock, sepsis, liver failure, seizures), Ethylene glycol, Salicylates. Lactic acidosis and DKA are the most common.", difficulty: 2 },
      { id: 107, front: "What are the common causes of normal anion gap metabolic acidosis?", back: "Mnemonic HARDUPS: Hyperalimentation, Acetazolamide, Renal tubular acidosis, Diarrhea, Uretero-pelvic diversions (ileal conduit), Pancreatic fistula, Saline over-resuscitation. Hallmark: HCO₃⁻ lost is replaced by Cl⁻ (hyperchloremic).", difficulty: 2 },
      { id: 108, front: "What is lactic acidosis and what are its two types?", back: "Type A: inadequate tissue oxygenation → anaerobic metabolism. Causes: shock, severe hypoxemia, cardiac arrest, mesenteric ischemia. Type B: no tissue hypoxia. Causes: liver failure (can't clear lactate), metformin, malignancy, thiamine deficiency, seizures. Normal lactate: < 2 mmol/L.", difficulty: 2 },
      { id: 109, front: "What are the common causes of metabolic alkalosis?", back: "Chloride-responsive (urine Cl⁻ < 20): vomiting, NG suction, diuretic use (post-diuretic). Chloride-resistant (urine Cl⁻ > 20): primary hyperaldosteronism, Cushing syndrome, severe hypokalemia, Bartter/Gitelman syndrome, excessive alkali intake.", difficulty: 2 },
      { id: 110, front: "How does hypokalemia cause metabolic alkalosis?", back: "When K⁺ is low, cells exchange intracellular K⁺ for extracellular H⁺ → H⁺ moves into cells → extracellular alkalosis. In the kidneys, K⁺ depletion causes H⁺ secretion (instead of K⁺) and HCO₃⁻ reabsorption. Also, hypokalemia stimulates renal ammonia production.", difficulty: 3 },
      { id: 111, front: "How is metabolic alkalosis treated?", back: "Chloride-responsive: IV normal saline (0.9% NaCl), KCl replacement, hold diuretics. Chloride-resistant: treat underlying cause (surgery for hyperaldosteronism). Severe (pH > 7.60): acetazolamide (increases HCO₃⁻ excretion), or dilute HCl infusion in ICU setting.", difficulty: 2 },
      { id: 112, front: "What is a mixed respiratory and metabolic acidosis? Give an example.", back: "Both PaCO₂ is elevated AND HCO₃⁻ is low, creating severe acidosis. Example: cardiac arrest — tissue hypoperfusion causes lactic acidosis (metabolic) and apnea causes CO₂ retention (respiratory). pH drops dramatically. Requires both ventilatory support and circulatory resuscitation.", difficulty: 3 },
      { id: 113, front: "What is the delta-delta (Δ-Δ) ratio and when is it used?", back: "Δ Anion Gap / Δ HCO₃⁻. Used when AG is elevated to detect concurrent non-AG metabolic acidosis or metabolic alkalosis. Ratio < 1: concurrent non-AG metabolic acidosis. Ratio 1–2: pure AG metabolic acidosis. Ratio > 2: concurrent metabolic alkalosis.", difficulty: 3 },
      { id: 114, front: "How does the body compensate for metabolic alkalosis?", back: "Lungs hypoventilate to retain CO₂ (PaCO₂ rises ~0.7 mmHg per 1 mEq/L rise in HCO₃⁻). However, respiratory compensation is limited — PaCO₂ rarely exceeds 55 mmHg because hypoxemia and hypercapnia strongly stimulate ventilation.", difficulty: 2, clinicalPearl: "Respiratory compensation for metabolic alkalosis is the weakest of all compensatory mechanisms — the body won't allow dangerous hypoventilation." },
      { id: 115, front: "What is the expected CO₂ compensation for metabolic alkalosis?", back: "Expected PaCO₂ = (0.7 × HCO₃⁻) + 21 ± 2. If actual PaCO₂ > expected → concurrent respiratory acidosis. If actual PaCO₂ < expected → concurrent respiratory alkalosis. PaCO₂ compensation rarely exceeds 55 mmHg.", difficulty: 3 },
      { id: 116, front: "What are the dangers of severe alkalosis (pH > 7.60)?", back: "Decreased ionized calcium → tetany, seizures. Cardiac arrhythmias (prolonged QT). Hypokalemia worsens. Leftward shift of oxyhemoglobin curve → reduced O₂ release to tissues. Cerebral vasoconstriction → confusion, obtundation. Can be fatal if uncorrected.", difficulty: 2 },
      { id: 117, front: "What are the dangers of severe acidosis (pH < 7.20)?", back: "Decreased cardiac contractility and output. Vasodilation → hypotension refractory to vasopressors. Hyperkalemia (H⁺/K⁺ exchange). Rightward shift of oxyhemoglobin curve → enhanced O₂ unloading (initially helpful). Ventricular arrhythmias. CNS depression.", difficulty: 2 },
      { id: 118, front: "When is sodium bicarbonate administration indicated in acidosis?", back: "Generally reserved for pH < 7.1 or HCO₃⁻ < 8 mEq/L. Used in hyperkalemia with ECG changes, tricyclic antidepressant overdose, and specific toxic ingestions (methanol, ethylene glycol). Risks: rebound alkalosis, hypernatremia, CO₂ generation (ensure adequate ventilation).", difficulty: 2 },
      { id: 119, front: "What is DKA and what are its characteristic ABG findings?", back: "Diabetic ketoacidosis: insulin deficiency → lipolysis → ketone body production (beta-hydroxybutyrate, acetoacetate). ABG: pH < 7.30, HCO₃⁻ low (often < 15), elevated anion gap, PaCO₂ low (respiratory compensation — Kussmaul breathing). Also: hyperglycemia, ketonuria, ketonemia.", difficulty: 2 },
      { id: 120, front: "What is the osmolar gap and when is it useful?", back: "Calculated osmolality = 2(Na) + glucose/18 + BUN/2.8. Osmolar gap = measured − calculated. Normal: < 10 mOsm/kg. Elevated gap with AG metabolic acidosis suggests toxic alcohol ingestion (methanol, ethylene glycol, isopropanol). Always check when AG metabolic acidosis etiology is unclear.", difficulty: 3 },
      { id: 121, front: "How does chronic kidney disease cause metabolic acidosis?", back: "Kidneys lose ability to excrete H⁺ and regenerate HCO₃⁻. Early CKD: non-AG acidosis (impaired ammoniagenesis). Advanced CKD (GFR < 20): AG acidosis from retained uremic toxins (sulfate, phosphate, organic acids). HCO₃⁻ typically 12–20 mEq/L. Treat with oral NaHCO₃.", difficulty: 2 },
      { id: 122, front: "What is contraction alkalosis?", back: "Metabolic alkalosis caused by volume depletion (e.g., from diuretics or vomiting). Loss of NaCl-rich, HCO₃⁻-poor fluid concentrates the remaining HCO₃⁻. Additionally, volume depletion stimulates aldosterone → increased H⁺ and K⁺ excretion → alkalosis maintained. Treatment: IV normal saline.", difficulty: 2 },
      { id: 123, front: "What is posthypercapnic metabolic alkalosis?", back: "Occurs when chronic respiratory acidosis (high CO₂) is rapidly corrected (e.g., intubation and aggressive ventilation). Kidneys had retained HCO₃⁻ for compensation — when CO₂ is suddenly lowered, the elevated HCO₃⁻ remains → metabolic alkalosis. Prevention: reduce PaCO₂ gradually.", difficulty: 3, clinicalPearl: "This is a common ICU pitfall — always target a PaCO₂ near the patient's baseline, not normal, when ventilating chronic CO₂ retainers." },
      { id: 124, front: "What are the renal tubular acidoses (RTA) and their key features?", back: "Type 1 (distal): can't secrete H⁺ → severe acidosis, urine pH > 5.3, hypokalemia. Type 2 (proximal): can't reabsorb HCO₃⁻ → milder acidosis, hypokalemia. Type 4 (hypoaldosteronism): hyperkalemia, mild acidosis, urine pH < 5.5. All are non-AG metabolic acidosis.", difficulty: 3 },
      { id: 125, front: "How does salicylate toxicity affect acid-base balance?", back: "Creates a unique mixed disorder: initial respiratory alkalosis (salicylates stimulate medullary respiratory center) + metabolic acidosis (salicylates uncouple oxidative phosphorylation → lactic acidosis + ketoacidosis). Early: respiratory alkalosis dominates. Late: AG metabolic acidosis dominates.", difficulty: 3 },
      { id: 126, front: "What is the significance of the urine anion gap in metabolic acidosis?", back: "Urine AG = Na⁺(u) + K⁺(u) − Cl⁻(u). Negative UAG: appropriate renal response (kidneys are excreting NH₄⁺/acid) → GI cause (diarrhea). Positive UAG: inappropriate renal response (kidneys can't excrete acid) → RTA. Helps differentiate renal from extra-renal causes.", difficulty: 3 },
      { id: 127, front: "What ABG pattern is seen in a patient with COPD exacerbation?", back: "Acute-on-chronic respiratory acidosis: pH mildly-moderately low (7.25–7.34), PaCO₂ significantly elevated (60–80+ mmHg), HCO₃⁻ elevated (30–40 — chronic compensation) but not enough to normalize pH (acute worsening). PaO₂ low. Treatment: controlled O₂, bronchodilators, BiPAP.", difficulty: 2 },
      { id: 128, front: "What is permissive hypercapnia?", back: "A ventilatory strategy allowing PaCO₂ to rise above normal (up to 60–80 mmHg) to maintain lung-protective tidal volumes (6 mL/kg IBW) in ARDS. Acceptable as long as pH stays > 7.20 (some protocols > 7.15). Contraindications: elevated ICP, severe pulmonary hypertension, significant cardiac dysfunction.", difficulty: 2 },
      { id: 129, front: "How do you calculate the expected PaCO₂ for acute respiratory acidosis compensation?", back: "In acute respiratory acidosis, HCO₃⁻ rises ~1 mEq/L for every 10 mmHg rise in PaCO₂ (cellular buffering). If HCO₃⁻ is higher than expected, suspect concurrent metabolic alkalosis or chronic component. This occurs within minutes to hours.", difficulty: 3 },
      { id: 130, front: "What is the Stewart (strong ion difference) approach to acid-base?", back: "An alternative to the traditional Henderson-Hasselbalch approach. Three independent variables determine pH: 1) Strong ion difference (SID) = (Na + K + Ca + Mg) − (Cl + lactate), 2) Total weak acids (albumin, phosphate), 3) PaCO₂. Explains hyperchloremic acidosis and albumin-related alkalosis.", difficulty: 3 }
    ]
  },
  {
    id: "mechanical-ventilation-basics",
    name: "Mechanical Ventilation Basics",
    description: "Fundamentals of mechanical ventilation including modes, settings, indications, and initial setup for respiratory therapy board exams",
    category: "Mechanical Ventilation",
    tier: "allied",
    cards: [
      { id: 201, front: "What are the primary indications for mechanical ventilation?", back: "1) Acute respiratory failure (Type I: PaO₂ < 60, Type II: PaCO₂ > 50 with pH < 7.30). 2) Airway protection (GCS ≤ 8). 3) Excessive work of breathing/respiratory muscle fatigue. 4) Post-operative ventilatory support. 5) Neuromuscular disease with declining vital capacity.", difficulty: 1 },
      { id: 202, front: "What is Volume-Controlled Ventilation (VCV)?", back: "The ventilator delivers a set tidal volume at a set flow rate. Pressure varies based on compliance and resistance. The clinician sets: Vt, rate, flow rate, flow pattern, FiO₂, PEEP. Advantage: guaranteed tidal volume. Disadvantage: pressure may rise dangerously if compliance worsens.", difficulty: 1 },
      { id: 203, front: "What is Pressure-Controlled Ventilation (PCV)?", back: "The ventilator delivers gas to a set inspiratory pressure for a set inspiratory time. Volume varies based on compliance and resistance. The clinician sets: inspiratory pressure, rate, I-time, FiO₂, PEEP. Advantage: pressure-limited (safer). Disadvantage: volume varies — must monitor Vt closely.", difficulty: 1 },
      { id: 204, front: "What is Assist-Control (A/C) mode?", back: "Every breath (triggered by patient or time) receives full ventilator support (set Vt or pressure). If patient triggers → assisted breath. If no trigger → control breath at set rate. Provides full ventilatory support. Risk: hyperventilation if patient triggers rapidly (respiratory alkalosis).", difficulty: 1, clinicalPearl: "A/C is the most commonly used initial ventilator mode for acute respiratory failure because it guarantees full support with every breath." },
      { id: 205, front: "What is SIMV (Synchronized Intermittent Mandatory Ventilation)?", back: "Delivers a set number of mandatory breaths synchronized with patient effort. Between mandatory breaths, patient can take spontaneous breaths (with or without pressure support). Used as a weaning mode. Disadvantage: increased work of breathing for spontaneous breaths if PS is inadequate.", difficulty: 2 },
      { id: 206, front: "What is Pressure Support Ventilation (PSV)?", back: "A spontaneous mode — every breath is patient-triggered and pressure-supported. Clinician sets: pressure support level, FiO₂, PEEP. The patient controls rate, Vt (based on PS level), and I-time. Used for weaning and patients with adequate respiratory drive. Requires a backup rate (apnea ventilation).", difficulty: 2 },
      { id: 207, front: "What is PRVC (Pressure-Regulated Volume Control)?", back: "A dual-control mode that targets a set tidal volume but uses decelerating flow (pressure-targeted delivery). The ventilator automatically adjusts inspiratory pressure breath-to-breath to achieve the target Vt. Combines benefits of volume guarantee with pressure-limited delivery.", difficulty: 2 },
      { id: 208, front: "What is CPAP mode on a ventilator?", back: "Continuous Positive Airway Pressure — maintains constant positive pressure throughout inspiration and expiration during spontaneous breathing. No mandatory breaths delivered. Patient must have adequate respiratory drive. Used for weaning readiness assessment, sleep apnea, and mild respiratory support.", difficulty: 1 },
      { id: 209, front: "What is BiPAP/bilevel ventilation?", back: "Provides two levels of positive pressure: IPAP (inspiratory positive airway pressure) and EPAP (expiratory positive airway pressure). Pressure support = IPAP − EPAP. Used non-invasively (NIV) for COPD exacerbation, acute cardiogenic pulmonary edema, and respiratory failure in patients who can protect their airway.", difficulty: 2 },
      { id: 210, front: "What are the initial ventilator settings for a standard adult patient?", back: "Mode: A/C (volume or pressure). Vt: 6-8 mL/kg IBW. Rate: 12-16 breaths/min. FiO₂: 100% initially, then titrate to SpO₂ 92-96%. PEEP: 5 cmH₂O (physiologic). Flow rate: 40-60 L/min (VCV). I:E ratio: 1:2 to 1:3.", difficulty: 1 },
      { id: 211, front: "How do you calculate ideal body weight (IBW)?", back: "Males: IBW (kg) = 50 + 2.3 × (height in inches − 60). Females: IBW (kg) = 45.5 + 2.3 × (height in inches − 60). Tidal volume is ALWAYS based on IBW, not actual body weight. This is critical for ARDS lung-protective ventilation.", difficulty: 2, clinicalPearl: "Using actual weight in obese patients leads to dangerously high tidal volumes. Always calculate and use IBW for ventilator settings." },
      { id: 212, front: "What is the I:E ratio and why is it important?", back: "Inspiratory-to-Expiratory time ratio. Normal: 1:2 to 1:3. Shorter I-time allows more time for exhalation (important in obstructive disease to prevent air trapping). Inverse ratio (1:1 to 2:1) may be used in severe ARDS to improve oxygenation but increases mean airway pressure and auto-PEEP risk.", difficulty: 2 },
      { id: 213, front: "What is minute ventilation (V̇E) and how is it calculated?", back: "V̇E = Vt × Respiratory Rate. Normal: 5-8 L/min. V̇E determines CO₂ elimination. To decrease PaCO₂ → increase V̇E (increase rate or Vt). To increase PaCO₂ → decrease V̇E. Dead space ventilation reduces effective alveolar ventilation.", difficulty: 1 },
      { id: 214, front: "What is the trigger sensitivity and how does it work?", back: "The mechanism that detects patient effort to initiate a breath. Flow trigger: detects change in circuit flow (typically 1-3 L/min — more sensitive). Pressure trigger: detects negative pressure (typically −1 to −2 cmH₂O). Auto-trigger: too sensitive → breaths without patient effort. Insensitive: increases work of breathing.", difficulty: 2 },
      { id: 215, front: "What is the cycling mechanism in mechanical ventilation?", back: "Determines when inspiration ends and exhalation begins. Volume-cycled: ends when set Vt delivered. Time-cycled: ends when set I-time reached. Flow-cycled: ends when flow drops to set percentage of peak (typically 25% in PSV). Pressure-cycled: ends when set pressure reached (safety mechanism).", difficulty: 2 },
      { id: 216, front: "What is the difference between peak inspiratory pressure (PIP) and plateau pressure (Pplat)?", back: "PIP = total pressure during inspiration (reflects airway resistance + compliance). Pplat = pressure during an inspiratory hold (reflects only compliance — alveolar pressure). Normal Pplat < 30 cmH₂O. If PIP is high but Pplat is normal → resistance problem (bronchospasm, secretions, kinked tube).", difficulty: 2, clinicalPearl: "Pplat > 30 cmH₂O increases risk of barotrauma. If Pplat is high → compliance problem (ARDS, pneumothorax, pulmonary edema, abdominal distension)." },
      { id: 217, front: "What is PEEP and what is its primary purpose?", back: "Positive End-Expiratory Pressure — maintains positive pressure at end exhalation to prevent alveolar collapse. Physiologic PEEP: 5 cmH₂O. Therapeutic PEEP: 8-20+ cmH₂O. Benefits: recruits collapsed alveoli, improves FRC, improves oxygenation, reduces shunt fraction.", difficulty: 1 },
      { id: 218, front: "What are the adverse effects of excessive PEEP?", back: "Decreased venous return → decreased cardiac output → hypotension. Overdistension of compliant alveoli (volutrauma). Increased intracranial pressure. Barotrauma (pneumothorax). Increased dead space. Hepatic/renal dysfunction from decreased perfusion. Auto-PEEP worsening.", difficulty: 2 },
      { id: 219, front: "What is FiO₂ and how should it be managed?", back: "Fraction of inspired oxygen (0.21 to 1.0). Start at 1.0 for acute respiratory failure, then titrate down to maintain SpO₂ 92-96% (88-92% in COPD). Goal: lowest FiO₂ that maintains adequate oxygenation. FiO₂ > 0.60 for prolonged periods → oxygen toxicity risk (absorption atelectasis, pulmonary fibrosis).", difficulty: 1 },
      { id: 220, front: "What is lung-protective ventilation (ARDSNet protocol)?", back: "Vt: 4-6 mL/kg IBW. Plateau pressure: < 30 cmH₂O. PEEP: per PEEP/FiO₂ table (higher PEEP with higher FiO₂). pH target: > 7.20 (permissive hypercapnia acceptable). SpO₂: 88-95%. This strategy reduces VILI (ventilator-induced lung injury) and mortality in ARDS.", difficulty: 2 },
      { id: 221, front: "What are the components of ventilator-induced lung injury (VILI)?", back: "Volutrauma: overdistension from excessive Vt. Barotrauma: high pressure causing pneumothorax/pneumomediastinum. Atelectrauma: repeated opening/closing of alveoli. Biotrauma: inflammatory mediator release from mechanical injury → systemic inflammation (can cause MODS). Prevented by lung-protective strategies.", difficulty: 2 },
      { id: 222, front: "What is auto-PEEP (intrinsic PEEP) and how is it detected?", back: "Air trapping from incomplete exhalation creating positive pressure above set PEEP. Causes: high minute ventilation, bronchospasm, short expiratory time, high airway resistance. Detection: expiratory hold maneuver — if total PEEP > set PEEP, the difference is auto-PEEP. Also suspect if flow doesn't return to zero before next breath.", difficulty: 2 },
      { id: 223, front: "How do you correct auto-PEEP?", back: "1) Decrease respiratory rate (increase expiratory time). 2) Decrease Vt. 3) Increase expiratory time (decrease I:E ratio). 4) Bronchodilators if bronchospasm present. 5) Reduce inspiratory time. 6) Consider increasing set PEEP to 75-80% of auto-PEEP (reduces triggering effort for patient).", difficulty: 2 },
      { id: 224, front: "What is Airway Pressure Release Ventilation (APRV)?", back: "An inverse-ratio, bilevel ventilation mode. Applies high CPAP (P-high) for a long time (T-high, 4-6 seconds) with brief releases to low pressure (P-low) for a short time (T-low, 0.5-0.8 seconds). Maintains lung recruitment. Used in ARDS. Allows spontaneous breathing throughout the cycle.", difficulty: 3 },
      { id: 225, front: "What is HFOV (High-Frequency Oscillatory Ventilation)?", back: "Delivers very small tidal volumes (1-3 mL/kg) at very high rates (3-15 Hz = 180-900 breaths/min) with a constant mean airway pressure. Maintains lung recruitment with minimal volume change. Used in refractory ARDS (rescue therapy) and neonates. Requires special ventilator and deep sedation/paralysis.", difficulty: 3 },
      { id: 226, front: "What is the flow waveform in volume ventilation and what are the types?", back: "Square (constant) flow: delivers Vt at constant rate. PIP is higher. Decelerating (descending ramp): flow starts high, decreases. Better gas distribution, lower PIP, higher mean airway pressure. Accelerating and sine wave patterns also exist but rarely used. Most clinicians prefer decelerating.", difficulty: 2 },
      { id: 227, front: "What are the indications for non-invasive ventilation (NIV)?", back: "Strong evidence: COPD exacerbation with respiratory acidosis, acute cardiogenic pulmonary edema, immunocompromised patients with respiratory failure. Moderate evidence: post-extubation support, pre-oxygenation before intubation. Contraindications: facial trauma, inability to protect airway, hemodynamic instability, copious secretions.", difficulty: 2 },
      { id: 228, front: "How does increasing respiratory rate affect CO₂ on the ventilator?", back: "Increasing RR increases minute ventilation (V̇E = Vt × RR) → more CO₂ eliminated → PaCO₂ decreases. However, excessive RR shortens expiratory time → risk of auto-PEEP (especially in obstructive disease). Also, rapid rates increase dead space ventilation proportion, diminishing CO₂ reduction benefits.", difficulty: 1 },
      { id: 229, front: "How do you adjust FiO₂ and PEEP to improve oxygenation?", back: "Step 1: If FiO₂ > 0.60, increase PEEP (recruits alveoli, reduces shunt). Step 2: Use ARDSNet PEEP/FiO₂ tables. PEEP improves oxygenation by maintaining alveolar recruitment. FiO₂ increases PAO₂. Oxygenation is primarily managed with FiO₂ and PEEP; ventilation (CO₂) is managed with Vt and RR.", difficulty: 2, clinicalPearl: "Remember: oxygenation = FiO₂ + PEEP; ventilation = rate + volume. This is the fundamental principle of ventilator management." },
      { id: 230, front: "What are the contraindications to NIV (non-invasive ventilation)?", back: "Absolute: cardiac/respiratory arrest, inability to protect airway, facial burns/trauma/surgery, copious secretions, life-threatening hypoxemia. Relative: GCS < 10, hemodynamic instability, undrained pneumothorax, upper GI surgery/bleed, patient non-compliance, inability to fit mask properly.", difficulty: 2 },
      { id: 231, front: "What is the difference between mandatory and spontaneous breaths?", back: "Mandatory: ventilator determines timing and/or volume/pressure. Patient may trigger but the ventilator controls delivery. Spontaneous: patient determines timing, flow, and volume. May receive pressure support. Understanding this distinction is key to understanding ventilator modes.", difficulty: 1 },
      { id: 232, front: "What is an inspiratory hold (plateau) maneuver?", back: "A brief occlusion of the expiratory valve at end-inspiration (0.5-2 seconds) with zero flow. Allows equilibration of pressure throughout the circuit and lungs. The resulting pressure = Pplat (alveolar pressure). Used to calculate static compliance and assess alveolar overdistension. Only valid in VCV.", difficulty: 2 },
      { id: 233, front: "What is the difference between invasive and non-invasive ventilation?", back: "Invasive: delivered through ETT or tracheostomy. Provides definitive airway protection. Full range of modes/settings. Disadvantages: VAP risk, sedation needs, vocal cord injury. Non-invasive: delivered via face/nasal mask or helmet. No airway protection. Better comfort. Lower VAP risk. Limited by patient cooperation.", difficulty: 1 },
      { id: 234, front: "What is the driving pressure and why is it important?", back: "Driving pressure = Pplat − PEEP. Represents the pressure distending the lungs above PEEP. Target: < 15 cmH₂O. Studies show driving pressure is the strongest ventilator variable associated with mortality in ARDS. Reflects the strain applied to aerated lung tissue (functional lung size).", difficulty: 2, clinicalPearl: "Driving pressure may be more important than Vt or Pplat individually because it accounts for the amount of functional lung available." },
      { id: 235, front: "What is the role of sedation in mechanically ventilated patients?", back: "Goals: patient comfort, ventilator synchrony, anxiety/pain management. RASS scale: target −2 to 0 (light sedation) in most patients. Daily sedation interruption (SAT) reduces ventilator days and ICU stay. Deep sedation increases delirium, VAP, ICU length of stay, and mortality. Use analgesia-first approach.", difficulty: 2 }
    ]
  },
  {
    id: "vent-settings-parameters",
    name: "Ventilator Settings & Parameters",
    description: "Detailed ventilator parameter management including PEEP, FiO₂, tidal volume, compliance, and pressure targets for RRT certification",
    category: "Mechanical Ventilation",
    tier: "allied",
    cards: [
      { id: 301, front: "What is the optimal tidal volume for mechanically ventilated patients?", back: "6-8 mL/kg IBW for most patients. 4-6 mL/kg IBW for ARDS (lung-protective). Never use actual body weight in obese patients. Higher Vt increases risk of VILI. Lower Vt may cause atelectasis if PEEP is insufficient.", difficulty: 1 },
      { id: 302, front: "What is the ARDSNet PEEP/FiO₂ table (lower PEEP)?", back: "FiO₂ 0.3→PEEP 5, FiO₂ 0.4→PEEP 5-8, FiO₂ 0.5→PEEP 8-10, FiO₂ 0.6→PEEP 10, FiO₂ 0.7→PEEP 10-14, FiO₂ 0.8→PEEP 14, FiO₂ 0.9→PEEP 14-18, FiO₂ 1.0→PEEP 18-24. Used to titrate PEEP and FiO₂ together for optimal oxygenation in ARDS.", difficulty: 2 },
      { id: 303, front: "What is the significance of plateau pressure (Pplat)?", back: "Reflects alveolar distending pressure. Target: < 30 cmH₂O. Measured during inspiratory hold (zero flow). If Pplat > 30 → decrease Vt (accept permissive hypercapnia) or increase sedation/paralysis. Elevated Pplat indicates decreased compliance (stiff lungs, chest wall restriction, abdominal distension).", difficulty: 2 },
      { id: 304, front: "How do you calculate static compliance (Cstat)?", back: "Cstat = Vt / (Pplat − PEEP). Normal: 60-100 mL/cmH₂O. Decreased in: ARDS, pulmonary fibrosis, pulmonary edema, pneumothorax, atelectasis, chest wall restriction, abdominal distension. Measures lung + chest wall distensibility without flow resistance.", difficulty: 2 },
      { id: 305, front: "How do you calculate dynamic compliance (Cdyn)?", back: "Cdyn = Vt / (PIP − PEEP). Always lower than Cstat because PIP includes resistance component. Decreased Cdyn with normal Cstat → increased airway resistance (bronchospasm, secretions, kinked ETT). Decreased Cdyn AND Cstat → decreased lung compliance.", difficulty: 2, clinicalPearl: "Comparing Cdyn and Cstat helps distinguish resistance problems from compliance problems at the bedside." },
      { id: 306, front: "How do you calculate airway resistance (Raw)?", back: "Raw = (PIP − Pplat) / Flow. Normal: 0.5-2.5 cmH₂O/L/sec. Increased in: bronchospasm, secretions, small/kinked ETT, mucosal edema. The pressure difference between PIP and Pplat represents the resistive component of airway pressure.", difficulty: 2 },
      { id: 307, front: "What is mean airway pressure (Paw) and what affects it?", back: "Average pressure throughout the respiratory cycle. Paw is the primary determinant of oxygenation on the ventilator. Increased by: higher PEEP, higher Vt, higher rate, longer I-time, higher PIP. Higher Paw improves oxygenation but may decrease cardiac output.", difficulty: 2 },
      { id: 308, front: "What is the flow rate setting and how does it affect ventilation?", back: "In VCV: set flow rate determines how fast Vt is delivered. Higher flow (60-80 L/min): shorter I-time, more E-time (good for obstructive disease), higher PIP. Lower flow (30-40 L/min): longer I-time, better gas distribution, lower PIP but less E-time. Typical: 40-60 L/min.", difficulty: 2 },
      { id: 309, front: "What is the significance of the PIP-Pplat gradient?", back: "PIP − Pplat represents the pressure needed to overcome airway resistance. Normal: < 5-10 cmH₂O. Elevated gradient (>10): increased resistance (bronchospasm, secretions, narrow/kinked ETT, biting on tube). Normal gradient with high pressures: compliance problem, not resistance.", difficulty: 2 },
      { id: 310, front: "What is the concept of best PEEP?", back: "The PEEP level that optimizes oxygenation while minimizing hemodynamic compromise and overdistension. Methods to determine: PEEP/FiO₂ tables, best compliance (decremental PEEP trial), pressure-volume curve (lower inflection point), esophageal manometry (transpulmonary pressure), CT imaging.", difficulty: 3 },
      { id: 311, front: "How does PEEP affect hemodynamics?", back: "PEEP increases intrathoracic pressure → decreases venous return → decreases RV preload → decreases cardiac output (especially in hypovolemic patients). Can also increase RV afterload (compresses pulmonary vasculature). May increase LV afterload by reducing transmural pressure difference. Monitor BP and CO when increasing PEEP.", difficulty: 2 },
      { id: 312, front: "What is the PEEP/FiO₂ titration approach?", back: "Increase FiO₂ and PEEP together per protocol tables. First, optimize PEEP to recruit alveoli and reduce shunt. Then, wean FiO₂ to < 0.60. If adequate oxygenation with FiO₂ ≤ 0.40 and PEEP ≤ 5-8 → may be ready for weaning. Avoid prolonged high FiO₂ (oxygen toxicity).", difficulty: 2 },
      { id: 313, front: "What is the effect of inspiratory time on ventilation?", back: "Longer I-time: improves gas distribution, increases mean airway pressure (improves oxygenation), but reduces E-time (risk of auto-PEEP). Shorter I-time: more E-time (prevents air trapping in obstructive disease), reduces mean airway pressure. I-time in PCV directly set; in VCV determined by Vt and flow rate.", difficulty: 2 },
      { id: 314, front: "How do you manage high PIP alarm?", back: "Systematic approach: 1) Check patient (coughing, biting, fighting vent → suction/sedate). 2) Perform inspiratory hold — if Pplat high → compliance problem (pneumothorax, mainsteam intubation, pulmonary edema). If Pplat normal → resistance problem (bronchospasm, secretions, kinked tube). 3) Treat cause.", difficulty: 2 },
      { id: 315, front: "What is the transpulmonary pressure and how is it measured?", back: "Transpulmonary pressure (PL) = Airway pressure − Pleural pressure. Pleural pressure estimated via esophageal balloon manometry. PL reflects true lung-distending pressure (separating lung from chest wall). Target end-inspiratory PL: < 20-25 cmH₂O. Used to optimize PEEP in obese patients and chest wall restriction.", difficulty: 3 },
      { id: 316, front: "What is the alveolar ventilation equation?", back: "V̇A = (Vt − Vd) × RR, where V̇A = alveolar ventilation, Vd = dead space volume. Anatomic dead space ≈ 1 mL/lb IBW (about 150 mL in average adult). Effective CO₂ elimination depends on alveolar ventilation, not total minute ventilation.", difficulty: 2 },
      { id: 317, front: "How does dead space affect ventilation?", back: "Dead space = ventilated but not perfused lung. Anatomic (airways): ~150 mL. Alveolar: pulmonary embolism, overdistension, decreased cardiac output. Vd/Vt ratio: normal 0.20-0.40. Increased Vd/Vt → need more minute ventilation to maintain CO₂ clearance. Measured by capnography (PaCO₂ − PETCO₂ gradient).", difficulty: 2 },
      { id: 318, front: "What are the key differences between volume and pressure ventilation?", back: "Volume: guaranteed Vt, variable pressure. Risk: high pressures if compliance decreases. Pressure: set pressure limit, variable Vt. Risk: hypoventilation if compliance worsens. Volume better for reliable minute ventilation. Pressure better for limiting peak pressure. Both can achieve same outcomes with proper monitoring.", difficulty: 1 },
      { id: 319, front: "What is the rise time (pressurization rate) setting?", back: "Controls how quickly pressure reaches the set level at the beginning of inspiration. Fast rise time (short): delivers flow quickly → comfortable for high-demand patients, higher peak flow. Slow rise time (long): gentle flow delivery → more comfortable for some patients but may increase work of breathing. Adjust based on patient comfort.", difficulty: 2 },
      { id: 320, front: "What is the expiratory sensitivity (cycle off) setting in PSV?", back: "Determines the percentage of peak inspiratory flow at which inspiration terminates. Default: typically 25% of peak flow. Higher % (30-50%): shorter inspiration, useful for COPD (prevents air trapping). Lower % (10-20%): longer inspiration. Adjusting improves patient-ventilator synchrony.", difficulty: 2 },
      { id: 321, front: "What is open lung ventilation?", back: "Strategy to recruit and keep alveoli open using: adequate PEEP (above closing pressure), recruitment maneuvers (sustained inflation 30-40 cmH₂O for 30-40 seconds), low Vt to prevent overdistension. Goal: maximize aerated lung volume, minimize cyclic opening/closing (atelectrauma). Used in ARDS management.", difficulty: 2 },
      { id: 322, front: "What is a recruitment maneuver?", back: "Brief application of sustained high pressure (30-40 cmH₂O for 30-40 seconds) or stepwise PEEP increases to open collapsed alveoli. Used in ARDS after disconnection, desaturation, or initial intubation. Risks: hypotension, barotrauma, arrhythmia. Requires hemodynamic monitoring. Follow with adequate PEEP to maintain recruitment.", difficulty: 2 },
      { id: 323, front: "How do you ventilate a patient with severe asthma/status asthmaticus?", back: "Key: prevent auto-PEEP. Low Vt (6-8 mL/kg). Low rate (8-12). High inspiratory flow (80-100 L/min to shorten I-time). Long expiratory time (I:E ratio 1:3 or 1:4). Accept permissive hypercapnia. Monitor auto-PEEP. Aggressive bronchodilators. Avoid high PEEP. Keep Pplat < 30.", difficulty: 2 },
      { id: 324, front: "How do you ventilate a COPD patient?", back: "Goals: prevent auto-PEEP, achieve permissive hypercapnia to patient's baseline. Moderate Vt (6-8 mL/kg IBW). Rate 10-14 (adequate E-time). Flow 50-60 L/min. PEEP 5-8 (may apply ~80% of measured auto-PEEP to reduce triggering effort). Target patient's baseline PaCO₂, not normal. Monitor auto-PEEP closely.", difficulty: 2, clinicalPearl: "Don't normalize the PaCO₂ in chronic CO₂ retainers — target their baseline (often 50-60 mmHg) to prevent posthypercapnic alkalosis." },
      { id: 325, front: "What is the backup rate (apnea ventilation) and when does it activate?", back: "A safety feature in spontaneous modes (PSV, CPAP). If the patient fails to trigger a breath within a set apnea interval (typically 20 seconds), the ventilator switches to a preset backup mode (usually A/C) at a set rate. Prevents apnea from going unventilated. Must be properly set.", difficulty: 1 },
      { id: 326, front: "What is proportional assist ventilation (PAV)?", back: "A mode where the ventilator amplifies the patient's own effort proportionally. Clinician sets a percentage of support (e.g., 80%). The harder the patient breathes, the more support provided. Promotes natural breathing patterns. Requires intact respiratory drive. May improve patient-ventilator synchrony.", difficulty: 3 },
      { id: 327, front: "What is NAVA (Neurally Adjusted Ventilatory Assist)?", back: "Uses diaphragmatic electrical activity (Edi) detected by a nasogastric catheter with embedded electrodes to trigger and cycle the ventilator. Pressure delivered is proportional to Edi signal. Advantages: best synchrony, avoids trigger delays, cannot over-assist. Requires special equipment.", difficulty: 3 },
      { id: 328, front: "What is the effect of positive pressure ventilation on intracranial pressure?", back: "Positive pressure → increases intrathoracic pressure → impedes cerebral venous drainage → increases ICP. PEEP has the greatest effect on ICP. Management in TBI: keep PEEP as low as possible (while maintaining oxygenation), elevate head of bed 30°, avoid hyperventilation (PaCO₂ 35-40), monitor ICP.", difficulty: 2 },
      { id: 329, front: "How does mechanical ventilation affect renal function?", back: "Positive pressure ventilation → decreased cardiac output → decreased renal perfusion → decreased urine output. Also: increased ADH release (posterior pituitary stimulation), decreased ANP release, sympathetic activation. Result: fluid retention, decreased UOP. Resolves with ventilator weaning.", difficulty: 2 },
      { id: 330, front: "What is ventilator-associated pneumonia (VAP) and how is it prevented?", back: "Pneumonia developing >48 hours after intubation. Prevention bundle: HOB elevation 30-45°, daily sedation interruption, daily SAT/SBT assessment, oral care with chlorhexidine, peptic ulcer prophylaxis, DVT prophylaxis, subglottic secretion drainage, cuff pressure 20-30 cmH₂O, minimize ventilator days.", difficulty: 2 }
    ]
  },
  {
    id: "vent-alarms-troubleshooting",
    name: "Ventilator Alarms & Troubleshooting",
    description: "Identification and management of ventilator alarms, patient-ventilator asynchrony, and emergency troubleshooting scenarios",
    category: "Mechanical Ventilation",
    tier: "allied",
    cards: [
      { id: 401, front: "What are the causes of a high-pressure alarm?", back: "Patient: coughing, biting ETT, bronchospasm, secretions, fighting ventilator, pneumothorax, worsening compliance (ARDS, edema). Circuit: water in tubing, kinked circuit, kinked ETT, right mainstem intubation. Response: assess patient first, suction, check ETT position, auscultate, perform inspiratory hold to differentiate compliance vs resistance.", difficulty: 1 },
      { id: 402, front: "What are the causes of a low-pressure alarm?", back: "Disconnection from ventilator circuit. Leak in circuit (loose connections, damaged tubing). Cuff leak or deflation (ETT or trach). Chest tube air leak. Patient not triggering ventilator (apnea). Circuit port left open. Response: check all connections, assess cuff pressure, listen for audible leak, hand ventilate if needed.", difficulty: 1 },
      { id: 403, front: "What are the causes of a low-volume (low Vt) alarm?", back: "Circuit leak or disconnection. Cuff leak. In PCV: worsening compliance or increased resistance reduces delivered Vt. Patient not making adequate effort in spontaneous modes. Insufficient pressure support level. Response: check connections, assess cuff, check compliance/resistance, adjust settings.", difficulty: 1 },
      { id: 404, front: "What are the causes of a high-volume alarm?", back: "In volume modes: unusual (volume is set). In pressure modes: improved compliance delivers larger volumes. Patient agitation/anxiety increases effort. Double-triggering (patient triggers second breath during exhalation). Response: may be benign (improving compliance) but check for double-triggering.", difficulty: 2 },
      { id: 405, front: "What causes an apnea alarm?", back: "Patient has no respiratory effort for the set apnea interval (usually 10-20 seconds). Causes: over-sedation, neurological event (stroke, brain death), respiratory muscle fatigue, phrenic nerve injury. Response: immediately verify patient condition, increase sedation if intentional (terminal weaning), decrease sedation if unintentional, switch to A/C mode.", difficulty: 1 },
      { id: 406, front: "What is patient-ventilator asynchrony (dyssynchrony)?", back: "Mismatch between patient's respiratory effort and ventilator breath delivery. Types: trigger asynchrony, flow asynchrony, cycle asynchrony, mode asynchrony. Increases work of breathing, causes distress, prolongs ventilation. Detected by waveform analysis and clinical assessment. Occurs in up to 25% of ventilated patients.", difficulty: 2 },
      { id: 407, front: "What is trigger asynchrony and how do you fix it?", back: "Types: 1) Ineffective triggering — patient effort doesn't trigger breath (auto-PEEP, weak effort, insensitive trigger). Fix: reduce auto-PEEP, increase sensitivity, apply extrinsic PEEP. 2) Auto-triggering — ventilator fires without patient effort (cardiac oscillations, water in circuit, over-sensitive trigger). Fix: decrease sensitivity, drain water.", difficulty: 2 },
      { id: 408, front: "What is flow asynchrony (flow starvation)?", back: "Patient's inspiratory demand exceeds ventilator flow delivery. Patient looks uncomfortable, uses accessory muscles. Waveform shows: scooped/concave pressure waveform during inspiration. Seen in VCV with set flow. Fix: increase flow rate, switch to decelerating flow, switch to PCV or PSV (variable flow), address cause of high demand.", difficulty: 2, clinicalPearl: "Flow starvation is one of the most common causes of ventilator agitation — always check waveforms before sedating." },
      { id: 409, front: "What is double-triggering?", back: "Two ventilator breaths delivered for one patient effort. Occurs when patient's inspiratory effort exceeds the set inspiratory time. The first breath ends but patient is still inhaling → triggers a second breath. Results in excessive Vt (volutrauma). Fix: increase Vt, increase I-time, or switch to PCV with longer I-time.", difficulty: 2 },
      { id: 410, front: "What is breath stacking?", back: "Successive breaths delivered before complete exhalation of the previous breath. Causes progressive air trapping (similar to auto-PEEP). Can result in dangerously high intrathoracic pressure. Seen with high rates, double-triggering, or inadequate E-time. Fix: decrease rate, increase E-time, address auto-PEEP, sedate if patient-driven.", difficulty: 2 },
      { id: 411, front: "What is reverse triggering?", back: "A unique form of dyssynchrony where the ventilator breath triggers a reflexive diaphragmatic contraction (the opposite of normal triggering). Seen in deeply sedated patients. Can cause breath stacking and double-triggering. Detected on Edi/esophageal pressure monitoring. Fix: adjust sedation level or ventilator settings.", difficulty: 3 },
      { id: 412, front: "What is the first thing you should do when a ventilator alarm sounds?", back: "1) Go to the patient immediately. 2) Assess patient safety — look, listen, feel (chest rise, breath sounds, SpO₂, vital signs). 3) If patient in distress and cause not immediately clear → disconnect from ventilator and bag-valve-mask ventilate with 100% O₂. 4) Systematically troubleshoot once patient is stable.", difficulty: 1, clinicalPearl: "When in doubt, take the patient off the ventilator and manually bag — this isolates whether the problem is the patient or the machine." },
      { id: 413, front: "How do you differentiate a patient problem from a ventilator/circuit problem?", back: "Disconnect patient from ventilator and manually bag. If bagging is easy with good chest rise → ventilator/circuit problem (check circuit, ventilator malfunction). If bagging is difficult → patient problem (pneumothorax, bronchospasm, mucus plug, mainstem intubation). Use mnemonic DOPE.", difficulty: 1 },
      { id: 414, front: "What does the DOPE mnemonic stand for?", back: "Troubleshooting sudden deterioration on a ventilator: D = Displacement (ETT displaced/extubated). O = Obstruction (mucus plug, kinked tube, biting). P = Pneumothorax. E = Equipment failure (ventilator malfunction, disconnection, power loss). Assess in this order: check tube position, suction, assess for pneumothorax, check equipment.", difficulty: 1 },
      { id: 415, front: "What are the signs of right mainstem bronchus intubation?", back: "ETT advanced too far → enters right mainstem (more vertical angle). Signs: absent/diminished breath sounds on left, high PIP, hypoxemia (left lung atelectasis), high-pressure alarms. Confirm with CXR (ETT tip should be 3-5 cm above carina, approximately at T2-T4 level). Fix: withdraw ETT 1-2 cm, reconfirm with CXR.", difficulty: 1 },
      { id: 416, front: "What are the signs of a pneumothorax in a ventilated patient?", back: "Sudden: high PIP/Pplat, decreased/absent breath sounds on affected side, tracheal deviation (tension), hypotension (tension), tachycardia, hypoxemia, subcutaneous emphysema. Ventilator: high-pressure alarms, decreased compliance. Emergency: needle decompression (2nd ICS, MCL or 5th ICS, MAL) followed by chest tube.", difficulty: 1 },
      { id: 417, front: "How do you manage a cuff leak?", back: "Signs: audible leak, low Vt delivered, low-pressure alarms, patient can vocalize around ETT. Check: cuff pressure (should be 20-30 cmH₂O). Reinflate cuff to seal. If can't seal: cuff may be damaged → prepare for reintubation. If trach: may need upsizing. Always use a cuff pressure manometer — avoid \"just enough\" technique.", difficulty: 2 },
      { id: 418, front: "What is the proper ETT cuff pressure range?", back: "20-30 cmH₂O (ideally 25 cmH₂O). < 20: aspiration risk, air leak. > 30: exceeds tracheal capillary perfusion pressure → mucosal ischemia → tracheal stenosis, tracheomalacia, tracheo-esophageal fistula. Check every 8-12 hours with a cuff pressure manometer. Use minimal occlusive volume or minimal leak technique.", difficulty: 1, clinicalPearl: "Think 20-30 cmH₂O — below 20 you aspirate, above 30 you damage the trachea." },
      { id: 419, front: "What is the high-PEEP alarm and what causes it?", back: "Indicates measured PEEP exceeds set PEEP. Causes: auto-PEEP (air trapping), active exhalation by patient, expiratory valve malfunction, obstructed expiratory circuit (water in tubing). Response: assess for auto-PEEP (expiratory hold), drain water from circuit, address air trapping (reduce rate, bronchodilators).", difficulty: 2 },
      { id: 420, front: "What should you do if the ventilator loses power?", back: "1) Immediately bag-valve-mask ventilate with 100% O₂. 2) Call for backup ventilator. 3) Check power source (outlet, plug, battery). Most ICU ventilators have internal batteries (30-60 min). 4) Ensure backup ventilator is functional before transferring patient. 5) Document event and notify responsible provider.", difficulty: 1 },
      { id: 421, front: "How do you manage a patient fighting the ventilator?", back: "1) Rule out serious causes first (DOPE mnemonic). 2) Assess pain and anxiety (BPS, CPOT, RASS). 3) Address underlying cause. 4) Optimize ventilator synchrony (check trigger, flow, mode). 5) Analgesia first (fentanyl/hydromorphone), then sedation (propofol/dexmedetomidine). 6) Last resort: neuromuscular blockade.", difficulty: 2 },
      { id: 422, front: "What is a low FiO₂ alarm?", back: "Measured FiO₂ is lower than set. Causes: gas supply failure (wall O₂ disconnected, empty cylinder), air entrainment in circuit, blender malfunction. This is potentially life-threatening. Response: check gas supply, switch to backup O₂ source, manually ventilate with self-inflating bag if needed.", difficulty: 1 },
      { id: 423, front: "How do you interpret ventilator waveforms for troubleshooting?", back: "Pressure-time: scooped = flow starvation; peaked then flat = high resistance. Flow-time: flow not returning to zero = auto-PEEP. Volume-time: not returning to baseline = air leak. Pressure waveform oscillation during exhalation = water in circuit. Learning to read waveforms is essential for troubleshooting.", difficulty: 2 },
      { id: 424, front: "What is cycle asynchrony?", back: "Mismatch between the end of ventilator inspiration and patient's neural inspiratory effort. Premature cycling: ventilator stops before patient → patient continues to inhale against closed valve (seen in restrictive disease). Delayed cycling: ventilator continues after patient stops (seen in obstructive disease with PSV). Fix: adjust cycle criteria.", difficulty: 2 },
      { id: 425, front: "What is the significance of sudden loss of Vt with stable pressures?", back: "Indicates a leak in the system. Check: circuit connections, humidifier connections, cuff pressure, chest tube (bronchopleural fistula). If cuff is intact and circuit is sealed → consider ETT above vocal cords (partial extubation). Verify ETT position at lip line and with direct visualization if needed.", difficulty: 2 },
      { id: 426, front: "How do you manage sudden severe hypoxemia in a ventilated patient?", back: "1) Increase FiO₂ to 1.0 immediately. 2) Assess patient (DOPE). 3) Bag if needed. 4) Check ETT position. 5) Suction. 6) Auscultate — absent sounds → pneumothorax vs mainstem. 7) Increase PEEP if recruitable atelectasis. 8) CXR. 9) Consider PE, mucus plug, aspiration. 10) Call for help early.", difficulty: 2 },
      { id: 427, front: "What are ventilator self-tests and when should they be performed?", back: "Automated checks of ventilator function: circuit leak test, pressure/flow sensor calibration, valve function, O₂ sensor calibration. Perform: before use on new patient, after circuit change, when ventilator malfunction suspected, per manufacturer recommendations. Do NOT skip — prevents equipment-related patient harm.", difficulty: 1 },
      { id: 428, front: "What is the I:E ratio alarm and what causes it?", back: "Alerts when I:E ratio approaches or reaches inverse ratio (I-time ≥ E-time). Causes: high rate with long I-time, high Vt with low flow, auto-cycling. Consequences: auto-PEEP, air trapping, hemodynamic compromise. Fix: decrease I-time, increase flow, decrease rate, increase E-time.", difficulty: 2 },
      { id: 429, front: "How do you respond to a high minute ventilation alarm?", back: "Patient is ventilating excessively. Causes: pain, anxiety, fever, metabolic acidosis (compensatory hyperventilation), neurological event, ventilator over-sensitivity (auto-triggering). Check ABG — if PaCO₂ low → assess for cause. Don't just sedate without investigating. May indicate worsening metabolic acidosis needing treatment.", difficulty: 2 },
      { id: 430, front: "What is a low minute ventilation alarm and how do you respond?", back: "Minute ventilation below set threshold. Causes: apnea or decreased effort (sedation, neuromuscular disease), circuit leak, inadequate PS level, decreased Vt in pressure modes (worsening compliance). Response: assess patient, check for leaks, consider increasing support or switching to A/C mode if patient cannot maintain adequate ventilation.", difficulty: 2 }
    ]
  },
  {
    id: "resp-pharm-bronchodilators",
    name: "Respiratory Pharmacology: Bronchodilators",
    description: "SABAs, LABAs, SAMAs, LAMAs, methylxanthines, and combination therapies with mechanisms of action, dosing, and clinical pearls",
    category: "Respiratory Pharmacology",
    tier: "allied",
    cards: [
      { id: 501, front: "What is albuterol (salbutamol) and how does it work?", back: "Short-acting beta-2 agonist (SABA). MOA: stimulates beta-2 adrenergic receptors on bronchial smooth muscle → activation of adenylyl cyclase → increased cAMP → smooth muscle relaxation → bronchodilation. Onset: 5-15 min. Duration: 4-6 hours. Dose: MDI 2-4 puffs q4-6h PRN; nebulizer 2.5 mg q4-6h.", difficulty: 1 },
      { id: 502, front: "What are the side effects of beta-2 agonists?", back: "Tachycardia (beta-1 cross-stimulation), tremor (skeletal muscle beta-2), hypokalemia (K⁺ shifts intracellularly), hyperglycemia, palpitations, anxiety, headache. Continuous nebulization can cause significant tachycardia and hypokalemia — monitor ECG and K⁺. Paradoxical bronchospasm is rare but possible.", difficulty: 1, clinicalPearl: "Always check potassium levels in patients receiving continuous albuterol nebulization — significant hypokalemia can occur within hours." },
      { id: 503, front: "What is levalbuterol (Xopenex) and how does it differ from albuterol?", back: "R-isomer of albuterol. Theoretically fewer cardiac side effects because it lacks the S-isomer (which may cause bronchial hyperresponsiveness). Dose: 0.63-1.25 mg nebulized q6-8h or MDI 2 puffs q4-6h. In practice, clinical superiority over racemic albuterol is debatable. More expensive.", difficulty: 2 },
      { id: 504, front: "What is ipratropium bromide (Atrovent) and how does it work?", back: "Short-acting muscarinic antagonist (SAMA). MOA: blocks muscarinic (M3) acetylcholine receptors on airway smooth muscle → prevents parasympathetic-mediated bronchoconstriction. Onset: 15-30 min. Peak: 1-2 hours. Duration: 4-6 hours. Dose: MDI 2-4 puffs q6h; nebulizer 0.5 mg q6-8h.", difficulty: 1 },
      { id: 505, front: "What is DuoNeb (ipratropium/albuterol combination)?", back: "Combination of ipratropium 0.5 mg + albuterol 2.5 mg in single nebulizer vial. Also available as MDI (Combivent Respimat: ipratropium 20 mcg + albuterol 100 mcg). Provides both anticholinergic and beta-2 agonist bronchodilation. Particularly useful in acute COPD exacerbation and severe asthma.", difficulty: 1 },
      { id: 506, front: "What are the long-acting beta-2 agonists (LABAs)?", back: "Salmeterol (Serevent): onset 30-60 min, duration 12 hours. Formoterol (Foradil): onset 5-15 min, duration 12 hours. Indacaterol (Arcapta): once daily. Vilanterol: once daily (only in combinations). Olodaterol (Striverdi): once daily. LABAs should NEVER be used as monotherapy in asthma (increased mortality risk — use with ICS).", difficulty: 2, clinicalPearl: "FDA Black Box Warning: LABA monotherapy increases asthma deaths. Always combine with an inhaled corticosteroid in asthma." },
      { id: 507, front: "What are the long-acting muscarinic antagonists (LAMAs)?", back: "Tiotropium (Spiriva): most studied, once daily. Umeclidinium (Incruse Ellipta): once daily. Glycopyrrolate (Lonhala Magnair): twice daily. Aclidinium (Tudorza): twice daily. MOA: blocks M3 receptors → sustained bronchodilation. Mainstay of COPD maintenance therapy. Also approved as add-on for asthma.", difficulty: 2 },
      { id: 508, front: "How do beta-2 agonists and anticholinergics differ in mechanism?", back: "Beta-2 agonists: active bronchodilation by relaxing smooth muscle (increase cAMP via adenylyl cyclase). Work on all airways but most effective in smaller airways. Anticholinergics: block bronchoconstriction (prevent ACh-mediated M3 receptor contraction). Most effective in larger, central airways. Complementary when combined.", difficulty: 2 },
      { id: 509, front: "What is theophylline and what are its clinical considerations?", back: "Methylxanthine bronchodilator. MOA: phosphodiesterase inhibition → increased cAMP → bronchodilation. Also: adenosine antagonism, anti-inflammatory effects, respiratory stimulant. Narrow therapeutic index: 5-15 mcg/mL. Toxicity: tachycardia, seizures, nausea, arrhythmias. Rarely used now due to better alternatives and toxicity risk.", difficulty: 2 },
      { id: 510, front: "What factors affect theophylline metabolism?", back: "Increased clearance (lower levels): smoking, phenytoin, rifampin, high-protein diet, youth. Decreased clearance (higher levels/toxicity risk): liver disease, CHF, cimetidine, macrolides (erythromycin), fluoroquinolones, viral illness, age >60. Therapeutic drug monitoring essential. Drug interactions are numerous.", difficulty: 3 },
      { id: 511, front: "What is the role of epinephrine in respiratory emergencies?", back: "Non-selective adrenergic agonist (alpha + beta). Used in: anaphylaxis (IM 0.3-0.5 mg 1:1000), severe croup (racemic epi nebulization 0.5 mL of 2.25%), severe asthma (SubQ 0.3 mg if unable to inhale). Effects: bronchodilation (beta-2), vasoconstriction (alpha-1), cardiac stimulation (beta-1).", difficulty: 2 },
      { id: 512, front: "What is racemic epinephrine and when is it used?", back: "A mixture of D- and L-isomers of epinephrine. Nebulized dose: 0.5 mL of 2.25% solution diluted in 3 mL NS. Primary use: croup (laryngotracheobronchitis) — reduces subglottic edema via alpha-adrenergic vasoconstriction. Also used for post-extubation stridor. Onset: 1-5 min. Duration: ~2 hours. Monitor for rebound swelling.", difficulty: 2 },
      { id: 513, front: "What are the key differences between SABAs and LABAs?", back: "SABAs (albuterol, levalbuterol): quick onset (5-15 min), short duration (4-6 hours), used as rescue/reliever. LABAs (salmeterol, formoterol): longer onset (most), 12-24 hour duration, used as maintenance/controller. Exception: formoterol has rapid onset AND long duration. LABAs never used alone in asthma.", difficulty: 1 },
      { id: 514, front: "What is the stepwise approach to bronchodilator therapy in COPD?", back: "Group A (low symptoms, low risk): SABA or SAMA PRN. Group B (more symptoms): LABA or LAMA. Group E (exacerbations): LABA + LAMA (or LABA + ICS if eosinophils ≥ 300). Escalation: LABA + LAMA + ICS (triple therapy) if still symptomatic. Per GOLD 2024 guidelines.", difficulty: 2 },
      { id: 515, front: "What is the role of bronchodilators in acute asthma exacerbation?", back: "First-line: albuterol nebulizer (2.5-5 mg q20min × 3 doses, then q1-4h) or MDI (4-8 puffs q20min). Add ipratropium (0.5 mg q20min × 3 doses) for severe exacerbation. Continuous nebulization (10-15 mg/hr albuterol) for life-threatening cases. IV magnesium sulfate (2g) if refractory.", difficulty: 2 },
      { id: 516, front: "What is the proper MDI technique with a spacer?", back: "1) Shake MDI. 2) Attach spacer. 3) Exhale fully. 4) Place mouthpiece in mouth, create seal. 5) Actuate MDI at start of slow deep inhalation. 6) Inhale slowly over 3-5 seconds. 7) Hold breath 10 seconds. 8) Wait 1 minute between puffs. Spacer improves lung deposition from ~10% to ~20% and reduces oral side effects.", difficulty: 1 },
      { id: 517, front: "What is the proper DPI (dry powder inhaler) technique?", back: "1) Load dose (twist, click, or open per device). 2) Exhale fully AWAY from device (moisture deactivates powder). 3) Place mouthpiece in mouth, seal lips. 4) Inhale FORCEFULLY and DEEPLY (flow-dependent device — minimum 30-60 L/min). 5) Hold breath 10 seconds. 6) No spacer used. Not suitable for severe exacerbation (patient can't generate flow).", difficulty: 1 },
      { id: 518, front: "What combination inhalers are available for COPD/asthma?", back: "LABA + ICS: fluticasone/salmeterol (Advair), budesonide/formoterol (Symbicort), fluticasone/vilanterol (Breo). LABA + LAMA: umeclidinium/vilanterol (Anoro), tiotropium/olodaterol (Stiolto). Triple (LABA + LAMA + ICS): fluticasone/umeclidinium/vilanterol (Trelegy), budesonide/glycopyrrolate/formoterol (Breztri).", difficulty: 2 },
      { id: 519, front: "What is the mechanism of muscarinic receptor blockade in the airways?", back: "Parasympathetic (vagal) tone maintains baseline bronchoconstriction via ACh acting on M3 receptors. Anticholinergics block M3 → bronchodilation + decreased mucus secretion. M2 receptors are inhibitory (autoreceptors) — non-selective agents block M2 too, paradoxically increasing ACh release. Tiotropium is M1/M3 selective.", difficulty: 3 },
      { id: 520, front: "What is the role of magnesium sulfate as a bronchodilator?", back: "IV MgSO₄ 2g over 20 min: smooth muscle relaxant, mild bronchodilator. Used in severe/life-threatening asthma not responding to initial bronchodilator therapy. MOA: inhibits calcium-mediated smooth muscle contraction, blocks acetylcholine release. Also available nebulized (isotonic MgSO₄ as diluent). Monitor for hypotension.", difficulty: 2 },
      { id: 521, front: "What is the difference between controller and reliever medications in asthma?", back: "Controllers (maintenance): taken daily to reduce inflammation and prevent symptoms — ICS, LABA+ICS, LAMA, leukotriene modifiers, biologics. Relievers (rescue): taken as needed for acute symptoms — SABA, SABA+SAMA. GINA now recommends ICS-formoterol as both reliever and controller (MART approach).", difficulty: 1 },
      { id: 522, front: "What are the anticholinergic side effects of inhaled SAMA/LAMA?", back: "Systemic anticholinergic effects minimal with inhalation. Main side effects: dry mouth (most common), urinary retention (caution in BPH), constipation, blurred vision (if sprayed in eyes — particularly with nebulizer mask). Contraindicated in narrow-angle glaucoma. Taste alteration. Generally well-tolerated.", difficulty: 1 },
      { id: 523, front: "What is the SMART/MART therapy approach?", back: "Single Maintenance And Reliever Therapy: using budesonide-formoterol (ICS-LABA with fast-onset LABA) as BOTH the daily controller AND rescue inhaler. Endorsed by GINA guidelines. Reduces exacerbations compared to SABA rescue. Works because formoterol has rapid onset, and every rescue dose also delivers anti-inflammatory ICS.", difficulty: 2 },
      { id: 524, front: "What bronchodilator dose adjustments are needed in pediatric patients?", back: "Albuterol nebulizer: 0.15 mg/kg (min 1.25 mg, max 5 mg) q20min × 3 for acute, then q1-4h. MDI with spacer + mask: 4-8 puffs. Ipratropium: 0.25-0.5 mg nebulized. Weight-based dosing is preferred. Use mask with spacer in children < 4 years. Continuous neb: 0.5 mg/kg/hr (max 15 mg/hr).", difficulty: 2 },
      { id: 525, front: "What is the Respimat Soft Mist Inhaler (SMI) and how does it differ?", back: "Propellant-free inhaler that produces a slow-moving aerosol cloud. Slower velocity than MDI → better lung deposition (~50% vs 10-20% for MDI). No hand-breath coordination needed. Does not require forceful inhalation (unlike DPI). Used for tiotropium (Spiriva Respimat), ipratropium/albuterol (Combivent Respimat), olodaterol (Striverdi).", difficulty: 2 }
    ]
  },
  {
    id: "resp-pharm-antiinflammatory",
    name: "Respiratory Pharmacology: Anti-Inflammatory & Other Agents",
    description: "Corticosteroids, mucolytics, leukotriene modifiers, biologics, antibiotics, and other respiratory medications for RRT exam prep",
    category: "Respiratory Pharmacology",
    tier: "allied",
    cards: [
      { id: 601, front: "How do inhaled corticosteroids (ICS) work?", back: "MOA: bind cytoplasmic glucocorticoid receptors → translocate to nucleus → suppress transcription of inflammatory genes (cytokines, chemokines, cell adhesion molecules). Reduce airway inflammation, edema, mucus production, and hyperresponsiveness. NOT bronchodilators — no immediate relief. Peak effect: 1-2 weeks.", difficulty: 2 },
      { id: 602, front: "What are common inhaled corticosteroids and their relative potencies?", back: "Low potency: beclomethasone, flunisolide. Medium: budesonide (Pulmicort), fluticasone propionate (Flovent) low-dose. High: fluticasone furoate (Arnuity), mometasone (Asmanex), ciclesonide (Alvesco). Potency determines dose equivalence. Higher potency = lower microgram dose needed. Choose based on asthma severity step.", difficulty: 2 },
      { id: 603, front: "What are the side effects of inhaled corticosteroids?", back: "Local: oral candidiasis (thrush), dysphonia (hoarseness), pharyngitis. Prevention: rinse mouth after each use, use spacer with MDI. Systemic (high doses): adrenal suppression, osteoporosis, cataracts, growth retardation in children, easy bruising, skin thinning. Systemic effects rare at low-moderate doses.", difficulty: 1, clinicalPearl: "Mouth rinsing after ICS use reduces thrush risk by 50%. Always educate patients on this simple but critical step." },
      { id: 604, front: "When are systemic corticosteroids used in respiratory care?", back: "Acute asthma exacerbation: prednisone 40-60 mg/day × 5-7 days (adults), prednisolone 1-2 mg/kg/day (peds). COPD exacerbation: prednisone 40 mg × 5 days. Croup: dexamethasone 0.6 mg/kg × 1 dose. Status asthmaticus: IV methylprednisolone 125 mg q6h. ARDS: dexamethasone 6 mg/day × 10 days.", difficulty: 2 },
      { id: 605, front: "What is N-acetylcysteine (NAC/Mucomyst) and how is it used?", back: "Mucolytic agent. MOA: breaks disulfide bonds in mucoproteins → reduces mucus viscosity. Routes: nebulized (3-5 mL of 20% or 6-10 mL of 10% q6-8h), oral. Also used as antidote for acetaminophen overdose (IV or oral). Side effects: bronchospasm (always give with bronchodilator), nausea, rhinorrhea, disagreeable odor (sulfur).", difficulty: 2, clinicalPearl: "Always administer a bronchodilator before or with NAC — it can trigger bronchospasm in reactive airways patients." },
      { id: 606, front: "What is dornase alfa (Pulmozyme)?", back: "Recombinant human DNase. MOA: cleaves extracellular DNA released by neutrophils in purulent secretions → reduces sputum viscosity. Primary indication: cystic fibrosis (2.5 mg nebulized once daily). Not effective in COPD or non-CF bronchiectasis. Expensive. Reduces CF exacerbation frequency and improves FEV₁.", difficulty: 2 },
      { id: 607, front: "What is hypertonic saline and how is it used as a respiratory therapy?", back: "3% or 7% NaCl nebulized. MOA: draws water into airway lumen (osmotic effect) → hydrates secretions, stimulates mucociliary clearance, induces cough. Uses: CF (alternative to dornase alfa), sputum induction for TB testing, bronchiolitis in infants (controversial). Side effects: bronchospasm — pretreat with bronchodilator.", difficulty: 2 },
      { id: 608, front: "What are leukotriene modifiers and how do they work?", back: "Two types: 1) Leukotriene receptor antagonists (LTRAs): montelukast (Singulair), zafirlukast — block CysLT1 receptors. 2) 5-lipoxygenase inhibitors: zileuton — blocks leukotriene synthesis. Leukotrienes cause bronchoconstriction, edema, mucus secretion, eosinophil recruitment. Used in asthma and allergic rhinitis.", difficulty: 2 },
      { id: 609, front: "What is montelukast (Singulair) and what are its indications?", back: "Leukotriene receptor antagonist. Oral, once daily at bedtime. Indications: asthma (add-on to ICS), exercise-induced bronchospasm prevention, allergic rhinitis. Particularly useful for aspirin-exacerbated respiratory disease. FDA black box warning: neuropsychiatric events (mood changes, suicidality) — counsel patients.", difficulty: 2 },
      { id: 610, front: "What biologic therapies are used in severe asthma?", back: "Anti-IgE: omalizumab (Xolair) — allergic asthma with elevated IgE. Anti-IL-5: mepolizumab (Nucala), reslizumab (Cinqair), benralizumab (Fasenra) — eosinophilic asthma. Anti-IL-4/13: dupilumab (Dupixent) — Type 2 inflammation. Anti-TSLP: tezepelumab (Tezspire) — broadest mechanism, works regardless of biomarker.", difficulty: 3 },
      { id: 611, front: "What is the role of antibiotics in COPD exacerbation?", back: "Indicated when: increased dyspnea + increased sputum volume + increased sputum purulence (Anthonisen criteria — need 2 of 3, with purulence being most important). Common agents: azithromycin (5-day course), amoxicillin-clavulanate, doxycycline, respiratory fluoroquinolone (levofloxacin). Prophylactic azithromycin reduces exacerbation frequency.", difficulty: 2 },
      { id: 612, front: "What is surfactant therapy and when is it used?", back: "Pulmonary surfactant (beractant/Survanta, calfactant/Infasurf, poractant alfa/Curosurf) reduces alveolar surface tension, preventing collapse. Primary indication: neonatal RDS (surfactant deficiency in premature infants <34 weeks). Given via ETT. Prophylactic or rescue dosing. Natural surfactants preferred over synthetic.", difficulty: 2 },
      { id: 613, front: "What is the role of PDE4 inhibitors in respiratory disease?", back: "Roflumilast (Daliresp/Daxas): selective PDE4 inhibitor. MOA: inhibits PDE4 → prevents cAMP breakdown → anti-inflammatory and bronchodilator effects. Indication: severe COPD with chronic bronchitis phenotype and frequent exacerbations, as add-on to bronchodilators. Side effects: diarrhea, nausea, weight loss, headache.", difficulty: 2 },
      { id: 614, front: "What are the common antibiotics used for community-acquired pneumonia?", back: "Outpatient no comorbidities: amoxicillin, doxycycline, or azithromycin. Outpatient with comorbidities: amoxicillin-clavulanate + macrolide, or respiratory fluoroquinolone. Inpatient: ceftriaxone + azithromycin, or fluoroquinolone alone. ICU: ceftriaxone + azithromycin/fluoroquinolone. Add vancomycin for MRSA risk, pip-taz for Pseudomonas risk.", difficulty: 2 },
      { id: 615, front: "What is the role of cromolyn sodium (Intal) in respiratory therapy?", back: "Mast cell stabilizer. MOA: prevents mast cell degranulation → blocks histamine and leukotriene release → prevents bronchoconstriction. Used prophylactically for exercise-induced and allergen-induced asthma. NOT for acute bronchospasm. Nebulized 20 mg QID. Very safe but less effective than ICS. Rarely used now.", difficulty: 2 },
      { id: 616, front: "What are the decongestants used in respiratory care?", back: "Phenylephrine (oral/nasal): alpha-1 agonist → vasoconstriction of nasal mucosa → decreased swelling. Oxymetazoline (Afrin): topical alpha agonist, potent decongestant. Limit topical use to 3 days (rebound congestion — rhinitis medicamentosa). Pseudoephedrine: alpha + beta agonist, oral, more effective but controlled substance.", difficulty: 1 },
      { id: 617, front: "What is the role of heliox (helium-oxygen mixture) in respiratory therapy?", back: "80%/20% or 70%/30% He/O₂. Helium is less dense than nitrogen → reduces turbulent flow resistance → decreases work of breathing. Uses: upper airway obstruction (croup, post-extubation stridor), severe asthma, vocal cord dysfunction. Limitations: can't use with high FiO₂ needs, may affect flow meter readings, expensive.", difficulty: 2 },
      { id: 618, front: "What is inhaled nitric oxide (iNO) and when is it used?", back: "Selective pulmonary vasodilator. MOA: activates guanylyl cyclase → increases cGMP → smooth muscle relaxation in ventilated lung areas. Dose: 5-20 ppm (rarely >40 ppm). Indications: PPHN (persistent pulmonary hypertension of the newborn — FDA approved), ARDS (off-label, improves oxygenation but not mortality). Wean slowly to avoid rebound PH.", difficulty: 3 },
      { id: 619, front: "What is the role of antitussives in respiratory therapy?", back: "Dextromethorphan: non-opioid cough suppressant, analogue of codeine. MOA: inhibits vagal afferent fibers in cough center. Used for non-productive cough. Codeine: opioid antitussive, more effective but sedating. Benzonatate: anesthetizes stretch receptors in lungs. Do NOT suppress productive cough (need to clear secretions).", difficulty: 1 },
      { id: 620, front: "What are the key drug interactions in respiratory pharmacology?", back: "Theophylline + macrolides → toxicity. Beta-blockers + beta-agonists → reduced bronchodilation. MAOIs + sympathomimetics → hypertensive crisis. ICS + CYP3A4 inhibitors → increased steroid absorption. Anticholinergics + other anticholinergics → additive effects. LABA monotherapy in asthma → increased mortality.", difficulty: 2 },
      { id: 621, front: "What is the role of corticosteroids in ARDS management?", back: "Dexamethasone 6 mg/day × 10 days reduces mortality in moderate-severe ARDS (DEXA-ARDS trial). Methylprednisolone early in unresolving ARDS may reduce fibroproliferation. Late initiation (>14 days after onset) may worsen outcomes. Steroids reduce inflammation and may prevent fibrotic phase. Benefits must outweigh infection risk.", difficulty: 2 },
      { id: 622, front: "What is the mechanism and use of zileuton (Zyflo)?", back: "5-lipoxygenase inhibitor. Blocks the enzyme that converts arachidonic acid to leukotrienes at the source (upstream block). Unlike LTRAs which block the receptor, zileuton prevents leukotriene synthesis entirely. Requires liver function monitoring (hepatotoxicity). Dosed 4x daily (extended-release: 2x daily). Less commonly used than montelukast.", difficulty: 3 },
      { id: 623, front: "What is the role of epoprostenol (Flolan) in respiratory care?", back: "Prostaglandin I₂ (prostacyclin) analogue. Potent pulmonary vasodilator and platelet aggregation inhibitor. Used in severe pulmonary arterial hypertension (PAH). Administered via continuous IV infusion. Must never be abruptly discontinued (rebound pulmonary hypertension can be fatal). Also used as nebulized form in ARDS (off-label).", difficulty: 3 },
      { id: 624, front: "What is the recommended antibiotic for pertussis (whooping cough)?", back: "First-line: azithromycin (5-day course). Alternative: erythromycin (14 days) or clarithromycin (7 days). TMP-SMX for macrolide-allergic patients. Early treatment (catarrhal phase) reduces transmission and severity. Late treatment (paroxysmal phase) doesn't change disease course but reduces contagiousness.", difficulty: 2 },
      { id: 625, front: "What is the proper administration technique for nebulized medications?", back: "1) Assemble nebulizer, add medication. 2) Connect to gas source (6-8 L/min for jet nebulizer). 3) Patient sits upright, breathes through mouthpiece. 4) Normal tidal breathing with occasional deep breaths. 5) Continue until sputtering (~10-15 min). 6) Rinse mouth if ICS. Particle size 1-5 microns optimal for lower airway deposition.", difficulty: 1 }
    ]
  },
  {
    id: "aerosol-delivery-devices",
    name: "Aerosol Delivery & Devices",
    description: "MDI, DPI, nebulizers, spacers, and aerosol physics including particle size, deposition, and device selection for optimal drug delivery",
    category: "Drug Delivery",
    tier: "allied",
    cards: [
      { id: 701, front: "What is the optimal particle size for lower airway deposition?", back: "1-5 microns (MMAD — mass median aerodynamic diameter). < 1 micron: exhaled without depositing. 1-3 microns: alveolar deposition (optimal for ICS, antibiotics). 3-5 microns: bronchial deposition (optimal for bronchodilators). > 5 microns: upper airway/oropharyngeal impaction (wasted drug, increased side effects).", difficulty: 2 },
      { id: 702, front: "What are the types of nebulizers?", back: "1) Jet (pneumatic): compressed gas drives solution through baffle. Flow 6-8 L/min. Most common. 2) Ultrasonic: piezoelectric crystal creates vibrations. Not suitable for suspensions. 3) Vibrating mesh (VMN): mesh plate with apertures. More efficient, quieter, suitable for all formulations. Higher drug output.", difficulty: 2 },
      { id: 703, front: "What factors affect aerosol deposition in the lungs?", back: "Patient: breathing pattern (slow deep breaths optimal), airway caliber, obstruction severity. Device: particle size, velocity, output. Technique: coordination, breath-hold. Humidity: hygroscopic growth increases particle size. Gravity: sedimentation in smaller airways. Lung deposition: MDI ~10%, MDI+spacer ~20%, DPI ~15-30%, VMN ~30-40%.", difficulty: 2 },
      { id: 704, front: "What is a spacer/VHC and why is it used with MDIs?", back: "Valved Holding Chamber (VHC): attached between MDI and patient. Benefits: 1) Eliminates need for hand-breath coordination. 2) Reduces oropharyngeal deposition (fewer side effects). 3) Increases lung deposition (from ~10% to ~20%). 4) Reduces particle velocity. 5) Allows evaporation → smaller particles. Essential for ICS and young children.", difficulty: 1 },
      { id: 705, front: "When should a nebulizer be used instead of an MDI?", back: "Severe acute exacerbation (too dyspneic for MDI technique). Patients who cannot coordinate MDI even with spacer. Infants/young children (nebulizer + mask). Patients who require high-dose continuous therapy. Medications only available in nebulizer form (dornase alfa, NAC, some antibiotics). ICU patients on ventilators.", difficulty: 1 },
      { id: 706, front: "How is aerosol delivery modified for mechanically ventilated patients?", back: "MDI: use in-line actuator adapter in inspiratory limb, actuate at beginning of inspiration, remove HME during treatment. Nebulizer: place in inspiratory limb ~15 cm from Y-connector. Increase Vt by 100-200 mL to compensate for circuit dead space. Lung deposition: ~10-15% (less than spontaneously breathing). Use VMN for best delivery.", difficulty: 2 },
      { id: 707, front: "What is the difference between MDI and SMI (Soft Mist Inhaler)?", back: "MDI: propellant-driven (HFA), fast velocity (requires coordination or spacer), ~10% lung deposition. SMI (e.g., Respimat): propellant-free, mechanical spring produces slow mist, longer aerosol duration (1.5 seconds vs 0.2 seconds for MDI), ~50% lung deposition, no coordination issues. More expensive.", difficulty: 2 },
      { id: 708, front: "What are the key patient instructions for DPI use?", back: "1) Never exhale INTO the device (moisture clumps powder). 2) Must inhale FORCEFULLY (flow-dependent, 30-60+ L/min). 3) No spacer used. 4) Keep dry (don't store in bathroom). 5) Hold breath 10 seconds after inhalation. Not appropriate during severe exacerbation (can't generate adequate flow). Different loading mechanisms per device.", difficulty: 1 },
      { id: 709, front: "How does humidity affect aerosol therapy?", back: "Humidity causes hygroscopic growth of particles → increased size → more upper airway deposition, less lung deposition. Active heated humidification in ventilator circuits reduces drug delivery by up to 40%. For ventilated patients: bypass humidifier during aerosol treatments or use mesh nebulizer (less affected).", difficulty: 2 },
      { id: 710, front: "What are the advantages of vibrating mesh nebulizers (VMN)?", back: "Higher lung deposition (~30-40%). Quieter operation. No compressed gas needed. Can nebulize suspensions (unlike ultrasonic). Shorter treatment time. More consistent particle size. Battery-operated (portable). Better for ventilator circuits (no additional gas flow). Disadvantage: higher cost, mesh can clog, requires cleaning.", difficulty: 2 },
      { id: 711, front: "What infection control measures are needed for nebulizers?", back: "Between treatments (same patient): rinse with sterile water, air dry. Daily: wash with soap and water, disinfect (vinegar soak 30 min or dishwasher), air dry completely. Replace nebulizer cups per manufacturer (typically every 2-4 weeks for home use). Never share nebulizers between patients. Hospital: single-patient use disposable cups.", difficulty: 1 },
      { id: 712, front: "How do you assess if a patient is using their inhaler correctly?", back: "Have patient demonstrate technique (teach-back method). Common MDI errors: not shaking, poor coordination, not using spacer, not holding breath, mouth not sealed. Common DPI errors: exhaling into device, not inhaling forcefully, not loading properly. Re-educate at every visit — up to 70% of patients have poor technique.", difficulty: 1 },
      { id: 713, front: "What is the bland aerosol and when is it used?", back: "Aerosolized sterile water or normal saline without medication. Uses: upper airway humidification (post-extubation, laryngitis, tracheostomy), sputum induction (for diagnostic specimens), humidification of dry medical gases. Delivered via large volume nebulizer (LVN), face tent, or aerosol mask. Does NOT deliver medication.", difficulty: 1 },
      { id: 714, front: "What is the difference between a small volume nebulizer (SVN) and large volume nebulizer (LVN)?", back: "SVN: holds 3-5 mL medication, used for aerosolized drug delivery (bronchodilators, steroids), treatment time 10-15 min. LVN: holds 200+ mL, used for bland aerosol (humidification), continuous output, connected to aerosol masks/trach collars. Different purposes — SVN for drugs, LVN for humidity.", difficulty: 1 },
      { id: 715, front: "What is sputum induction and how is it performed?", back: "Procedure to obtain lower respiratory specimen (usually for TB diagnosis or cytology). Technique: patient inhales hypertonic saline (3-5% NaCl) via nebulizer for 15-20 minutes. Stimulates cough and thin secretions. Collect expectorated sputum in sterile container. Perform in negative pressure room (airborne precaution for TB). Pre-treat with bronchodilator.", difficulty: 2 },
      { id: 716, front: "What is the breath-actuated MDI?", back: "An MDI that automatically actuates when the patient inhales (no coordination needed). Examples: Autohaler, EasyBreathe. Triggers when patient's inspiratory flow reaches threshold. Advantages: eliminates coordination problem, no spacer needed. Disadvantages: still requires adequate inspiratory effort, fewer medications available, more expensive.", difficulty: 2 },
      { id: 717, front: "What are the considerations for aerosol delivery in pediatric patients?", back: "< 4 years: nebulizer with face mask, or MDI + spacer + face mask. 4-6 years: MDI + spacer + mouthpiece (if cooperative). > 6 years: MDI + spacer, or DPI if adequate inspiratory flow. Blow-by technique is ineffective (drug doesn't reach lungs). Crying reduces deposition. Mask must seal on face. Use weight-based dosing.", difficulty: 2 },
      { id: 718, front: "How should MDI canisters be stored and when should they be replaced?", back: "Store at room temperature (cold decreases output). Keep cap on. Prime new canister (4 puffs into air) and re-prime if not used for >2 weeks. Floating test is unreliable — use dose counter. Replace when counter reaches zero. Don't puncture or incinerate. HFA propellant canisters should not be exposed to high heat.", difficulty: 1 },
      { id: 719, front: "What is the role of aerosol therapy in cystic fibrosis?", back: "CF patients use multiple inhaled therapies in specific order: 1) Bronchodilator (albuterol). 2) Hypertonic saline (7%) or dornase alfa (Pulmozyme). 3) Airway clearance therapy. 4) Inhaled antibiotic (tobramycin, aztreonam). 5) Inhaled corticosteroid if needed. Treatment burden is significant — adherence is challenging.", difficulty: 2 },
      { id: 720, front: "What are the characteristics of the ideal aerosol delivery device?", back: "High lung deposition (>30%). Consistent dose delivery. Easy technique (no coordination needed). Portable and convenient. Low cost. Multiple drug compatibility. Breath-actuated. Minimal oropharyngeal deposition. Patient-friendly (quick treatment, quiet). Environmentally sustainable. No single device meets all criteria.", difficulty: 1 },
      { id: 721, front: "What is the role of the RT in aerosol device selection?", back: "Assess patient capability (coordination, inspiratory flow, cognition). Match device to patient ability and clinical situation. Evaluate inhaler technique at each visit. Consider cost and insurance coverage. Recommend spacer with MDI for all patients when possible. Ensure patient can demonstrate proper technique before discharge.", difficulty: 1 },
      { id: 722, front: "How does body position affect aerosol deposition?", back: "Upright (sitting/standing): optimal position for aerosol treatments — gravity aids deposition, airways more open, FRC is higher. Supine: reduced FRC, less uniform ventilation, more central deposition. In ventilated patients: HOB elevation 30-45° improves aerosol distribution. Always have patients sit upright for nebulizer treatments.", difficulty: 1 },
      { id: 723, front: "What is the difference between continuous and intermittent nebulization?", back: "Intermittent: standard SVN treatment 10-15 minutes, then off. Continuous: albuterol delivered at constant rate (10-15 mg/hr adults) via large-volume nebulizer for severe/refractory bronchospasm. Monitor HR, K⁺, and tremor. Used in status asthmaticus when intermittent treatments are needed more frequently than q1h.", difficulty: 2 },
      { id: 724, front: "How do you calculate the output rate of a nebulizer?", back: "Output rate = (pre-weight − post-weight) / nebulization time. Expressed in mL/min. Normal jet nebulizer output: 0.2-0.4 mL/min. Dead volume (residual): 0.5-1.5 mL remains in cup (never aerosolized). To maximize drug delivery: fill volume of 4-5 mL, or add NS to dilute (increases treatment time but reduces proportional dead volume loss).", difficulty: 2 },
      { id: 725, front: "What is electrostatic charge and how does it affect spacer/VHC performance?", back: "Plastic spacers develop static charge that attracts aerosol particles to walls → reduces drug delivery by up to 50%. Solutions: wash spacer with dilute soap, don't rinse, air dry (leaves anti-static film). Use anti-static spacers (AeroChamber Plus, metal spacers). Prime new spacers with 10-20 actuations. Anti-static spacers deliver more consistent doses.", difficulty: 2 }
    ]
  },
  {
    id: "oxygen-delivery-systems",
    name: "Oxygen Delivery Systems",
    description: "Low-flow and high-flow oxygen devices, FiO₂ calculations, indications for supplemental oxygen, and clinical decision-making",
    category: "Oxygen Therapy",
    tier: "allied",
    cards: [
      { id: 801, front: "What is the difference between low-flow and high-flow oxygen systems?", back: "Low-flow: provides O₂ at flow rate less than patient's inspiratory demand. Patient entrains room air. FiO₂ variable (depends on respiratory pattern). Examples: nasal cannula, simple mask. High-flow: meets or exceeds patient's inspiratory demand. FiO₂ is fixed/predictable. Examples: Venturi mask, high-flow nasal cannula (HFNC), non-rebreather at max flow.", difficulty: 1 },
      { id: 802, front: "What FiO₂ does a nasal cannula deliver at different flow rates?", back: "1 L/min ≈ 24%. 2 L/min ≈ 28%. 3 L/min ≈ 32%. 4 L/min ≈ 36%. 5 L/min ≈ 40%. 6 L/min ≈ 44%. Rule of thumb: each L/min adds ~4% FiO₂. Maximum 6 L/min (higher causes nasal drying/discomfort without significantly increasing FiO₂). Actual FiO₂ varies with respiratory rate and tidal volume.", difficulty: 1, clinicalPearl: "FiO₂ delivery is approximate because nasal cannula is a low-flow device — the faster and deeper a patient breathes, the more room air they entrain, lowering actual FiO₂." },
      { id: 803, front: "How does a simple oxygen mask work?", back: "Provides FiO₂ 35-55% at 5-10 L/min. Minimum flow: 5 L/min to prevent CO₂ rebreathing (must flush mask dead space ~100-200 mL). Has exhalation ports on sides. Not suitable for precise FiO₂ delivery. Variable performance based on patient's breathing pattern. Useful for moderate hypoxemia.", difficulty: 1 },
      { id: 804, front: "How does a non-rebreather mask (NRB) work?", back: "Reservoir bag + one-way valves over exhalation ports. FiO₂: 60-80% at 10-15 L/min (theoretical 100% but air leaks prevent this). Flow must keep reservoir bag at least 1/3 full during inspiration. One exhalation valve typically removed as safety valve. Used for severe hypoxemia. Short-term bridge device.", difficulty: 1 },
      { id: 805, front: "How does a partial rebreather mask differ from a non-rebreather?", back: "Partial rebreather: reservoir bag but NO one-way valves between bag and mask. First 1/3 of exhaled air (dead space gas — mostly O₂) re-enters bag. FiO₂: 40-70% at 6-10 L/min. Less effective than NRB but allows some CO₂ rebreathing. Keep bag at least 1/3 full. Less commonly used now.", difficulty: 2 },
      { id: 806, front: "How does a Venturi mask (air-entrainment mask) work?", back: "Uses Bernoulli principle: high-velocity O₂ jet entrains room air through fixed ports. Delivers precise, fixed FiO₂ regardless of breathing pattern. Settings: 24%, 28%, 31%, 35%, 40%, 50% with corresponding O₂ flow rates. Ideal for COPD patients requiring controlled, precise O₂. Total flow must exceed patient's inspiratory demand.", difficulty: 1, clinicalPearl: "Venturi masks are the gold standard for precise FiO₂ delivery in COPD — they prevent both hypoxemia and excessive oxygen that could worsen hypercapnia." },
      { id: 807, front: "What is High-Flow Nasal Cannula (HFNC) and how does it work?", back: "Delivers heated, humidified O₂ at flows up to 60 L/min through large-bore nasal prongs. FiO₂: 21-100% (precisely blended). Benefits: generates low-level PEEP (~1 cmH₂O per 10 L/min), reduces dead space (CO₂ washout), provides stable FiO₂, excellent humidification, patient comfort. Systems: Vapotherm, Optiflow, Airvo.", difficulty: 2 },
      { id: 808, front: "What are the indications for HFNC?", back: "Acute hypoxemic respiratory failure (alternative to NIV). Post-extubation support (reduces reintubation). Pre-oxygenation before intubation. Pneumonia with moderate hypoxemia. Heart failure with pulmonary edema. Palliative dyspnea management. Can delay or prevent intubation. ROX index helps predict HFNC success.", difficulty: 2 },
      { id: 809, front: "What is the ROX index and how is it used?", back: "ROX index = (SpO₂/FiO₂) / Respiratory Rate. Predicts HFNC success/failure. ROX ≥ 4.88 at 2, 6, or 12 hours → likely HFNC success. ROX < 3.85 → high risk of HFNC failure, consider escalation. Used to guide decision-making on when to intubate versus continue HFNC.", difficulty: 2 },
      { id: 810, front: "What are the indications for supplemental oxygen therapy?", back: "Acute: SpO₂ < 94% (or < 88% in COPD), acute MI, carbon monoxide poisoning, pneumothorax, severe trauma, post-anesthesia. Chronic (home O₂): PaO₂ ≤ 55 mmHg or SpO₂ ≤ 88% at rest. PaO₂ 56-59 with cor pulmonale, polycythemia, or edema. During exercise or sleep if desaturation occurs.", difficulty: 1 },
      { id: 811, front: "What is the oxygen dissociation curve?", back: "Sigmoid-shaped curve plotting PaO₂ vs SaO₂. P50 (PaO₂ at 50% saturation) = 27 mmHg normally. Steep portion (PaO₂ 20-60): small PaO₂ changes cause large SaO₂ changes. Flat portion (PaO₂ 60-100): large PaO₂ changes cause minimal SaO₂ changes. This explains why SpO₂ falls dramatically once PaO₂ drops below 60.", difficulty: 2 },
      { id: 812, front: "What causes a rightward shift of the oxyhemoglobin dissociation curve?", back: "Decreased O₂ affinity (easier O₂ release to tissues). Causes (mnemonic: CADET face Right): CO₂ increase, Acidosis, 2,3-DPG increase, Exercise, Temperature increase. Clinical significance: tissues extract O₂ more easily. Beneficial in exercising muscles, fever, tissue hypoxia. P50 increases (>27 mmHg).", difficulty: 2 },
      { id: 813, front: "What causes a leftward shift of the oxyhemoglobin dissociation curve?", back: "Increased O₂ affinity (O₂ binds tighter, less release to tissues). Causes: alkalosis, hypothermia, decreased 2,3-DPG (stored blood), CO poisoning, fetal hemoglobin, methemoglobinemia. Clinical significance: O₂ held on Hgb → tissue hypoxia despite normal SaO₂. P50 decreases (<27 mmHg).", difficulty: 2 },
      { id: 814, front: "What is oxygen toxicity and how is it prevented?", back: "Prolonged exposure to FiO₂ > 0.60 can cause: tracheobronchitis (early), absorption atelectasis (N₂ washout), diffuse alveolar damage (late — ARDS-like). Timeline: symptoms at 24-48 hours of FiO₂ > 0.60. Prevention: titrate to lowest FiO₂ maintaining SpO₂ 92-96%. Optimize PEEP before increasing FiO₂.", difficulty: 2 },
      { id: 815, front: "What is absorption atelectasis?", back: "Occurs with high FiO₂ (>0.60): nitrogen in alveoli is washed out and replaced by O₂. O₂ is rapidly absorbed into blood → alveolus collapses (no nitrogen to splint it open). Particularly problematic in areas of low V/Q. This is why 100% O₂ should not be used for extended periods. PEEP helps prevent it.", difficulty: 2 },
      { id: 816, front: "What is the air-entrainment ratio and how do you calculate total flow?", back: "Air-entrainment ratio = parts air : parts O₂ for a given FiO₂. Common ratios: 24% = 25:1, 28% = 10:1, 31% = 7:1, 35% = 5:1, 40% = 3:1, 50% = 1.7:1. Total flow = O₂ flow × (ratio + 1). Example: 28% at 4 L/min O₂ → total flow = 4 × 11 = 44 L/min. Total flow must exceed patient's peak inspiratory flow.", difficulty: 2, clinicalPearl: "If total flow from the Venturi mask is less than the patient's peak inspiratory flow (~30-40 L/min), they'll entrain room air and receive less FiO₂ than intended." },
      { id: 817, front: "What is the 'magic box' method for calculating air-entrainment ratios?", back: "Draw a box. Write desired FiO₂ in center (e.g., 0.40). Write O₂ concentration (1.00) at top left and air concentration (0.21) at bottom left. Cross-subtract: |1.00 − 0.40| = 0.60 (air parts) and |0.21 − 0.40| = 0.19 (O₂ parts). Ratio = 0.60:0.19 ≈ 3:1 air:O₂.", difficulty: 2 },
      { id: 818, front: "What are the types of home oxygen delivery systems?", back: "Compressed gas cylinders: H-tank (large, stationary), E-tank (portable). Liquid oxygen: Dewar flask (large) + portable unit, longest duration. Oxygen concentrators: electrically powered, extract O₂ from room air, most cost-effective, up to 5-10 L/min. Portable concentrators: battery-operated, lightweight, pulse or continuous flow.", difficulty: 1 },
      { id: 819, front: "How do you calculate the duration of an oxygen cylinder?", back: "Duration (min) = (PSI × cylinder factor) / flow rate (L/min). Cylinder factors: E-tank = 0.28, H-tank = 3.14, D-tank = 0.16. Example: E-tank at 2000 PSI, 2 L/min → (2000 × 0.28) / 2 = 280 min = 4.7 hours. Always account for safe residual pressure (≥500 PSI).", difficulty: 2 },
      { id: 820, front: "What is the danger of excessive oxygen in COPD patients?", back: "Chronic CO₂ retainers may depend on hypoxic drive for ventilation. Excessive O₂ can suppress this drive → worsen hypoventilation → CO₂ narcosis. Also: Haldane effect (oxygenated Hgb carries less CO₂) and release of hypoxic pulmonary vasoconstriction → V/Q mismatch. Target SpO₂: 88-92% in COPD. Never withhold O₂ if critically needed.", difficulty: 2, clinicalPearl: "The risk of oxygen-induced hypercapnia is real but should never prevent treating life-threatening hypoxemia. Controlled, titrated O₂ is the approach." },
      { id: 821, front: "What is a tracheostomy collar (trach mask)?", back: "A device that delivers heated, humidified gas directly over a tracheostomy opening. Provides FiO₂ 21-100% depending on gas source. Flow typically 10-15 L/min. Primary purpose: humidification of inspired gas (bypasses nasal/oral humidification). Can deliver bland aerosol or supplemental O₂. Must be secured to prevent displacement.", difficulty: 1 },
      { id: 822, front: "What is a T-piece (Briggs adapter)?", back: "A T-shaped connector attached directly to an ETT or tracheostomy. One arm connects to gas source (heated humidified O₂), other arm serves as expiratory reservoir. Provides precise FiO₂ with high flow. Used for spontaneous breathing trials (SBT) and tracheostomy patients. No positive pressure — purely spontaneous breathing.", difficulty: 1 },
      { id: 823, front: "What is pulse-dose (demand) oxygen delivery?", back: "Delivers a bolus of O₂ only during early inspiration (triggered by patient's inspiratory effort). Conserves oxygen compared to continuous flow (3:1 to 7:1 ratio). Used with portable systems (conserving device/pendant). Not appropriate during sleep (irregular breathing may not trigger), exercise (may not meet demand), or mouth breathing.", difficulty: 2 },
      { id: 824, front: "What safety precautions are required with oxygen equipment?", back: "No smoking or open flames within 10 feet. No petroleum-based products near O₂ (use water-based lubricants). Secure cylinders to prevent falling. Store away from heat. Oxygen supports combustion (not flammable itself). Check connections for leaks. Ground electrical equipment. Post 'Oxygen in Use' signs. Ensure adequate ventilation.", difficulty: 1 },
      { id: 825, front: "What is an oxygen blender?", back: "A device that precisely mixes air and O₂ to deliver a set FiO₂ at high flows. Connected to both air and O₂ wall outlets (50 PSI each). Provides FiO₂ 21-100% at flow rates needed for HFNC, CPAP, and other high-flow devices. Essential for neonatal care where precise FiO₂ is critical. Includes alarm for source gas failure.", difficulty: 2 },
      { id: 826, front: "What is transtracheal oxygen therapy?", back: "Direct delivery of O₂ into trachea via a small catheter inserted through the anterior neck (between cricoid and 2nd tracheal ring). Benefits: lower flow rate needed (50% reduction), improved compliance (cosmetically acceptable), no nasal irritation, allows eating/talking. Risks: mucus ball formation, subcutaneous emphysema. Requires careful maintenance.", difficulty: 3 },
      { id: 827, front: "What are the Medicare criteria for qualifying for home oxygen?", back: "Group I: PaO₂ ≤ 55 mmHg or SpO₂ ≤ 88% at rest on room air. Group II: PaO₂ 56-59 or SpO₂ 89% with edema, cor pulmonale (P-pulmonale on ECG), or polycythemia (Hct > 56%). Must be documented while in stable condition on optimal medical therapy. Retesting required at 60-90 days for non-Group I.", difficulty: 2 },
      { id: 828, front: "What is the Haldane effect?", back: "Deoxygenated hemoglobin binds CO₂ more readily than oxygenated hemoglobin. In the lungs, as Hgb picks up O₂, it releases CO₂ (facilitates CO₂ elimination). In tissues, as Hgb releases O₂, it picks up CO₂ (facilitates CO₂ transport). Clinically: giving O₂ to COPD patients → oxygenated Hgb releases CO₂ → increases PaCO₂.", difficulty: 3 },
      { id: 829, front: "What is a face tent and when is it used?", back: "An open-bottom aerosol device that fits loosely under the chin. Delivers humidified gas or bland aerosol. FiO₂ variable and imprecise (21-40%). Used for patients who can't tolerate a mask (facial trauma, burns, claustrophobia). Also used for humidification post-extubation. Less effective for precise O₂ delivery.", difficulty: 1 },
      { id: 830, front: "What is carbon monoxide poisoning management regarding oxygen?", back: "100% O₂ via NRB mask or intubation. CO has 200-250× greater Hgb affinity than O₂. Half-life of COHb: room air ~5 hours, 100% O₂ ~60-90 minutes, hyperbaric O₂ ~20-30 minutes. Hyperbaric O₂ indications: COHb > 25%, pregnancy, LOC, cardiac ischemia. SpO₂ is falsely normal — must measure COHb by co-oximetry.", difficulty: 2 }
    ]
  },
  {
    id: "pulmonary-function-testing",
    name: "Pulmonary Function Testing",
    description: "Spirometry, lung volumes, DLCO, flow-volume loops, and interpretation of obstructive vs restrictive patterns for TMC/CSE exam prep",
    category: "Diagnostics",
    tier: "allied",
    cards: [
      { id: 901, front: "What is FEV₁ and what does it measure?", back: "Forced Expiratory Volume in 1 second — the volume of air forcefully exhaled in the first second after maximal inspiration. Normal: > 80% predicted. Most reproducible and useful measure of airway obstruction. Used to grade severity of obstruction and monitor disease progression/treatment response.", difficulty: 1 },
      { id: 902, front: "What is FVC and what does it measure?", back: "Forced Vital Capacity — total volume of air forcefully exhaled after maximum inspiration. Normal: > 80% predicted. Reduced in both obstructive disease (air trapping) and restrictive disease (reduced lung capacity). Most useful when combined with FEV₁ to calculate the FEV₁/FVC ratio.", difficulty: 1 },
      { id: 903, front: "What does the FEV₁/FVC ratio indicate?", back: "FEV₁/FVC < 0.70 (70%): obstructive pattern — airflow limitation (COPD, asthma, bronchiectasis). FEV₁/FVC normal or increased (>0.85): restrictive pattern (if FVC is reduced). Normal ratio: ≥ 0.70. The GOLD criteria define COPD as post-bronchodilator FEV₁/FVC < 0.70.", difficulty: 1, clinicalPearl: "Some experts prefer age-adjusted LLN (Lower Limit of Normal) instead of fixed 0.70 cutoff, as FEV₁/FVC naturally declines with age — the fixed ratio may over-diagnose COPD in elderly patients." },
      { id: 904, front: "How do you classify the severity of obstructive disease by FEV₁?", back: "GOLD classification (post-bronchodilator FEV₁): Mild (GOLD 1): FEV₁ ≥ 80% predicted. Moderate (GOLD 2): 50-79%. Severe (GOLD 3): 30-49%. Very Severe (GOLD 4): < 30% predicted. All require FEV₁/FVC < 0.70 for COPD diagnosis.", difficulty: 1 },
      { id: 905, front: "What is a positive bronchodilator response on spirometry?", back: "Post-bronchodilator improvement: FEV₁ increase ≥ 200 mL AND ≥ 12% from baseline. Suggests reversible airflow obstruction (classic for asthma). Some COPD patients also show partial reversibility. Administer 400 mcg albuterol, wait 15-20 minutes, repeat spirometry. Complete reversibility strongly suggests asthma over COPD.", difficulty: 2 },
      { id: 906, front: "What are the lung volumes and what is TLC?", back: "TLC (Total Lung Capacity): total air in lungs after maximum inspiration. Normal: ~6 L. Increased in: obstructive disease (hyperinflation). Decreased in: restrictive disease. Cannot be measured by spirometry — requires body plethysmography, helium dilution, or nitrogen washout.", difficulty: 1 },
      { id: 907, front: "What is RV (Residual Volume)?", back: "Volume of air remaining in lungs after maximal exhalation. Normal: ~1.2 L. Increased in: obstructive disease (air trapping — COPD, asthma). Cannot be measured by spirometry. RV/TLC ratio > 35% suggests air trapping. Elevated RV is a hallmark of hyperinflation.", difficulty: 1 },
      { id: 908, front: "What is FRC (Functional Residual Capacity)?", back: "Volume of air remaining in lungs after normal (tidal) exhalation. FRC = ERV + RV. Normal: ~2.4 L. Represents the equilibrium point of chest wall and lung elastic recoil. Increased in COPD (hyperinflation). Decreased in restrictive disease, obesity, supine position. Determines baseline lung volume for gas exchange.", difficulty: 2 },
      { id: 909, front: "What is DLCO and what does it measure?", back: "Diffusing Capacity of the Lung for Carbon Monoxide — measures gas transfer across the alveolar-capillary membrane. Normal: > 80% predicted. Patient inhales small amount of CO, holds breath 10 seconds, exhales. Decreased in: emphysema, pulmonary fibrosis, pulmonary vascular disease, anemia. Increased in: polycythemia, pulmonary hemorrhage, asthma.", difficulty: 2 },
      { id: 910, front: "What PFT pattern is seen in emphysema?", back: "Obstructive: ↓ FEV₁, ↓ FEV₁/FVC. ↑ TLC (hyperinflation). ↑ RV (air trapping). ↑ RV/TLC ratio. ↓ DLCO (alveolar destruction reduces surface area). Normal or ↑ FRC. Poor bronchodilator response (irreversible). Flow-volume loop: scooped expiratory curve.", difficulty: 2 },
      { id: 911, front: "What PFT pattern is seen in asthma?", back: "Obstructive (during exacerbation): ↓ FEV₁, ↓ FEV₁/FVC. TLC may be ↑ during attack. Good bronchodilator response (≥12% and 200 mL FEV₁ improvement). DLCO: normal or ↑ (unlike emphysema). May be completely normal between attacks. Methacholine challenge positive if baseline normal.", difficulty: 2 },
      { id: 912, front: "What PFT pattern is seen in pulmonary fibrosis?", back: "Restrictive: ↓ FEV₁, ↓ FVC, normal or ↑ FEV₁/FVC ratio. ↓ TLC (can't fully expand). ↓ RV (proportionally reduced). ↓ DLCO (thickened interstitium impairs diffusion). No bronchodilator response. Flow-volume loop: reduced in size but normal shape. All volumes proportionally reduced.", difficulty: 2 },
      { id: 913, front: "What is the methacholine challenge test?", back: "Bronchoprovocation test for diagnosing asthma when baseline spirometry is normal. Patient inhales increasing concentrations of methacholine (a cholinergic bronchoconstrictor). Positive: FEV₁ drops ≥ 20% from baseline (PC20 reported — concentration causing 20% drop). PC20 < 4 mg/mL = definite airway hyperreactivity.", difficulty: 2 },
      { id: 914, front: "What is a flow-volume loop and what does a normal one look like?", back: "Graph plotting flow (Y-axis) versus volume (X-axis) during forced inspiration and expiration. Normal: expiratory limb peaks quickly (PEFR) then gradually decreases linearly. Inspiratory limb is a symmetric semicircle. Total width = FVC. Peak expiratory flow occurs early in exhalation.", difficulty: 2 },
      { id: 915, front: "What does a scooped expiratory limb on a flow-volume loop indicate?", back: "Obstructive disease (COPD, asthma). The concave (scooped) shape results from dynamic airway compression during forced exhalation. Small airways collapse → flow limitation at lower lung volumes. Severity of scooping correlates with severity of obstruction. Classic finding on PFTs.", difficulty: 2 },
      { id: 916, front: "What does a flow-volume loop look like with fixed upper airway obstruction?", back: "Both inspiratory AND expiratory flow are flattened (truncated). Creates a box-like appearance. Flow is limited in both directions at a constant level. Causes: tracheal stenosis, goiter compressing trachea, tracheal tumor. Both PEFR and PIFR are reduced and roughly equal.", difficulty: 2 },
      { id: 917, front: "What does a flow-volume loop look like with variable extrathoracic obstruction?", back: "Flattened INSPIRATORY limb (flow limitation on inspiration) with normal expiratory limb. Cause: vocal cord paralysis, laryngeal tumor, subglottic stenosis. During inspiration, negative intrathoracic pressure causes extrathoracic airway to narrow. During expiration, positive pressure splints it open.", difficulty: 2 },
      { id: 918, front: "What does a flow-volume loop look like with variable intrathoracic obstruction?", back: "Flattened EXPIRATORY limb with normal inspiratory limb. Cause: tracheomalacia, intrathoracic tracheal tumor. During expiration, positive intrathoracic pressure compresses the intrathoracic airway. During inspiration, negative pressure opens it. Opposite pattern of extrathoracic obstruction.", difficulty: 2 },
      { id: 919, front: "What is peak expiratory flow rate (PEFR) and its clinical use?", back: "Maximum flow rate during forced exhalation. Normal: 400-700 L/min (varies by age, sex, height). Used for asthma monitoring at home (peak flow meter). Green zone: >80% personal best. Yellow zone: 50-80% (caution, adjust meds). Red zone: <50% (emergency). Less sensitive than FEV₁ for detecting airway obstruction.", difficulty: 1 },
      { id: 920, front: "What quality criteria must spirometry meet to be acceptable?", back: "ATS/ERS criteria: 1) Good start — back-extrapolated volume < 5% FVC or 150 mL. 2) No cough in first second. 3) No early termination — ≥ 6 seconds exhalation (adults) or plateau for ≥ 1 second. 4) Reproducibility — ≥ 3 acceptable efforts with largest two FEV₁ and FVC within 150 mL. Report largest FEV₁ and FVC (can be from different efforts).", difficulty: 2 },
      { id: 921, front: "What is body plethysmography?", back: "Gold standard for measuring lung volumes (TLC, RV, FRC). Patient sits in sealed box, breathes against closed shutter. Uses Boyle's law (P₁V₁ = P₂V₂): as patient inhales against closed shutter, box pressure changes proportionally to thoracic gas volume. Measures all gas in thorax (including trapped gas — advantage over dilution methods).", difficulty: 2 },
      { id: 922, front: "How does helium dilution differ from body plethysmography?", back: "Helium dilution: closed circuit with known helium concentration. Patient rebreathes until equilibrium → calculate FRC by dilution. Only measures communicating gas volume (misses trapped gas). Underestimates FRC/TLC in obstructive disease. Plethysmography measures ALL thoracic gas including trapped gas → more accurate in COPD.", difficulty: 2 },
      { id: 923, front: "What is maximum voluntary ventilation (MVV)?", back: "Maximum volume of air a patient can breathe in 12-15 seconds, extrapolated to L/min. Normal: ~170 L/min (varies). Effort-dependent. Reduced in: obstructive and restrictive disease, neuromuscular weakness, poor effort. Used to assess ventilatory reserve for surgery and exercise capacity. Low MVV suggests high surgical risk.", difficulty: 2 },
      { id: 924, front: "What is the significance of the FEF25-75% (forced expiratory flow)?", back: "Average flow during the middle 50% of the FVC maneuver. Reflects small airway function. Often the first PFT abnormality in early obstructive disease. Normal: > 65% predicted. Highly variable and effort-dependent, so less reliable than FEV₁. May detect early airway disease when FEV₁ is still normal. Not recommended as sole diagnostic criterion.", difficulty: 2 },
      { id: 925, front: "What factors affect PFT predicted values?", back: "Age: lung function declines with age (after ~25 years). Height: taller individuals have larger lungs. Sex: males have larger lung volumes than females. Race/ethnicity: differences in trunk-to-leg ratio affect volumes. GLI-2012 reference equations are now recommended (account for all these factors). Always compare to predicted values.", difficulty: 1 },
      { id: 926, front: "How do you differentiate obstructive from restrictive disease on PFTs?", back: "Obstructive: ↓ FEV₁/FVC (<0.70), ↓ FEV₁, FVC may be normal or ↓, ↑ TLC, ↑ RV. Restrictive: Normal or ↑ FEV₁/FVC, ↓ FVC, ↓ TLC (confirmatory), ↓ RV. Mixed: ↓ FEV₁/FVC AND ↓ TLC. Spirometry alone suggests restriction if FVC ↓ with normal ratio, but TLC is needed to confirm.", difficulty: 1 },
      { id: 927, front: "What is exercise-induced bronchoconstriction (EIB) testing?", back: "Exercise challenge: patient exercises on treadmill/cycle to 85-90% max HR for 6-8 minutes breathing dry air. Post-exercise spirometry at 5, 10, 15, 20, 30 minutes. Positive: ≥ 10% drop in FEV₁. Alternative: eucapnic voluntary hyperventilation (EVH) — more sensitive. Diagnosis of EIB doesn't always mean asthma.", difficulty: 2 },
      { id: 928, front: "What is the cardiopulmonary exercise test (CPET)?", back: "Comprehensive test measuring respiratory, cardiovascular, and metabolic responses during incremental exercise. Measures: VO₂ max, VCO₂, anaerobic threshold, minute ventilation, heart rate response, O₂ pulse, ventilatory equivalents. Used to differentiate cardiac vs pulmonary causes of dyspnea and assess surgical fitness and disability.", difficulty: 3 },
      { id: 929, front: "What is the 6-minute walk test (6MWT)?", back: "Submaximal exercise test measuring distance walked on flat surface in 6 minutes. Normal: > 400 meters (age/sex dependent). Measures functional capacity. Monitor SpO₂, HR, dyspnea, fatigue. Desaturation >4% is significant. Used in COPD, pulmonary hypertension, ILD for prognosis, treatment response, and transplant evaluation.", difficulty: 1 },
      { id: 930, front: "What is slow vital capacity (SVC) and why is it sometimes preferred?", back: "SVC = maximal volume exhaled slowly (not forced). In obstructive disease, SVC > FVC because forced exhalation causes dynamic compression/air trapping. The difference (SVC − FVC) quantifies air trapping. Some patients can't perform adequate forced maneuvers. SVC is useful for measuring true vital capacity in severe obstruction.", difficulty: 2 }
    ]
  },
  {
    id: "airway-management",
    name: "Airway Management",
    description: "Intubation, tracheostomy care, suctioning, cuff management, difficult airway algorithms, and airway emergency procedures",
    category: "Airway Management",
    tier: "allied",
    cards: [
      { id: 1001, front: "What are the standard ETT sizes for adults?", back: "Males: 7.5-8.5 mm ID (typically 8.0). Females: 7.0-8.0 mm ID (typically 7.0-7.5). Depth: 21 cm at lip (females), 23 cm at lip (males). Confirm with CXR: tip 3-5 cm above carina (approximately T2-T4). Smaller tubes increase resistance but decrease laryngeal injury risk. Larger tubes facilitate bronchoscopy.", difficulty: 1 },
      { id: 1002, front: "What are the ETT sizes for pediatric patients?", back: "Uncuffed (age < 2): ETT size = (age/4) + 4. Cuffed: ETT size = (age/4) + 3.5. Neonates: 3.0-3.5 mm. Depth at lip ≈ ETT size × 3 (or age/2 + 12 for oral). Always have one size up and one size down available. Cuffed tubes now preferred even in young children (reduced reintubation rate).", difficulty: 2 },
      { id: 1003, front: "What equipment is needed for intubation (airway cart)?", back: "Mnemonic SOAP-ME: Suction (Yankauer + catheter), Oxygen (BVM, HFNC), Airway adjuncts (OPA, NPA, LMA), Pharmaceuticals (sedation, paralysis, vasopressors), Monitoring (SpO₂, ETCO₂, BP), Equipment (laryngoscope, ETT, stylet, bougie, video laryngoscope). Also: tape/securing device, syringe for cuff, backup plan.", difficulty: 1 },
      { id: 1004, front: "What is rapid sequence intubation (RSI)?", back: "Simultaneous administration of sedation and neuromuscular blockade to facilitate rapid intubation. Steps: pre-oxygenation (3-5 min), induction (propofol, etomidate, or ketamine), paralysis (succinylcholine or rocuronium), laryngoscopy and intubation, confirm placement. Goal: minimize aspiration risk by reducing time without airway protection.", difficulty: 2 },
      { id: 1005, front: "What are the methods to confirm ETT placement?", back: "Gold standard: continuous waveform capnography (ETCO₂). Physical: bilateral breath sounds, absent epigastric sounds, chest rise, misting of tube. Additional: direct visualization of tube through cords, CXR (tip position), colorimetric CO₂ detector (changes color), esophageal detector device. Use ETCO₂ + CXR for definitive confirmation.", difficulty: 1, clinicalPearl: "ETCO₂ is the single most reliable method — if you see persistent waveform ETCO₂, the tube is in the trachea. CXR confirms depth, not placement." },
      { id: 1006, front: "What are the complications of endotracheal intubation?", back: "Immediate: esophageal intubation, right mainstem intubation, dental/lip trauma, vocal cord injury, aspiration, hypoxemia, bradycardia (vagal), hypotension. Short-term: VAP, sinusitis, sore throat, vocal cord ulceration. Long-term: subglottic stenosis, tracheomalacia, tracheoesophageal fistula, vocal cord paralysis, granuloma.", difficulty: 2 },
      { id: 1007, front: "What is the Difficult Airway Algorithm?", back: "ASA DAA: 1) Assess airway predictors (Mallampati, thyromental distance, mouth opening, neck mobility). 2) Plan A: direct or video laryngoscopy. 3) Plan B: alternative device (LMA, bougie, video). 4) Plan C: can't intubate/can ventilate → LMA, maintain oxygenation. 5) Plan D: can't intubate/can't ventilate → surgical airway (cricothyrotomy).", difficulty: 2 },
      { id: 1008, front: "What is the Mallampati classification?", back: "Assessed with patient sitting, mouth open, tongue protruded. Class I: fauces, pillars, soft palate, uvula visible (easy intubation). Class II: fauces, soft palate, uvula partially visible. Class III: only soft palate visible. Class IV: only hard palate visible (difficult intubation expected). Higher class = more difficult intubation.", difficulty: 1 },
      { id: 1009, front: "What is a bougie (gum elastic bougie)?", back: "A semi-rigid, angled-tip introducer used when the glottis is partially visible or not visible. Inserted blindly or under laryngoscopy, advanced into trachea (feel tracheal clicks as tip passes over cartilage rings). ETT then railroaded over the bougie. Essential tool for difficult intubation. Standard length: 60 cm.", difficulty: 2, clinicalPearl: "Tracheal clicks (feeling cartilage rings) and hold-up at ~30 cm (carina) confirm tracheal placement. Smooth passage without clicks may indicate esophageal placement." },
      { id: 1010, front: "What is a supraglottic airway device (LMA)?", back: "Laryngeal Mask Airway: inserted blindly, sits over laryngeal inlet. Provides airway without intubation. No direct tracheal access. Types: classic LMA, i-gel, LMA Supreme, intubating LMA (Fastrach). Uses: rescue airway when can't intubate, brief procedures, cardiac arrest. Doesn't protect against aspiration. Size by weight.", difficulty: 1 },
      { id: 1011, front: "How is open suctioning of an ETT performed?", back: "1) Pre-oxygenate with 100% O₂ (30-60 seconds). 2) Disconnect from ventilator. 3) Insert sterile catheter without suction to resistance or carina. 4) Apply suction while withdrawing (rotating). 5) Each pass < 10-15 seconds. 6) Reconnect to ventilator. 7) Monitor SpO₂ and heart rate. Catheter size: ≤ half ETT ID. Suction: adults 100-150 mmHg.", difficulty: 1 },
      { id: 1012, front: "What are the advantages of closed (in-line) suctioning?", back: "Catheter remains in ventilator circuit — no disconnection needed. Advantages: maintains PEEP and FiO₂ during suctioning, reduces environmental contamination, prevents derecruitment (important in ARDS), reduces desaturation episodes. Disadvantage: potential for biofilm formation on catheter, technique variations. Preferred in patients requiring high PEEP or FiO₂.", difficulty: 2 },
      { id: 1013, front: "What is the proper technique for tracheostomy care?", back: "1) Suction tracheostomy before cuff deflation. 2) Clean stoma with half-strength hydrogen peroxide, then NS. 3) Replace inner cannula (disposable) or clean (reusable). 4) Change trach ties/holder when soiled. 5) Assess stoma for redness, drainage, granulation. 6) Monitor cuff pressure (20-30 cmH₂O). First trach change: 5-7 days post-insertion (tract mature).", difficulty: 1 },
      { id: 1014, front: "What are the indications for tracheostomy?", back: "Prolonged mechanical ventilation (typically >14-21 days). Upper airway obstruction (tumor, bilateral vocal cord paralysis, trauma). Facilitation of pulmonary toilet (copious secretions). Airway protection in chronic neurological conditions. Obstructive sleep apnea (failure of other interventions). Reduces sedation needs, improves comfort, enables speech.", difficulty: 1 },
      { id: 1015, front: "What is the difference between a cuffed and uncuffed tracheostomy tube?", back: "Cuffed: inflatable cuff seals trachea — prevents aspiration, allows positive pressure ventilation. Used during MV and when aspiration risk is high. Uncuffed: no cuff — allows air to pass around tube → enables speech (with finger occlusion or speaking valve). Used when mechanical ventilation is not needed and aspiration risk is low.", difficulty: 1 },
      { id: 1016, front: "What is a Passy-Muir speaking valve?", back: "One-way valve attached to tracheostomy. Opens during inspiration (air enters through trach), closes during exhalation (air forced up past deflated cuff and through vocal cords → speech). Requirements: cuff MUST be deflated (or uncuffed tube), adequate airway above trach, toleration of cuff deflation. Also improves swallowing and secretion management.", difficulty: 2 },
      { id: 1017, front: "What is cricothyrotomy and when is it performed?", back: "Emergency surgical airway through cricothyroid membrane. Indication: can't intubate AND can't ventilate/oxygenate (CICO). Technique: vertical skin incision, horizontal membrane incision, insert cuffed tube (6.0 mm ETT or commercial kit). Converts to formal tracheostomy later. Contraindicated in children < 10-12 years (use needle cricothyrotomy instead).", difficulty: 2 },
      { id: 1018, front: "What are oropharyngeal (OPA) and nasopharyngeal (NPA) airways?", back: "OPA: placed in mouth to prevent tongue from obstructing airway. Size: corner of mouth to angle of jaw. Only in unconscious patients (causes gagging if awake). NPA: soft tube through nostril to posterior pharynx. Size: tip of nose to earlobe. Tolerated in semi-conscious patients. Contraindicated in basilar skull fracture. Both are temporary adjuncts.", difficulty: 1 },
      { id: 1019, front: "What is the purpose of the ETT stylet?", back: "A malleable metal rod inserted into the ETT to maintain shape and provide rigidity during intubation. Bent into 'hockey stick' or straight shape depending on technique. Must not extend beyond ETT tip (perforation risk). Lubricate before insertion. Remove during ETT advancement into trachea. Essential for difficult airways.", difficulty: 1 },
      { id: 1020, front: "What is the optimal cuff pressure for an ETT and how is it maintained?", back: "20-30 cmH₂O. Measure with cuff manometer every 8-12 hours. Minimum occlusive volume (MOV): inflate until no leak heard during positive pressure breath. Minimum leak technique (MLT): inflate, then withdraw air until small leak heard at peak inspiration. MOV preferred to prevent micro-aspiration.", difficulty: 1 },
      { id: 1021, front: "What is subglottic secretion drainage?", back: "Special ETTs have a suction port above the cuff to drain secretions pooling in the subglottic space. Reduces VAP incidence by up to 50%. Secretions above the cuff are a major source of bacterial contamination. Can use intermittent or continuous low suction (20 mmHg). Part of VAP prevention bundle.", difficulty: 2 },
      { id: 1022, front: "What is video laryngoscopy and its advantages?", back: "Uses camera on laryngoscope blade to view glottis on screen. Types: GlideScope, C-MAC, McGrath. Advantages: better glottic view (especially in difficult airways), reduced cervical spine movement, learning tool, higher first-pass success rate. Disadvantages: may require different intubation technique (hyperangulated blade), fogging, cost.", difficulty: 2 },
      { id: 1023, front: "What are the signs of accidental extubation?", back: "Audible leak/vocalization, visible ETT displacement, acute desaturation, increased peak pressures then sudden low-pressure alarm, loss of ETCO₂ waveform, patient distress/coughing, low tidal volume alarms. Action: assess if patient can breathe spontaneously. If not → BVM ventilate, prepare for reintubation. If stable → assess for extubation readiness.", difficulty: 1 },
      { id: 1024, front: "What is the decannulation process for tracheostomy?", back: "Prerequisites: no longer needs MV, can protect airway, tolerates cuff deflation, adequate cough/secretion clearance. Steps: 1) Downsize tube. 2) Deflate cuff. 3) Cap tracheostomy (breathe through upper airway). 4) If tolerates 24-48 hours capped → remove. 5) Cover stoma with occlusive dressing. Stoma closes in days to weeks.", difficulty: 2 },
      { id: 1025, front: "What is the fenestrated tracheostomy tube?", back: "Has an opening (fenestration) in the outer cannula that allows air to pass through the upper airway for speech when the inner cannula is removed and the tube is capped/valved. Use fenestrated inner cannula for speech, non-fenestrated for suctioning and MV. Risk: granulation tissue growing through fenestration.", difficulty: 2 }
    ]
  },
  {
    id: "neonatal-respiratory-care",
    name: "Neonatal Respiratory Care",
    description: "Surfactant therapy, neonatal RDS, CPAP, neonatal ventilation, NRP, Apgar scoring, and premature infant respiratory management",
    category: "Neonatal/Pediatric",
    tier: "allied",
    cards: [
      { id: 1101, front: "What is neonatal respiratory distress syndrome (RDS)?", back: "Surfactant deficiency disease primarily affecting premature infants (<34 weeks gestation). Insufficient surfactant → high surface tension → alveolar collapse → atelectasis → hypoxemia. CXR: ground-glass appearance with air bronchograms. Risk increases with decreasing gestational age. Treatment: surfactant replacement, CPAP, mechanical ventilation.", difficulty: 1 },
      { id: 1102, front: "What is surfactant and how does it work?", back: "Lipid-protein mixture produced by Type II alveolar cells. Primary component: dipalmitoylphosphatidylcholine (DPPC). Reduces alveolar surface tension → prevents collapse at end-expiration (LaPlace's law). Production begins ~24 weeks gestation, adequate by ~34-36 weeks. Lecithin/sphingomyelin (L/S) ratio ≥ 2.0 indicates lung maturity.", difficulty: 2 },
      { id: 1103, front: "What surfactant preparations are available?", back: "Natural (animal-derived): beractant (Survanta) — bovine; calfactant (Infasurf) — calf; poractant alfa (Curosurf) — porcine. Synthetic: lucinactant (Surfaxin). Natural preparations preferred (better outcomes). Dosing: weight-based, given via ETT in divided doses with position changes. May require multiple doses.", difficulty: 2 },
      { id: 1104, front: "What is the INSURE technique?", back: "INtubate, SURfactant, Extubate. Approach for RDS: briefly intubate to administer surfactant, then quickly extubate to nasal CPAP. Reduces duration of mechanical ventilation and BPD risk. Preferred over prolonged ventilation when possible. Requires infant to have adequate respiratory drive for CPAP post-surfactant.", difficulty: 2 },
      { id: 1105, front: "What is the LISA (Less Invasive Surfactant Administration) technique?", back: "Surfactant given through a thin catheter placed in the trachea while the infant breathes spontaneously on CPAP (no intubation). Avoids mechanical ventilation entirely. Growing evidence supports LISA over INSURE for reducing BPD. Requires experience with technique. Infant must be spontaneously breathing on CPAP.", difficulty: 2 },
      { id: 1106, front: "What is neonatal CPAP and how is it applied?", back: "Continuous Positive Airway Pressure: maintains alveolar recruitment, increases FRC, stabilizes chest wall, reduces work of breathing in neonates. Delivery: nasal prongs (most common), nasal mask, nasopharyngeal tube. Initial CPAP: 5-7 cmH₂O. Titrate based on oxygenation and work of breathing. Bubble CPAP is popular in NICUs.", difficulty: 1 },
      { id: 1107, front: "What is bubble CPAP?", back: "CPAP system where the expiratory limb is submerged in water. Depth of submersion determines CPAP level (1 cm water = 1 cmH₂O). Bubbling creates oscillations that may enhance gas exchange. Simple, inexpensive, effective. Widely used in NICUs globally. CPAP level adjusted by changing water depth. Cannot exceed water depth.", difficulty: 2 },
      { id: 1108, front: "What are the initial ventilator settings for neonates?", back: "Mode: A/C or SIMV (pressure control preferred). PIP: 15-25 cmH₂O. PEEP: 4-6 cmH₂O. Rate: 30-60 breaths/min. I-time: 0.3-0.5 seconds. FiO₂: titrate to maintain SpO₂ 90-95% (preterm) or 92-97% (term). Vt target: 4-6 mL/kg. Volume-targeted ventilation increasingly preferred.", difficulty: 2 },
      { id: 1109, front: "What is the Apgar score?", back: "Assessment at 1 and 5 minutes after birth. Five components scored 0-2 each: Appearance (color), Pulse (HR), Grimace (reflex), Activity (muscle tone), Respiration. Total: 0-10. 7-10: normal. 4-6: moderately depressed. 0-3: severely depressed. Guides resuscitation but doesn't predict long-term outcomes. Continue scoring q5min if <7.", difficulty: 1 },
      { id: 1110, front: "What are the steps of the Neonatal Resuscitation Program (NRP)?", back: "1) Initial steps: warm, dry, stimulate, position, clear airway if needed (30 seconds). 2) If HR <100 or apneic → PPV with room air or blended O₂ (30 seconds). 3) If HR <60 → continue PPV + chest compressions (3:1 ratio). 4) If HR still <60 → epinephrine IV/IO (0.01-0.03 mg/kg). Reassess after each 30-second interval.", difficulty: 2 },
      { id: 1111, front: "What oxygen saturation targets are used in neonatal resuscitation?", back: "Target pre-ductal SpO₂ (right hand): 1 min: 60-65%. 2 min: 65-70%. 3 min: 70-75%. 4 min: 75-80%. 5 min: 80-85%. 10 min: 85-95%. Start with 21% O₂ for term infants, 21-30% for preterm. Titrate based on SpO₂. Avoid hyperoxia (>95% in preterm — retinopathy of prematurity risk).", difficulty: 2, clinicalPearl: "Pre-ductal SpO₂ (right hand) is used because it reflects oxygenated blood before the ductus arteriosus — post-ductal readings may be misleadingly low in transitional circulation." },
      { id: 1112, front: "What is bronchopulmonary dysplasia (BPD)?", back: "Chronic lung disease of prematurity. Defined as need for supplemental O₂ at 36 weeks postmenstrual age. Risk factors: prematurity, RDS, prolonged ventilation, oxygen toxicity, inflammation, infection. Prevention: surfactant, CPAP (avoid intubation), caffeine, low tidal volumes, vitamin A, postnatal steroids. New BPD: arrested alveolar development.", difficulty: 2 },
      { id: 1113, front: "What is the role of caffeine in neonatal respiratory care?", back: "Caffeine citrate: respiratory stimulant for apnea of prematurity. MOA: adenosine receptor antagonist → stimulates respiratory center, increases diaphragmatic contractility, increases chemoreceptor sensitivity. Loading dose: 20 mg/kg IV/PO. Maintenance: 5-10 mg/kg/day. Reduces BPD, facilitates earlier extubation. Continue until 34-36 weeks PMA.", difficulty: 2 },
      { id: 1114, front: "What is persistent pulmonary hypertension of the newborn (PPHN)?", back: "Failure of normal postnatal decrease in pulmonary vascular resistance → right-to-left shunting through PDA/foramen ovale → severe hypoxemia. Causes: MAS, CDH, RDS, sepsis, idiopathic. Pre/post-ductal SpO₂ difference >10%. Treatment: inhaled nitric oxide (iNO), optimize ventilation, high-frequency ventilation, ECMO for refractory cases.", difficulty: 2 },
      { id: 1115, front: "What is meconium aspiration syndrome (MAS)?", back: "Aspiration of meconium-stained amniotic fluid → airway obstruction, chemical pneumonitis, surfactant inactivation, PPHN. Occurs in term/post-term infants. CXR: patchy infiltrates, hyperinflation. Management: supportive (O₂, ventilation, surfactant if severe), do NOT perform routine tracheal suctioning at birth (current NRP guidelines).", difficulty: 2 },
      { id: 1116, front: "What is transient tachypnea of the newborn (TTN)?", back: "Self-limiting respiratory distress in term/near-term infants caused by delayed clearance of fetal lung fluid. Risk factors: C-section (no thoracic squeeze), rapid delivery. CXR: prominent interstitial markings, fluid in fissures. Treatment: supportive — supplemental O₂, CPAP if needed. Resolves in 24-72 hours. Rule out more serious causes.", difficulty: 1 },
      { id: 1117, front: "What is retinopathy of prematurity (ROP) and how does oxygen management prevent it?", back: "Abnormal retinal blood vessel development in premature infants exposed to excessive oxygen. Risk: gestational age <32 weeks, birth weight <1500g. Prevention: target SpO₂ 90-95% in preterm infants (avoid >95%). Screening: ophthalmic exams starting at 31 weeks PMA. Treatment: laser photocoagulation, anti-VEGF injection.", difficulty: 2 },
      { id: 1118, front: "What are the types of high-frequency ventilation used in neonates?", back: "HFOV (oscillatory): most common. Delivers tiny Vt at 8-15 Hz. Constant mean airway pressure. Used for rescue in severe RDS, air leak syndromes, PPHN. HFJV (jet): uses short bursts of gas at 240-660/min. Often combined with conventional vent. Both minimize VILI. Require special ventilators.", difficulty: 2 },
      { id: 1119, front: "What is congenital diaphragmatic hernia (CDH)?", back: "Defect in diaphragm allowing abdominal contents to enter thorax → pulmonary hypoplasia and pulmonary hypertension. Left-sided most common (Bochdalek type). Scaphoid abdomen, absent breath sounds on affected side. Do NOT bag-mask ventilate (distends stomach). Intubate immediately. Gentle ventilation strategy. Surgical repair after stabilization.", difficulty: 2 },
      { id: 1120, front: "What is antenatal corticosteroid therapy and why is it important?", back: "Betamethasone (12 mg IM × 2 doses, 24 hours apart) or dexamethasone given to mother when preterm delivery expected between 24-34 weeks. Accelerates fetal lung maturity (surfactant production). Reduces RDS by 50%, IVH, NEC, and neonatal death. Most beneficial when given >24 hours and <7 days before delivery.", difficulty: 2 },
      { id: 1121, front: "What is apnea of prematurity?", back: "Cessation of breathing ≥ 20 seconds or any pause with bradycardia (<100 bpm) and/or desaturation in preterm infants. Types: central (no effort), obstructive (effort against obstruction), mixed (most common). Caused by brainstem immaturity. Treatment: caffeine, CPAP, tactile stimulation. Resolves by 36-40 weeks PMA.", difficulty: 1 },
      { id: 1122, front: "What is the Silverman-Andersen score?", back: "Neonatal respiratory distress scoring system. Assesses 5 parameters (0-2 each): chest-abdominal synchrony, intercostal retractions, xiphoid retractions, nasal flaring, expiratory grunting. Total: 0-10. 0 = no distress. ≥7 = severe distress. Higher score = more distress (opposite of Apgar). Used to guide respiratory support escalation.", difficulty: 2 },
      { id: 1123, front: "What is the difference between nasal CPAP and nasal intermittent positive pressure ventilation (NIPPV)?", back: "NCPAP: continuous positive pressure during spontaneous breathing. NIPPV: adds mandatory breaths above CPAP level (like nasal ventilation). NIPPV may reduce intubation rates compared to CPAP alone in preterm infants. Synchronized NIPPV (detected by abdominal sensor) may be more effective than non-synchronized.", difficulty: 2 },
      { id: 1124, front: "What is the golden hour concept in neonatal care?", back: "The first 60 minutes after birth are critical for premature infant outcomes. Checklist: thermoregulation (plastic wrap, radiant warmer), delayed cord clamping (30-60 sec), respiratory support (CPAP or intubation if needed), surfactant within 2 hours if indicated, glucose management, vascular access, antibiotics if sepsis suspected.", difficulty: 2 },
      { id: 1125, front: "What are the oxygen delivery devices for neonates?", back: "Nasal cannula: 0.5-2 L/min (FiO₂ 22-40%), most common for chronic needs. Oxyhood/oxygen hood: enclosed head box with FiO₂ 21-100%, used in acute care. CPAP nasal prongs/mask: provides positive pressure + O₂. HFNC: 2-8 L/min heated/humidified. Incubator: ambient O₂ adjustment for isolette. All require precise FiO₂ monitoring via blender.", difficulty: 1 }
    ]
  },
  {
    id: "pediatric-respiratory-care",
    name: "Pediatric Respiratory Care",
    description: "Croup, bronchiolitis, epiglottitis, foreign body aspiration, pediatric asthma, and age-specific respiratory management",
    category: "Neonatal/Pediatric",
    tier: "allied",
    cards: [
      { id: 1201, front: "What is croup (laryngotracheobronchitis) and how does it present?", back: "Viral infection (usually parainfluenza type 1) causing subglottic edema. Ages: 6 months to 3 years (peak). Symptoms: barking (seal-like) cough, inspiratory stridor, hoarseness, worse at night. CXR: steeple sign (subglottic narrowing). Treatment: mild → single dose oral dexamethasone (0.6 mg/kg). Moderate/severe → add nebulized racemic epinephrine.", difficulty: 1 },
      { id: 1202, front: "What is the Westley croup score?", back: "Assesses croup severity (0-17 points): stridor (0-2), retractions (0-3), air entry (0-2), cyanosis (0-5), level of consciousness (0-5). Mild: 0-2. Moderate: 3-7. Severe: 8-11. Impending respiratory failure: ≥12. Guides treatment: mild → dexamethasone only. Moderate/severe → dexamethasone + racemic epinephrine + observation.", difficulty: 2 },
      { id: 1203, front: "What is bronchiolitis and how is it managed?", back: "Lower respiratory infection primarily caused by RSV, affecting infants (<2 years, peak 2-6 months). Symptoms: rhinorrhea → wheezing, crackles, tachypnea, respiratory distress, feeding difficulty. Management: supportive — suctioning, O₂ if SpO₂ < 90-92%, HFNC or CPAP if severe. NO routine bronchodilators, steroids, or antibiotics. Palivizumab for prevention in high-risk.", difficulty: 1 },
      { id: 1204, front: "What is epiglottitis and how does it differ from croup?", back: "Bacterial infection (H. influenzae type b, now rare due to Hib vaccine) causing supraglottic swelling. Ages: 2-6 years (classic), any age. Symptoms: rapid onset, high fever, drooling, tripod position, muffled voice, NO barking cough. CXR: thumbprint sign. EMERGENCY: do NOT examine throat, keep child calm, prepare for intubation in OR. IV antibiotics.", difficulty: 2, clinicalPearl: "The key distinction from croup: epiglottitis has rapid onset with drooling and toxic appearance, while croup has gradual onset with barking cough. Never examine the throat in suspected epiglottitis." },
      { id: 1205, front: "How does foreign body aspiration present?", back: "Sudden onset cough, choking, wheezing (usually unilateral). Most common: 1-3 years. Right mainstem bronchus more common (wider, more vertical). CXR: may show radiopaque object, unilateral hyperinflation (ball-valve effect), atelectasis. Management: rigid bronchoscopy for removal. If complete obstruction → back blows/chest thrusts (infant) or Heimlich (child).", difficulty: 1 },
      { id: 1206, front: "How does pediatric asthma management differ from adults?", back: "Ages 0-4: diagnosis challenging (no reliable spirometry). Use risk-based approach. Short course oral prednisolone for exacerbation. Ages 5-11: low-dose ICS as first controller. Step up with medium ICS or ICS+LABA. Ages ≥12: follow adult guidelines. Spacer with mask for young children. Weight-based dosing. Asthma action plans for parents/school.", difficulty: 2 },
      { id: 1207, front: "What is the pediatric assessment triangle (PAT)?", back: "Rapid visual assessment (within 30 seconds): 1) Appearance: tone, interactiveness, consolability, look/gaze, speech/cry (TICLS). 2) Work of breathing: retractions, nasal flaring, positioning, audible sounds. 3) Circulation: skin color (pallor, mottling, cyanosis). Abnormal in any domain → urgent intervention needed.", difficulty: 1 },
      { id: 1208, front: "What are the normal respiratory rates for pediatric age groups?", back: "Newborn: 30-60 breaths/min. Infant (1-12 months): 24-40. Toddler (1-3 years): 22-34. Preschool (4-5 years): 22-34. School-age (6-12 years): 18-30. Adolescent (13-17): 12-20. Tachypnea is defined relative to age-specific norms. Respiratory rate is the most sensitive vital sign for respiratory distress in children.", difficulty: 1 },
      { id: 1209, front: "What are the differences between adult and pediatric airways?", back: "Pediatric: tongue proportionally larger, epiglottis floppy/omega-shaped, larynx higher and more anterior (C3-4 vs C4-5), narrowest point at cricoid ring (subglottic — vs vocal cords in adults), shorter trachea (higher risk of mainstem intubation). Obligate nasal breathers until ~4-6 months. Small diameter = large resistance increase with edema.", difficulty: 2, clinicalPearl: "1 mm of edema in a neonatal airway (4 mm diameter) reduces the cross-sectional area by 75% and increases resistance 16-fold. This is why even mild swelling causes significant distress in infants." },
      { id: 1210, front: "What is RSV (Respiratory Syncytial Virus)?", back: "Most common cause of bronchiolitis and pneumonia in infants < 1 year. Peak: fall/winter. Transmitted by contact with respiratory secretions. Incubation: 4-6 days. High risk: premature, CHD, chronic lung disease, immunocompromised. Prevention: palivizumab (monthly IM injection for high-risk infants), nirsevimab (single dose — newer). Treatment: supportive.", difficulty: 1 },
      { id: 1211, front: "What is pertussis (whooping cough) and how does it present in children?", back: "Caused by Bordetella pertussis. Three phases: 1) Catarrhal (1-2 weeks): URI symptoms. 2) Paroxysmal (2-8 weeks): severe coughing fits followed by inspiratory 'whoop', post-tussive vomiting. 3) Convalescent: gradual improvement. Infants may present with apnea without classic whoop. Treatment: macrolide antibiotics. Prevention: DTaP vaccine.", difficulty: 2 },
      { id: 1212, front: "What is the role of HFNC in pediatric respiratory care?", back: "High-flow nasal cannula: delivers heated humidified gas at flows exceeding patient demand. Pediatric flows: 2 L/kg/min (typical starting point, max varies by age). Benefits: generates positive pressure, reduces work of breathing, improves mucociliary clearance, well-tolerated. Used in bronchiolitis, pneumonia, post-extubation. May reduce need for CPAP/intubation.", difficulty: 2 },
      { id: 1213, front: "How is status asthmaticus managed in children?", back: "Continuous albuterol nebulization (0.5 mg/kg/hr, max 15 mg/hr). Ipratropium q20min × 3 doses. IV methylprednisolone (2 mg/kg then 1 mg/kg q6h). IV magnesium sulfate (25-75 mg/kg, max 2g). If refractory: IV terbutaline, heliox, consider intubation (last resort — high risk of barotrauma). Monitor K⁺, glucose, lactate.", difficulty: 2 },
      { id: 1214, front: "What is pneumonia in pediatric patients and how does the etiology differ by age?", back: "Neonates: Group B Strep, E. coli, Listeria. 1-3 months: Chlamydia, RSV, pertussis. 3 months-5 years: viruses (most common), S. pneumoniae. >5 years: S. pneumoniae, Mycoplasma (walking pneumonia). Treatment: empiric antibiotics based on age group. Assess with CXR. Hospitalize if hypoxemic, dehydrated, or toxic-appearing.", difficulty: 2 },
      { id: 1215, front: "What is the proper BVM (bag-valve-mask) technique for infants?", back: "Size: use infant-sized bag (450-500 mL). Mask: should cover nose and mouth without covering eyes. Head position: neutral (sniffing position — avoid hyperextension). Two-person technique preferred: one holds mask with jaw thrust (EC grip), one squeezes bag. Gentle breaths to visible chest rise. Rate: 30-40/min. Avoid excessive volume.", difficulty: 1 },
      { id: 1216, front: "What are the chest compression to ventilation ratios in pediatric resuscitation?", back: "Neonates (NRP): 3:1 (3 compressions, 1 breath, at rate of 120 events/min). Infants/children (PALS): 15:2 (two rescuers) or 30:2 (single rescuer). Compression depth: infant 1.5 inches (4 cm), child 2 inches (5 cm). Rate: 100-120/min. Two-thumb encircling technique for neonates/infants.", difficulty: 1 },
      { id: 1217, front: "What is the role of heliox in pediatric respiratory emergencies?", back: "70:30 or 80:20 helium-oxygen mixture. Reduces turbulent flow resistance in narrowed airways. Uses: croup (reduces stridor/WOB while steroids take effect), severe asthma, post-extubation stridor, subglottic stenosis. Limitations: can't use if high FiO₂ needed (max 30-40% O₂ in mixture). Must use specifically calibrated equipment.", difficulty: 2 },
      { id: 1218, front: "What is the PAT (Pediatric Assessment Triangle) approach to respiratory distress?", back: "Step 1 — Across-the-room assessment: Appearance (TICLS), Work of Breathing, Circulation. Step 2 — Categorize severity: compensated (abnormal WOB, normal appearance) vs decompensated (abnormal appearance + WOB). Step 3 — Focused assessment: vitals, auscultation, SpO₂. Step 4 — Intervene based on severity.", difficulty: 1 },
      { id: 1219, front: "What is the proper pediatric suctioning technique?", back: "Nasal: use appropriately sized catheter, limit depth to measured distance (tip of nose to tragus). Oral: suction to back of throat only. Tracheal: catheter ≤ half ETT diameter. Suction pressure: neonates 60-80 mmHg, infants 80-100 mmHg, children 100-120 mmHg. Limit passes to < 10 seconds. Pre-oxygenate.", difficulty: 1 },
      { id: 1220, front: "What is the Pediatric Early Warning Score (PEWS)?", back: "Scoring system to detect clinical deterioration in hospitalized children. Assesses: behavior, cardiovascular status, respiratory status (rate, effort, SpO₂). Score 0-9. Higher score → higher risk of deterioration. Triggers escalation: nursing concern, medical review, rapid response team. Used to standardize recognition of worsening patients.", difficulty: 2 },
      { id: 1221, front: "What is viral-induced wheezing vs asthma in young children?", back: "Before age 5, recurrent wheezing is common with viral infections. Not all wheezers have asthma. Predictors of asthma: parental asthma, eczema, allergic sensitization, eosinophilia, wheezing without colds. Modified Asthma Predictive Index (mAPI) helps predict which preschoolers will develop asthma. Trial of ICS may be diagnostic.", difficulty: 2 },
      { id: 1222, front: "What is the appropriate ventilation strategy for intubated pediatric patients?", back: "Pressure control preferred (smaller, more variable lungs). PIP: 15-25 cmH₂O. PEEP: 4-6 cmH₂O. Rate: infants 20-30, children 15-20. Vt target: 5-8 mL/kg. FiO₂: titrate to SpO₂ 92-97%. I-time: 0.4-0.8 sec. Use cuffed ETTs with cuff pressure 20-25 cmH₂O. Volume-targeted ventilation increasingly used.", difficulty: 2 },
      { id: 1223, front: "What medications are used for rapid sequence intubation in pediatrics?", back: "Premedication: atropine 0.02 mg/kg (prevents bradycardia from laryngoscopy, optional >1 year). Induction: propofol (1-3 mg/kg) or ketamine (1-2 mg/kg — preferred for bronchospasm/hemodynamic instability) or etomidate (0.3 mg/kg). Paralytic: rocuronium (1 mg/kg — preferred) or succinylcholine (2 mg/kg infant, 1-1.5 mg/kg child — avoid in hyperkalemia risk).", difficulty: 2 },
      { id: 1224, front: "What is palivizumab and who should receive it?", back: "Monoclonal antibody against RSV. Given IM monthly during RSV season. Indications: premature infants (<29 weeks GA in first RSV season), infants with hemodynamically significant CHD, chronic lung disease of prematurity requiring treatment within 6 months. Nirsevimab (single-dose alternative) now available for all infants in first RSV season.", difficulty: 2 },
      { id: 1225, front: "What is the management of acute anaphylaxis in a pediatric patient?", back: "1) IM epinephrine: 0.01 mg/kg of 1:1000 (max 0.3 mg child, 0.5 mg adolescent) — anterolateral thigh. Repeat q5-15min if needed. 2) Position: supine with legs elevated. 3) O₂. 4) IV fluid bolus (NS 20 mL/kg). 5) Albuterol for bronchospasm. 6) Diphenhydramine + famotidine. 7) Dexamethasone/methylprednisolone. 8) Observe ≥4 hours.", difficulty: 2 }
    ]
  },
  {
    id: "ards-critical-care",
    name: "ARDS & Critical Care Respiratory Concepts",
    description: "Berlin criteria, prone positioning, ECMO basics, lung-protective ventilation, and critical care respiratory management",
    category: "Critical Care",
    tier: "allied",
    cards: [
      { id: 1301, front: "What is ARDS and what are the Berlin criteria?", back: "Acute Respiratory Distress Syndrome — acute, diffuse inflammatory lung injury. Berlin criteria: 1) Timing: within 1 week of clinical insult. 2) Imaging: bilateral opacities not fully explained by effusions/atelectasis. 3) Origin: not fully explained by cardiac failure/fluid overload. 4) Oxygenation: Mild P/F 200-300, Moderate 100-200, Severe <100 (all with PEEP ≥ 5).", difficulty: 2 },
      { id: 1302, front: "What are the common causes of ARDS?", back: "Direct (pulmonary): pneumonia (most common), aspiration, pulmonary contusion, inhalation injury, near-drowning. Indirect (extrapulmonary): sepsis (most common indirect), pancreatitis, massive transfusion (TRALI), trauma, burns, DIC. Pathophysiology: diffuse alveolar damage → protein-rich edema → surfactant dysfunction → atelectasis → refractory hypoxemia.", difficulty: 1 },
      { id: 1303, front: "What are the three phases of ARDS?", back: "1) Exudative (days 1-7): diffuse alveolar damage, hyaline membrane formation, protein-rich edema, capillary leak. 2) Proliferative (days 7-21): Type II cell proliferation, early fibrosis begins, some recovery possible. 3) Fibrotic (>21 days): collagen deposition, decreased compliance, pulmonary hypertension, poor prognosis if reached.", difficulty: 2 },
      { id: 1304, front: "What is the ARDSNet ventilation protocol?", back: "Tidal volume: start 6 mL/kg IBW (can go to 4 mL/kg). Plateau pressure: maintain < 30 cmH₂O. Rate: adjust for pH (up to 35/min). FiO₂/PEEP: per protocol table. SpO₂ target: 88-95%. pH target: 7.30-7.45 (permissive hypercapnia for pH 7.15-7.30 acceptable). This protocol reduced mortality from 40% to 31% in the landmark ARMA trial.", difficulty: 2 },
      { id: 1305, front: "What is prone positioning and when is it indicated?", back: "Placing patient face-down. Indications: moderate-severe ARDS (P/F < 150) within 48 hours. Duration: ≥ 16 hours/day (PROSEVA trial). Benefits: improves V/Q matching, recruits dorsal lung regions, reduces compression, improves secretion drainage. Mortality benefit proven. Contraindications: spinal instability, open abdomen, facial surgery. Requires trained team.", difficulty: 2, clinicalPearl: "Prone positioning is one of the few ARDS interventions proven to reduce mortality — don't wait until the patient is moribund to try it." },
      { id: 1306, front: "What is ECMO and what are its types?", back: "Extracorporeal Membrane Oxygenation — blood is circulated through an external membrane lung for gas exchange. VV-ECMO (veno-venous): for respiratory failure — drains and returns blood to venous system. VA-ECMO (veno-arterial): for cardiac + respiratory failure — returns oxygenated blood to arterial system. Used as bridge to recovery or transplant.", difficulty: 2 },
      { id: 1307, front: "What are the indications for VV-ECMO in ARDS?", back: "Severe refractory hypoxemia (P/F < 80 despite optimal ventilation). Murray Lung Injury Score ≥ 3.0. Failure of prone positioning and neuromuscular blockade. pH < 7.20 despite optimal ventilator settings. Potentially reversible cause. Contraindications: irreversible disease, prolonged MV (>7-10 days), severe neurological injury, age (relative).", difficulty: 3 },
      { id: 1308, front: "What is neuromuscular blockade and when is it used in ARDS?", back: "Cisatracurium (most studied) given as continuous infusion for 48 hours. Indications: severe ARDS (P/F < 150) in first 48 hours. Benefits: improves ventilator synchrony, reduces O₂ consumption, prevents dyssynchrony-related VILI. ACURASYS trial showed mortality benefit. ROSE trial was equivocal. Requires deep sedation. Monitor with train-of-four.", difficulty: 2 },
      { id: 1309, front: "What is the concept of the 'baby lung' in ARDS?", back: "In ARDS, only a fraction of the lung is aerated and functional (roughly the size of a baby's lung — ~300-500g vs 900g normal). The non-aerated regions are collapsed or consolidated. Standard tidal volumes applied to this small aerated fraction cause overdistension → VILI. This is why low Vt (4-6 mL/kg IBW) is essential.", difficulty: 2 },
      { id: 1310, front: "What are the complications of ARDS?", back: "Pulmonary: barotrauma (pneumothorax), VAP, pulmonary fibrosis, oxygen toxicity. Extrapulmonary: multi-organ dysfunction (MODS), DVT/PE, ICU-acquired weakness, delirium, PTSD, depression. Long-term: persistent lung function abnormalities, exercise limitation, neurocognitive impairment, decreased quality of life. Mortality: 30-50%.", difficulty: 2 },
      { id: 1311, front: "What is the Murray Lung Injury Score?", back: "Scoring system for ARDS severity. Four components (0-4 each): CXR consolidation, PaO₂/FiO₂ ratio, PEEP level, static compliance. Score = sum / 4. 0: no injury. 0.1-2.5: mild-moderate. >2.5: severe (ARDS). Used to help determine ECMO candidacy (score ≥3.0). Not widely used for diagnosis (Berlin criteria preferred).", difficulty: 2 },
      { id: 1312, front: "What is sepsis-related ARDS management?", back: "Treat sepsis (source control, antibiotics, resuscitation). Lung-protective ventilation (6 mL/kg IBW, Pplat <30). Conservative fluid management (FACTT trial — lower fluid balance improves outcomes). Prone positioning for P/F <150. Consider NMB for 48 hours. Low-dose corticosteroids if shock (hydrocortisone 200 mg/day). Avoid excessive fluid.", difficulty: 2 },
      { id: 1313, front: "What is the FACTT fluid management strategy for ARDS?", back: "Conservative (restrictive) fluid strategy: targets lower CVP/PCWP. Reduces ventilator days and ICU stay compared to liberal strategy. No mortality difference but improved lung function. Use diuretics to achieve neutral/negative fluid balance once hemodynamically stable. Avoid volume overload — worsens pulmonary edema.", difficulty: 2 },
      { id: 1314, front: "What is the role of recruitment maneuvers in ARDS?", back: "Sustained inflation (30-40 cmH₂O for 30-40 seconds) or incremental PEEP steps to open collapsed alveoli. Benefits: may improve oxygenation temporarily. Risks: hypotension, barotrauma, arrhythmia. ART trial: routine aggressive recruitment + decremental PEEP titration increased mortality. Current practice: use cautiously, with hemodynamic monitoring.", difficulty: 2 },
      { id: 1315, front: "What is the difference between Type I and Type II respiratory failure?", back: "Type I (hypoxemic): PaO₂ < 60 mmHg with normal or low PaCO₂. V/Q mismatch, shunt, diffusion impairment. Causes: pneumonia, ARDS, PE, pulmonary edema. Type II (hypercapnic): PaCO₂ > 50 mmHg with pH < 7.35. Ventilatory pump failure. Causes: COPD, neuromuscular disease, overdose. Can be combined (Type I + Type II).", difficulty: 1 },
      { id: 1316, front: "What is ventilator-associated event (VAE) surveillance?", back: "CDC framework replacing VAP surveillance. Tier 1: Ventilator-Associated Condition (VAC) — worsening oxygenation after ≥2 days of stability. Tier 2: Infection-Related VAC (IVAC) — VAC + fever/WBC + new antibiotic. Tier 3: Possible/Probable VAP — IVAC + purulent secretions or positive culture. More objective than traditional VAP criteria.", difficulty: 2 },
      { id: 1317, front: "What is the role of inhaled vasodilators in ARDS?", back: "Inhaled nitric oxide (iNO, 5-20 ppm) or inhaled epoprostenol: selectively vasodilate pulmonary vessels in ventilated lung regions → improve V/Q matching → improve oxygenation. No proven mortality benefit. Used as rescue therapy for refractory hypoxemia. May serve as bridge to prone positioning or ECMO. Wean slowly to avoid rebound.", difficulty: 2 },
      { id: 1318, front: "What is the 'open lung' approach to ARDS management?", back: "Strategy combining: 1) Recruitment maneuver to open collapsed alveoli. 2) PEEP set above closing pressure to keep alveoli open. 3) Low Vt to prevent overdistension. Goal: maximize aerated lung, minimize cyclic atelectrauma and volutrauma. Decremental PEEP trial: recruit, then stepwise decrease PEEP until compliance drops → set PEEP 2-3 above that.", difficulty: 2 },
      { id: 1319, front: "What is ICU-acquired weakness (ICUAW)?", back: "Diffuse, symmetric weakness developing during ICU stay. Risk factors: sepsis, MODS, prolonged MV, immobility, NMB use, corticosteroids, hyperglycemia. Types: critical illness polyneuropathy (CIP), critical illness myopathy (CIM). Prevention: early mobilization, minimize sedation, glycemic control, avoid prolonged NMB. Affects ventilator weaning and recovery.", difficulty: 2 },
      { id: 1320, front: "What is the approach to refractory hypoxemia in ARDS?", back: "Stepwise escalation: 1) Optimize ventilator (lung-protective, PEEP/FiO₂ table). 2) Prone positioning (≥16 hours). 3) Neuromuscular blockade (48 hours). 4) Inhaled vasodilators (iNO/epoprostenol). 5) Recruitment maneuvers (cautious). 6) ECMO consideration. Each step should be tried before escalating. Don't delay proven interventions.", difficulty: 2 },
      { id: 1321, front: "What is the P/F ratio trend and how does it guide management?", back: "Serial P/F ratios track ARDS trajectory. Improving P/F (>200, then >300): consider weaning FiO₂ and PEEP. Stable P/F: maintain current strategy. Worsening P/F (<150): escalate (prone, NMB, consider ECMO). A P/F < 100 on optimal settings for >6 hours despite prone position → ECMO evaluation. Always calculate P/F during ARDS management.", difficulty: 2 },
      { id: 1322, front: "What is liberation from mechanical ventilation in ARDS?", back: "Prerequisites: FiO₂ ≤ 0.40, PEEP ≤ 8, improving CXR, adequate mentation. Daily SAT + SBT (ABCDEF bundle). SBT on PS 5-8 or T-piece for 30-120 minutes. Extubate if: RR < 35, SpO₂ ≥ 90%, HR stable, no distress, adequate cough, minimal secretions. Post-extubation: HFNC or NIV can reduce reintubation risk.", difficulty: 2 },
      { id: 1323, front: "What is the difference between cardiogenic and non-cardiogenic pulmonary edema?", back: "Cardiogenic: elevated hydrostatic pressure (CHF, valvular disease). CXR: cephalization, Kerley B lines, pleural effusions, cardiomegaly. BNP elevated. Responds to diuretics. Non-cardiogenic (ARDS): increased permeability. CXR: bilateral diffuse infiltrates, normal heart size. BNP normal. Doesn't respond well to diuretics. Protein-rich edema fluid.", difficulty: 2 },
      { id: 1324, front: "What is the ABCDEF ICU liberation bundle?", back: "A: Assess/manage pain. B: Both SAT and SBT daily. C: Choice of analgesia and sedation (minimize). D: Delirium assessment and management (CAM-ICU). E: Early mobility and exercise. F: Family engagement. Evidence-based approach to reduce ventilator days, delirium, ICU-acquired weakness, and improve outcomes.", difficulty: 1 },
      { id: 1325, front: "What is the role of corticosteroids in COVID-19 ARDS?", back: "Dexamethasone 6 mg/day (IV or PO) × 10 days: RECOVERY trial showed 29% reduction in 28-day mortality in patients requiring invasive MV, 20% reduction in those on O₂. No benefit (possible harm) in patients not requiring O₂. This was a landmark finding — first drug proven to reduce COVID-19 mortality. Now standard of care.", difficulty: 2 }
    ]
  },
  {
    id: "respiratory-assessment",
    name: "Respiratory Assessment & Patient Monitoring",
    description: "Chest assessment techniques, breath sounds, pulse oximetry, capnography, chest X-ray basics, and clinical monitoring",
    category: "Assessment",
    tier: "allied",
    cards: [
      { id: 1401, front: "What are the components of a respiratory assessment?", back: "Inspection: respiratory rate, pattern, depth, symmetry, accessory muscle use, skin color, body position. Palpation: chest expansion, tactile fremitus, tracheal position, subcutaneous emphysema. Percussion: resonance (normal), hyperresonance (pneumothorax/emphysema), dullness (consolidation/effusion). Auscultation: breath sounds, adventitious sounds.", difficulty: 1 },
      { id: 1402, front: "What are normal (vesicular) breath sounds?", back: "Soft, low-pitched, heard over peripheral lung fields. Inspiration longer than expiration (~3:1 ratio). No pause between I and E. Represent turbulent flow in larger airways filtered through normal lung parenchyma. Decreased/absent vesicular sounds: pleural effusion, pneumothorax, atelectasis, hyperinflation, obesity.", difficulty: 1 },
      { id: 1403, front: "What are bronchial breath sounds and when are they abnormal?", back: "Loud, high-pitched, tubular sounds. Expiration longer than inspiration (~2:3 ratio). Pause between I and E. Normal over trachea. ABNORMAL if heard over peripheral lung — indicates consolidated lung tissue (pneumonia) transmitting tracheal sounds. Also heard over large cavity or above pleural effusion.", difficulty: 1 },
      { id: 1404, front: "What are crackles (rales)?", back: "Discontinuous, brief popping sounds. Fine crackles: high-pitched, end-inspiratory, heard in dependent lung zones. Causes: pulmonary fibrosis, early CHF, atelectasis. Coarse crackles: low-pitched, louder, heard in early inspiration and possibly expiration. Causes: pneumonia, bronchiectasis, severe pulmonary edema. May clear with coughing.", difficulty: 1 },
      { id: 1405, front: "What are wheezes?", back: "Continuous, musical, high-pitched sounds. Caused by airflow through narrowed airways. Expiratory wheezes: most common, bronchospasm, asthma, COPD. Inspiratory wheezes: suggest more severe obstruction. Monophonic (single pitch): fixed obstruction (tumor, foreign body). Polyphonic (multiple pitches): diffuse airway narrowing (asthma, COPD). Absence of wheeze in severe asthma = ominous ('silent chest').", difficulty: 1, clinicalPearl: "A silent chest in an asthmatic patient is more dangerous than wheezing — it means airflow is so limited that wheezes can't be generated. This is a medical emergency." },
      { id: 1406, front: "What is stridor?", back: "High-pitched, monophonic sound heard best over the neck. Indicates upper airway (extrathoracic) obstruction. Inspiratory stridor: supraglottic/glottic obstruction (croup, epiglottitis, foreign body). Biphasic stridor: subglottic/tracheal obstruction (tracheal stenosis). Causes: croup, epiglottitis, anaphylaxis, post-extubation edema, foreign body. Always a medical urgency.", difficulty: 1 },
      { id: 1407, front: "What is pleural friction rub?", back: "Grating, creaking sound heard during both inspiration and expiration. Caused by inflamed pleural surfaces rubbing together. Sounds like walking on fresh snow. Localized to area of pleurisy. Disappears with breath-holding (distinguishes from pericardial rub). Causes: pleurisy, pulmonary infarction, pneumonia extending to pleura.", difficulty: 2 },
      { id: 1408, front: "How does pulse oximetry (SpO₂) work?", back: "Uses two wavelengths of light (red 660 nm and infrared 940 nm) to measure ratio of oxyhemoglobin to deoxyhemoglobin in pulsatile arterial blood. Calculates SpO₂. Accuracy: ±2% for SpO₂ 70-100%. Response time: 30-60 seconds. Measures saturation (SaO₂ surrogate), NOT PaO₂ or oxygen content.", difficulty: 1 },
      { id: 1409, front: "What conditions cause inaccurate pulse oximetry readings?", back: "Falsely high: CO poisoning (COHb reads as HbO₂), methemoglobinemia (reads ~85% regardless). Falsely low: nail polish (especially blue/black), poor perfusion (shock, hypothermia), motion artifact, venous pulsations. Unreliable: severe anemia (normal SpO₂ but low O₂ content), dark skin pigment (may overestimate in hypoxemia). Always correlate clinically.", difficulty: 2 },
      { id: 1410, front: "What is capnography (ETCO₂) and how does it work?", back: "Measures CO₂ concentration in exhaled gas. Normal ETCO₂: 35-45 mmHg (close to PaCO₂, typically 2-5 mmHg lower). Mainstream: sensor at airway. Sidestream: sample drawn to remote sensor. Uses: ETT placement confirmation (gold standard), ventilation monitoring, CPR quality indicator, procedural sedation monitoring.", difficulty: 1 },
      { id: 1411, front: "How do you interpret capnography waveform abnormalities?", back: "Normal: rectangular waveform with plateau. Shark fin (sloping upstroke): bronchospasm/airway obstruction. No waveform: esophageal intubation, disconnection, cardiac arrest. Sudden drop to zero: extubation, circuit disconnect. Gradually rising baseline: rebreathing CO₂. Falling ETCO₂: hyperventilation, decreased perfusion (PE, cardiac arrest).", difficulty: 2 },
      { id: 1412, front: "What are the normal arterial blood gas values?", back: "pH: 7.35-7.45. PaCO₂: 35-45 mmHg. PaO₂: 80-100 mmHg. HCO₃⁻: 22-26 mEq/L. BE: −2 to +2 mEq/L. SaO₂: 95-100%. These values are for room air at sea level. Always interpret in clinical context (altitude, chronic conditions, supplemental O₂).", difficulty: 1 },
      { id: 1413, front: "What is the modified Allen test and when is it performed?", back: "Performed before radial artery puncture (ABG). Tests adequacy of collateral ulnar blood supply. Technique: occlude both radial and ulnar arteries, have patient clench fist, release ulnar artery. Positive (normal): hand re-pinks in <5-10 seconds (adequate collateral). Negative: delayed refill → don't puncture radial (use other site).", difficulty: 1 },
      { id: 1414, front: "What does a chest X-ray show in pneumonia?", back: "Consolidation: lobar (dense opacification of an entire lobe — typical bacterial), patchy/interstitial (atypical — Mycoplasma, viral), bilateral diffuse (PCP, severe viral). Air bronchograms (air-filled bronchi visible against consolidated lung). Pleural effusion (parapneumonic). Cavitation (abscess, TB, Staph). Compare with prior films.", difficulty: 2 },
      { id: 1415, front: "What does a chest X-ray show in pneumothorax?", back: "Visceral pleural line visible with absence of lung markings beyond it. Lung appears collapsed toward hilum. Deep sulcus sign on supine CXR (lateral costophrenic angle deepens). Tension pneumothorax: mediastinal shift AWAY from affected side, tracheal deviation, compressed contralateral lung, flattened hemidiaphragm.", difficulty: 2 },
      { id: 1416, front: "What does a chest X-ray show in pleural effusion?", back: "Upright: meniscus sign (fluid creates curved upper border), blunting of costophrenic angle (>200 mL to detect). Lateral decubitus: layering of free fluid. Massive effusion: opacification of hemithorax with mediastinal shift away. Loculated effusion: doesn't shift with position change. Bilateral effusions: CHF, nephrotic syndrome.", difficulty: 2 },
      { id: 1417, front: "What is tactile (vocal) fremitus?", back: "Vibration felt on chest wall when patient says '99' or 'boy.' Increased fremitus: consolidation (pneumonia) — solid tissue transmits vibrations better. Decreased fremitus: pleural effusion (fluid blocks vibrations), pneumothorax (air blocks vibrations), obesity, COPD (hyperinflation). Compare symmetric areas bilaterally.", difficulty: 2 },
      { id: 1418, front: "What are the patterns of abnormal breathing?", back: "Kussmaul: deep, rapid — metabolic acidosis (DKA). Cheyne-Stokes: crescendo-decrescendo with apnea — CHF, stroke. Biot's (ataxic): irregular with sudden apnea — brainstem damage. Apneustic: prolonged inspiration with pause — pons damage. Paradoxical: abdomen/chest move opposite — diaphragm paralysis. Agonal: gasping — near death.", difficulty: 2 },
      { id: 1419, front: "What is the Borg dyspnea scale?", back: "Subjective scale from 0-10 (modified) or 6-20 (original). 0 = nothing at all, 3 = moderate, 5 = severe, 7 = very severe, 10 = maximal. Used to assess patient's perception of breathing difficulty during exercise testing, pulmonary rehab, and clinical assessment. Correlates with objective measures of respiratory function.", difficulty: 1 },
      { id: 1420, front: "What is the significance of digital clubbing?", back: "Bulbous enlargement of fingertip with loss of normal angle (Lovibond angle >180°, Schamroth window disappears). Causes: lung cancer (#1), chronic hypoxemia (COPD, bronchiectasis, pulmonary fibrosis), cystic fibrosis, endocarditis, IBD, liver cirrhosis. Mechanism: unclear — possibly platelet-derived growth factor. Develops over weeks-months.", difficulty: 2 },
      { id: 1421, front: "How do you assess work of breathing?", back: "Signs of increased WOB: tachypnea, accessory muscle use (SCM, scalenes, intercostals), nasal flaring, retractions (intercostal, subcostal, suprasternal), pursed-lip breathing, tripod positioning, diaphoresis, inability to speak in full sentences, paradoxical breathing (abdominal/chest). Quantified by respiratory rate, RSBI, and clinical assessment.", difficulty: 1 },
      { id: 1422, front: "What is the role of co-oximetry?", back: "Advanced spectrophotometry measuring multiple hemoglobin species: oxyhemoglobin (O₂Hb), deoxyhemoglobin, carboxyhemoglobin (COHb), methemoglobin (MetHb). Standard pulse oximetry only differentiates two species. Co-oximetry is essential for CO poisoning (COHb), methemoglobinemia, and critical illness where standard SpO₂ may be inaccurate.", difficulty: 2 },
      { id: 1423, front: "What is the PaCO₂ − ETCO₂ gradient and what does it indicate?", back: "Normal: 2-5 mmHg (PaCO₂ slightly higher than ETCO₂). Increased gradient: dead space ventilation (PE, decreased cardiac output, COPD). Decreased gradient (or ETCO₂ > PaCO₂): rebreathing, contamination with exhaled gas. Trending ETCO₂ is useful for monitoring ventilation without repeated ABGs.", difficulty: 2 },
      { id: 1424, front: "What is the significance of tracheal deviation on physical exam?", back: "Trachea shifts TOWARD: atelectasis (volume loss pulls mediastinum), pneumonectomy, upper lobe fibrosis. Trachea shifts AWAY: tension pneumothorax (pressure pushes mediastinum — EMERGENCY), large pleural effusion, large mass. Check at the sternal notch. Subtle deviation may only be detectable on CXR/CT.", difficulty: 2 },
      { id: 1425, front: "What information does the respiratory therapist report during patient handoff?", back: "SBAR format: Situation (current respiratory status, device, settings). Background (diagnosis, baseline, recent changes). Assessment (current SpO₂, ABG, breath sounds, WOB, vitals, mental status). Recommendation (planned changes, concerns, pending tests). Include: vent settings, recent changes, response to interventions, upcoming procedures.", difficulty: 1 }
    ]
  },
  {
    id: "weaning-extubation",
    name: "Weaning & Extubation",
    description: "Spontaneous breathing trials, RSBI, weaning parameters, extubation criteria, and post-extubation care strategies",
    category: "Mechanical Ventilation",
    tier: "allied",
    cards: [
      { id: 1501, front: "What are the prerequisites for initiating ventilator weaning?", back: "1) Underlying cause improving/resolved. 2) Adequate oxygenation: PaO₂ ≥ 60 on FiO₂ ≤ 0.40, PEEP ≤ 5-8. 3) Hemodynamically stable (no/low vasopressors). 4) Adequate mental status (follows commands). 5) Adequate respiratory drive. 6) No planned procedures requiring heavy sedation. 7) Manageable secretions. 8) Adequate cough strength.", difficulty: 1 },
      { id: 1502, front: "What is the RSBI (Rapid Shallow Breathing Index)?", back: "RSBI = respiratory rate / tidal volume (in liters). Measured during 1-2 minutes of unassisted breathing. RSBI < 105: predicts successful weaning (positive predictive value ~80%). RSBI > 105: predicts failure (high sensitivity). Example: RR 20, Vt 0.4L → RSBI = 50 (favorable). RR 35, Vt 0.2L → RSBI = 175 (unfavorable).", difficulty: 1, clinicalPearl: "RSBI is the single best predictor of weaning success. Calculate it before every SBT — it takes only 1 minute and can prevent premature extubation failure." },
      { id: 1503, front: "What is a Spontaneous Breathing Trial (SBT)?", back: "Period of minimal or no ventilator support to assess readiness for extubation. Methods: T-piece (no support), PSV 5-8 cmH₂O + PEEP 5, or CPAP 5 cmH₂O. Duration: 30-120 minutes (30 min may be sufficient). Monitor: RR, HR, SpO₂, BP, WOB, mental status. Failure criteria: RR > 35, SpO₂ < 90%, HR change > 20%, distress.", difficulty: 1 },
      { id: 1504, front: "What are the failure criteria during an SBT?", back: "RR > 35 for > 5 minutes. SpO₂ < 90%. HR > 140 or change > 20%. Systolic BP > 180 or < 90. Agitation, diaphoresis, anxiety. Increased WOB (accessory muscles, retractions). Arrhythmia. If any criterion met → terminate SBT, return to full support, reassess in 24 hours, identify and address barriers.", difficulty: 1 },
      { id: 1505, front: "What is the SAT/SBT protocol (Wake Up and Breathe)?", back: "Daily paired Spontaneous Awakening Trial (SAT) + Spontaneous Breathing Trial (SBT). SAT: stop/reduce sedation, assess wakefulness. If passes SAT → proceed to SBT. Landmark ABC trial showed: paired SAT+SBT reduces MV duration by 3 days, ICU stay by 4 days, and 1-year mortality. Part of ABCDEF bundle.", difficulty: 2 },
      { id: 1506, front: "What are the traditional weaning parameters?", back: "Negative inspiratory force (NIF/MIP): ≤ −20 to −30 cmH₂O (adequate muscle strength). Vital capacity: > 10-15 mL/kg. Minute ventilation: < 10 L/min. Tidal volume: > 5 mL/kg. RSBI: < 105. PaO₂/FiO₂: > 150-200. Maximum voluntary ventilation: > 2× resting V̇E. These are screening tools, not definitive predictors.", difficulty: 2 },
      { id: 1507, front: "What is NIF (Negative Inspiratory Force) / MIP?", back: "Maximum negative pressure generated during inspiration against an occluded airway. Measures inspiratory muscle strength (primarily diaphragm). Technique: occlude airway at end-expiration for 20 seconds, measure most negative pressure. Normal: −80 to −120 cmH₂O. Adequate for weaning: ≤ −20 to −30 cmH₂O. More negative = stronger muscles.", difficulty: 2 },
      { id: 1508, front: "What are the causes of weaning failure?", back: "Respiratory: unresolved lung disease, excessive secretions, bronchospasm, weak respiratory muscles, auto-PEEP. Cardiac: CHF (LV dysfunction unmasked by positive pressure removal), ischemia. Neurological: inadequate drive (sedation, CNS disease), delirium. Other: metabolic (electrolytes, nutrition), psychological (anxiety, ventilator dependence), anemia.", difficulty: 2 },
      { id: 1509, front: "What is the cuff leak test and when is it performed?", back: "Assesses for laryngeal edema before extubation. Deflate ETT cuff, observe air leak around tube. Qualitative: listen for audible leak. Quantitative: in VCV, compare inspired and expired Vt — leak > 110-130 mL suggests minimal edema. No leak or small leak → higher risk of post-extubation stridor. Consider steroids (methylprednisolone 20mg q4h × 4 doses) before extubation.", difficulty: 2 },
      { id: 1510, front: "What is the extubation procedure?", back: "1) Ensure SBT passed. 2) Suction ETT and oropharynx. 3) Sit patient up (30-45°). 4) Preoxygenate. 5) Deflate cuff. 6) Remove ETT at end-inspiration or during cough. 7) Apply supplemental O₂ (NC, HFNC, or NIV as planned). 8) Assess voice, cough, swallow. 9) Monitor closely for 24-48 hours. NPO for 2-4 hours post-extubation.", difficulty: 1 },
      { id: 1511, front: "What is post-extubation stridor and how is it managed?", back: "Inspiratory stridor after extubation — indicates laryngeal/subglottic edema. Risk factors: prolonged intubation, large ETT, traumatic intubation, female, failed cuff leak test. Treatment: racemic epinephrine nebulization, IV dexamethasone, heliox. If severe/refractory → reintubation (with smaller ETT), consider tracheostomy. Prevention: pre-extubation steroids if at risk.", difficulty: 2 },
      { id: 1512, front: "What is the role of HFNC after extubation?", back: "Post-extubation HFNC reduces reintubation rate compared to conventional O₂. Particularly beneficial in high-risk patients: age >65, cardiac disease, respiratory disease, BMI >30, prolonged MV. HFNC provides positive pressure, CO₂ washout, and humidification. May be superior to or equivalent to prophylactic NIV in some populations.", difficulty: 2 },
      { id: 1513, front: "What is the role of prophylactic NIV after extubation?", back: "Prophylactic (preventive) NIV applied immediately after extubation in high-risk patients reduces reintubation and mortality. Use for: COPD, CHF, hypercapnia during SBT, age >65, multiple comorbidities. Therapeutic NIV (applied after respiratory failure develops post-extubation) may DELAY reintubation and worsen outcomes — avoid.", difficulty: 2 },
      { id: 1514, front: "What is prolonged mechanical ventilation (PMV)?", back: "Generally defined as ≥ 21 days of MV for ≥ 6 hours/day. Affects ~5-10% of ICU patients. Causes: neuromuscular weakness, persistent respiratory failure, delirium, cardiac dysfunction. May require tracheostomy. Weaning: gradual (progressive lengthening of SBT), may take weeks-months. Consider long-term acute care (LTAC) facility.", difficulty: 2 },
      { id: 1515, front: "What is the ventilator liberation protocol?", back: "Systematic approach: 1) Daily screening for readiness (checklist). 2) SAT (lighten/stop sedation). 3) SBT (30-120 min on minimal support). 4) If SBT passed → assess for extubation (cough strength, secretions, mental status, upper airway patency). 5) Post-extubation plan (O₂ device, monitoring, escalation plan). Protocol-driven approach reduces MV duration.", difficulty: 1 },
      { id: 1516, front: "What is the role of diaphragm ultrasound in weaning?", back: "Bedside ultrasound measures diaphragm thickness and thickening fraction (DTF). DTF = (thickness at end-inspiration − thickness at end-expiration) / thickness at end-expiration × 100. DTF > 30-36%: adequate diaphragm function, likely weaning success. DTF < 20%: diaphragm dysfunction, likely weaning failure. Non-invasive, reproducible, can be done daily.", difficulty: 2 },
      { id: 1517, front: "What is tracheostomy-related weaning?", back: "Steps: 1) Wean ventilator support (reduce rate, PS). 2) Transition to trach collar/T-piece trials (increasing duration). 3) When tolerating 24-48 hours off vent → wean O₂. 4) Downsize tracheostomy tube. 5) Deflate cuff. 6) Cap tracheostomy (breathe through upper airway). 7) If tolerates capping → decannulate. May take weeks to months.", difficulty: 2 },
      { id: 1518, front: "How does cardiac function affect weaning?", back: "Removing positive pressure → increased venous return → increased LV preload → may precipitate CHF (especially in patients with LV dysfunction). Also: increased LV afterload (loss of positive pressure splinting). Signs of cardiac-related weaning failure: tachycardia, hypertension, pulmonary edema during SBT. Management: diuresis, inotropes, NIV, gradual weaning.", difficulty: 2 },
      { id: 1519, front: "What are the extubation readiness criteria?", back: "1) Passed SBT. 2) Adequate cough (able to clear secretions). 3) Minimal secretions (suctioning < q2h). 4) Alert, follows commands. 5) Positive cuff leak (if at risk for stridor). 6) Upper airway patency. 7) No planned return to OR. 8) Hemodynamically stable. 9) Appropriate post-extubation plan (O₂, monitoring, escalation plan).", difficulty: 1 },
      { id: 1520, front: "What is the reintubation rate and what increases the risk?", back: "Expected reintubation rate: 10-15% within 48-72 hours (some failure is acceptable — a 0% rate suggests under-extubation). Risk factors: age >65, COPD, CHF, prolonged MV, failed cuff leak, weak cough, excessive secretions, high acuity. Reintubation increases mortality, ICU stay, and VAP risk. Use prophylactic HFNC/NIV in high-risk patients.", difficulty: 2 },
      { id: 1521, front: "What is the 'leak around' test for pediatric ETTs?", back: "Particularly important for uncuffed pediatric ETTs. With positive pressure ventilation (20-25 cmH₂O), listen for air leak around the tube. No leak: tube may be too large (risk mucosal ischemia). Large leak at low pressure: tube too small (inadequate ventilation). Ideal: audible leak at 20-30 cmH₂O. Guides tube size selection and extubation readiness.", difficulty: 2 },
      { id: 1522, front: "What is the impact of nutrition on ventilator weaning?", back: "Malnutrition → respiratory muscle wasting → weaning failure. Overfeeding → excess CO₂ production → increased ventilatory demand → weaning failure. Optimal: protein 1.2-2.0 g/kg/day, calories at measured/estimated REE. High-fat, low-carb formulas reduce CO₂ production (RQ lower). Correct electrolytes (phosphate, magnesium, potassium — essential for muscle function).", difficulty: 2, clinicalPearl: "Low phosphate is an underrecognized cause of weaning failure — phosphate is essential for ATP production in respiratory muscles. Always check and correct." },
      { id: 1523, front: "What is automated weaning (SmartCare/PS, ASV)?", back: "Computer-driven protocols that automatically adjust ventilator support based on patient parameters. SmartCare/PS: adjusts PS level based on RR, Vt, ETCO₂. ASV (Adaptive Support Ventilation): adjusts rate and pressure to achieve target V̇E with minimal WOB. Studies show automated weaning may reduce MV duration compared to physician-directed weaning.", difficulty: 3 },
      { id: 1524, front: "What is the significance of the P0.1 measurement in weaning?", back: "P0.1: airway occlusion pressure at 0.1 seconds — measures respiratory drive. Normal: 1-2 cmH₂O. P0.1 > 4-6 cmH₂O: excessive drive (high WOB, likely to fail weaning). P0.1 < 1: inadequate drive (over-sedation, CNS depression). Used to assess respiratory center output without requiring patient cooperation.", difficulty: 3 },
      { id: 1525, front: "What are the criteria for weaning failure requiring return to full support?", back: "During SBT: RR > 35, SpO₂ < 90%, HR change > 20%, arrhythmia, systolic BP > 180 or < 90, increased WOB, agitation/diaphoresis, RSBI > 105. After extubation: increasing O₂ requirements, tachypnea, desaturation, stridor, inability to clear secretions. Reintubate within 24-48 hours if post-extubation failure develops.", difficulty: 1 }
    ]
  },
  {
    id: "hemodynamics-gas-exchange",
    name: "Hemodynamics & Gas Exchange",
    description: "V/Q relationships, shunt, dead space, oxygen transport, CO₂ transport, and the oxyhemoglobin dissociation curve",
    category: "Physiology",
    tier: "allied",
    cards: [
      { id: 1601, front: "What is V/Q (ventilation-perfusion) matching?", back: "Ratio of alveolar ventilation (V̇A) to pulmonary blood flow (Q̇). Normal V/Q = 0.8 (4 L/min ventilation ÷ 5 L/min perfusion). Ideal: V/Q = 1.0. V/Q mismatch is the most common cause of hypoxemia. V/Q varies within the lung: higher at apex (more ventilation relative to perfusion), lower at base.", difficulty: 2 },
      { id: 1602, front: "What is intrapulmonary shunt?", back: "Blood passes through the lungs without gas exchange. V/Q = 0 (perfusion without ventilation). True shunt: blood bypasses alveoli entirely (intracardiac shunt, AVM) or flows past completely collapsed/filled alveoli (atelectasis, pneumonia, ARDS). Shunt doesn't respond well to supplemental O₂ (unventilated blood can't be oxygenated). Respond to PEEP/recruitment.", difficulty: 2, clinicalPearl: "If hypoxemia doesn't improve significantly with 100% O₂, suspect true shunt — this is a key clinical distinction from V/Q mismatch." },
      { id: 1603, front: "What is dead space ventilation?", back: "Ventilation without perfusion. V/Q = infinity. Anatomic dead space: conducting airways (~150 mL). Alveolar dead space: alveoli ventilated but not perfused (PE, decreased CO, overdistension). Physiologic dead space = anatomic + alveolar. Vd/Vt ratio normally 0.20-0.40. Increased dead space → need more V̇E for adequate CO₂ elimination.", difficulty: 2 },
      { id: 1604, front: "How do you calculate the shunt fraction (Qs/Qt)?", back: "Qs/Qt = (CcO₂ − CaO₂) / (CcO₂ − CvO₂). CcO₂ = pulmonary capillary O₂ content (calculated assuming PAO₂ = alveolar PO₂). CaO₂ = arterial O₂ content. CvO₂ = mixed venous O₂ content. Normal: < 5%. In ARDS, shunt can be 20-50%. Simplified: if P/F < 200 on FiO₂ 1.0 → shunt likely > 20%.", difficulty: 3 },
      { id: 1605, front: "How do you calculate the Vd/Vt ratio (dead space fraction)?", back: "Vd/Vt = (PaCO₂ − PĒCO₂) / PaCO₂ (Bohr equation). PĒCO₂ = mixed expired CO₂. Normal: 0.20-0.40 (20-40%). Increased in: PE, decreased cardiac output, COPD, overdistension. Clinically estimated by PaCO₂ − ETCO₂ gradient (normally 2-5 mmHg; larger gradient = more dead space).", difficulty: 3 },
      { id: 1606, front: "What is hypoxic pulmonary vasoconstriction (HPV)?", back: "Protective reflex where pulmonary arterioles constrict in response to alveolar hypoxia. Diverts blood away from poorly ventilated alveoli toward better-ventilated areas → optimizes V/Q matching. Impaired by: vasodilators, volatile anesthetics, sepsis, high FiO₂ (releases HPV, worsening V/Q matching). Enhanced by: metabolic acidosis.", difficulty: 2 },
      { id: 1607, front: "What is the alveolar gas equation?", back: "PAO₂ = FiO₂(Patm − PH₂O) − (PaCO₂ / RQ). At sea level: PAO₂ = FiO₂(760 − 47) − (PaCO₂ / 0.8). On room air: PAO₂ ≈ 150 − (PaCO₂ × 1.25). Used to calculate expected alveolar PO₂ and determine A-a gradient. Essential for identifying the mechanism of hypoxemia.", difficulty: 2 },
      { id: 1608, front: "What are the five mechanisms of hypoxemia?", back: "1) Low FiO₂ (high altitude). 2) Hypoventilation (elevated PaCO₂). 3) V/Q mismatch (most common — COPD, asthma, pneumonia). 4) Shunt (intracardiac or intrapulmonary — ARDS, atelectasis). 5) Diffusion impairment (pulmonary fibrosis, emphysema). V/Q mismatch and shunt distinguished by response to supplemental O₂.", difficulty: 2 },
      { id: 1609, front: "What is the Bohr effect?", back: "Decreased pH (increased H⁺ or CO₂) decreases hemoglobin's oxygen affinity → rightward shift of oxyhemoglobin curve → promotes O₂ release to tissues. In active tissues: metabolism produces CO₂ and H⁺ → Bohr effect facilitates O₂ unloading. In lungs: CO₂ is exhaled → pH rises → increases O₂ loading onto hemoglobin.", difficulty: 2 },
      { id: 1610, front: "How is CO₂ transported in the blood?", back: "Three forms: 1) Dissolved CO₂ (5-10%) — directly proportional to PaCO₂. 2) Carbaminohemoglobin (20-30%) — CO₂ bound to hemoglobin amino groups. 3) Bicarbonate (60-70%) — CO₂ + H₂O → H₂CO₃ → H⁺ + HCO₃⁻ (catalyzed by carbonic anhydrase in RBCs). Chloride shift maintains electrical neutrality.", difficulty: 2 },
      { id: 1611, front: "What is the chloride shift?", back: "When CO₂ enters RBCs and is converted to HCO₃⁻, the bicarbonate moves out to plasma. To maintain electrical neutrality, Cl⁻ moves INTO the RBC (chloride shift/Hamburger phenomenon). In the lungs, the process reverses: HCO₃⁻ enters RBC, Cl⁻ exits, and CO₂ is reformed and exhaled.", difficulty: 3 },
      { id: 1612, front: "What is 2,3-DPG and how does it affect oxygen transport?", back: "2,3-diphosphoglycerate (2,3-BPG): produced by RBC glycolysis. Binds to deoxyhemoglobin → reduces O₂ affinity → rightward shift → facilitates O₂ release to tissues. Increased 2,3-DPG: anemia, chronic hypoxemia, high altitude, hyperthyroidism. Decreased: stored blood (depleted over 1-2 weeks), hypothermia, alkalosis.", difficulty: 2 },
      { id: 1613, front: "What is oxygen delivery (DO₂) and how is it calculated?", back: "DO₂ = CO × CaO₂ × 10. Where CO = cardiac output (L/min), CaO₂ = arterial oxygen content (mL O₂/dL). Normal: 900-1100 mL O₂/min. Three determinants: cardiac output, hemoglobin, SaO₂. DO₂ must exceed O₂ consumption (VO₂ ~250 mL/min). If DO₂ falls below critical threshold → tissue hypoxia → lactic acidosis.", difficulty: 2 },
      { id: 1614, front: "What is the O₂ extraction ratio?", back: "O₂ER = (CaO₂ − CvO₂) / CaO₂ × 100. Or: O₂ER = VO₂ / DO₂. Normal: 25% (tissues extract ~25% of delivered O₂). Increased O₂ER (>30%): compensation for decreased DO₂ (anemia, low CO, hypoxemia). Critically ill patients: if O₂ER > 50%, DO₂ is critically low. SvO₂ < 65% reflects increased extraction.", difficulty: 2 },
      { id: 1615, front: "What is mixed venous oxygen saturation (SvO₂)?", back: "O₂ saturation of blood in the pulmonary artery (requires PA catheter). Normal: 65-75%. Reflects balance between O₂ delivery and consumption. Low SvO₂ (<65%): increased extraction (low CO, anemia, hypoxemia, increased O₂ demand). High SvO₂ (>80%): sepsis (cells can't extract O₂), left-to-right shunt, cyanide poisoning, hypothermia.", difficulty: 2 },
      { id: 1616, front: "What is the Fick equation?", back: "VO₂ = CO × (CaO₂ − CvO₂) × 10. Can be rearranged to calculate cardiac output: CO = VO₂ / [(CaO₂ − CvO₂) × 10]. Normal VO₂ (oxygen consumption): ~250 mL/min at rest. Normal CaO₂ − CvO₂ difference: ~5 mL O₂/dL. The equation relates O₂ consumption, cardiac output, and arteriovenous O₂ content difference.", difficulty: 3 },
      { id: 1617, front: "What is the difference between PaO₂ and SaO₂?", back: "PaO₂: partial pressure of dissolved O₂ in arterial blood (mmHg). Reflects driving pressure for O₂ diffusion. SaO₂: percentage of hemoglobin saturated with O₂ (%). Reflects O₂ bound to hemoglobin (the main O₂ carrier). They're related via the oxyhemoglobin dissociation curve but not linearly. SpO₂ is the pulse oximetry estimate of SaO₂.", difficulty: 1 },
      { id: 1618, front: "What is the P50 value and how is it used?", back: "PaO₂ at which hemoglobin is 50% saturated. Normal P50: 26.6-27 mmHg. Increased P50 (>27): rightward shift, decreased affinity (easier O₂ release). Decreased P50 (<27): leftward shift, increased affinity (harder O₂ release). Measured in the lab. Helps characterize abnormal hemoglobin variants and conditions affecting O₂ affinity.", difficulty: 2 },
      { id: 1619, front: "How does anemia affect oxygenation parameters?", back: "PaO₂ and SaO₂: NORMAL (hemoglobin that exists is fully oxygenated). CaO₂: DECREASED (less hemoglobin to carry O₂). DO₂: DECREASED (if cardiac output doesn't compensate). SpO₂: NORMAL (measures saturation of available Hgb, not total content). This is why SpO₂ can be falsely reassuring in anemia — tissue hypoxia may exist with normal SpO₂.", difficulty: 2 },
      { id: 1620, front: "What is methemoglobinemia?", back: "Hemoglobin with iron in Fe³⁺ state (normally Fe²⁺ in functioning hemoglobin). MetHb can't bind O₂ and shifts remaining HbO₂ curve leftward. Causes: dapsone, topical anesthetics (benzocaine, lidocaine), nitrites. Symptoms: cyanosis unresponsive to O₂ at MetHb >15%, chocolate-brown blood. SpO₂ reads ~85% regardless. Treatment: methylene blue 1-2 mg/kg IV.", difficulty: 2 },
      { id: 1621, front: "What is the relationship between compliance, resistance, and time constant?", back: "Time constant (τ) = Compliance × Resistance. Represents time for alveolus to fill/empty to 63% of final volume. 3 × τ = 95% equilibration, 5 × τ = 99%. High compliance + high resistance (emphysema): long time constant → slow filling/emptying → needs long expiratory time. Low compliance (ARDS): short time constant → faster filling but higher pressures needed.", difficulty: 2 },
      { id: 1622, front: "What is the West zones of the lung model?", back: "Zone 1 (apex): PA > Pa > Pv → alveolar dead space (perfusion compressed). Zone 2 (middle): Pa > PA > Pv → intermittent flow (waterfall effect). Zone 3 (base): Pa > Pv > PA → continuous flow (best V/Q matching). Zone 4 (lowest): interstitial pressure may compress vessels. PEEP can convert Zone 3 to Zone 1 (increased dead space).", difficulty: 3 },
      { id: 1623, front: "What is the critical DO₂?", back: "The oxygen delivery below which oxygen consumption (VO₂) becomes supply-dependent. Normal: VO₂ is maintained constant over a wide range of DO₂ (by increasing extraction). Below critical DO₂ (~300-330 mL O₂/min/m²), VO₂ drops proportionally → anaerobic metabolism → lactic acidosis → organ failure → death. Goal: keep DO₂ above critical threshold.", difficulty: 3 },
      { id: 1624, front: "What is the effect of positive pressure ventilation on V/Q matching?", back: "PPV preferentially distributes gas to non-dependent (anterior) lung regions (which may already be well-ventilated). Blood flow remains gravity-dependent (posterior/dependent). Result: increased V/Q mismatch and dead space in some areas. PEEP can recruit dependent alveoli and improve V/Q. Prone position reverses this effect.", difficulty: 2 },
      { id: 1625, front: "How does carbon monoxide affect oxygen transport?", back: "CO binds hemoglobin with 200-250× greater affinity than O₂ → forms carboxyhemoglobin (COHb). Effects: 1) Reduces available Hgb for O₂ transport. 2) Shifts O₂ dissociation curve left (remaining O₂ held tighter). 3) SpO₂ falsely normal (pulse ox can't distinguish COHb from HbO₂). Diagnosis: co-oximetry. Treatment: 100% O₂.", difficulty: 2 }
    ]
  },
  {
    id: "compliance-resistance-mechanics",
    name: "Compliance, Resistance & Lung Mechanics",
    description: "Static and dynamic compliance, airway resistance, work of breathing, time constants, and pressure-volume relationships",
    category: "Physiology",
    tier: "allied",
    cards: [
      { id: 1701, front: "What is lung compliance?", back: "The change in volume per unit change in pressure (ΔV/ΔP). Measures how easily the lung can be distended. Normal: 200 mL/cmH₂O (lung alone), 100 mL/cmH₂O (lung + chest wall — total system). High compliance: easy to inflate (emphysema). Low compliance: stiff, hard to inflate (ARDS, fibrosis, pulmonary edema).", difficulty: 1 },
      { id: 1702, front: "What is the difference between static and dynamic compliance?", back: "Static (Cstat): measured during zero flow (inspiratory hold). Cstat = Vt / (Pplat − PEEP). Reflects elastic properties only. Normal: 60-100 mL/cmH₂O on ventilator. Dynamic (Cdyn): measured during flow. Cdyn = Vt / (PIP − PEEP). Reflects elastic properties + airway resistance. Cdyn is always lower than Cstat.", difficulty: 2 },
      { id: 1703, front: "What conditions decrease lung compliance?", back: "Pulmonary: ARDS, pulmonary fibrosis, pulmonary edema, pneumonia (consolidation), atelectasis, pneumothorax, pleural effusion, surfactant deficiency. Extrapulmonary: obesity, ascites, abdominal compartment syndrome, chest wall deformity (kyphoscoliosis), circumferential burns, pregnancy. All require higher pressures to deliver same volume.", difficulty: 1 },
      { id: 1704, front: "What conditions increase lung compliance?", back: "Emphysema (loss of elastic recoil from alveolar wall destruction). Normal aging (mild increase). Compliance increased = lungs inflate easily but don't recoil well → air trapping, hyperinflation. Result: increased TLC, increased RV, decreased expiratory flow, dynamic hyperinflation during exercise.", difficulty: 1 },
      { id: 1705, front: "What is airway resistance?", back: "Opposition to airflow through the airways. Raw = ΔP / Flow = (PIP − Pplat) / Flow. Normal: 0.5-2.5 cmH₂O/L/sec (with ETT: 5-10 cmH₂O/L/sec due to tube resistance). Determined by: airway caliber (most important — resistance ∝ 1/r⁴), length, flow type (turbulent vs laminar), gas density/viscosity.", difficulty: 2 },
      { id: 1706, front: "What is Poiseuille's Law and how does it apply to airways?", back: "Resistance = 8ηL / πr⁴ (for laminar flow). Resistance is inversely proportional to the FOURTH POWER of the radius. Halving the radius → 16× increase in resistance. Clinical significance: small reductions in airway caliber (edema, bronchospasm, secretions) cause dramatic resistance increases, especially in small airways/pediatric patients.", difficulty: 2, clinicalPearl: "This is why 1mm of subglottic edema in an infant (4mm airway) is catastrophic — it reduces the radius by 25%, increasing resistance 16-fold." },
      { id: 1707, front: "What causes increased airway resistance?", back: "Inside airway: secretions, mucus plugging, foreign body, tumor, edema. Airway wall: bronchospasm (smooth muscle contraction), mucosal edema/inflammation, airway remodeling. Outside airway: dynamic compression (forced exhalation in COPD), tumor compression, lymphadenopathy. Also: small ETT, kinked ETT/circuit.", difficulty: 1 },
      { id: 1708, front: "What is the work of breathing (WOB)?", back: "Energy expended to move air in and out of lungs. Components: elastic WOB (overcoming compliance — lung recoil and chest wall) and resistive WOB (overcoming airway resistance and tissue friction). Normal: ~0.5 J/L (5% of total body O₂ consumption). In respiratory failure: can increase to 30% of O₂ consumption → respiratory muscle fatigue.", difficulty: 2 },
      { id: 1709, front: "How does WOB differ between obstructive and restrictive disease?", back: "Obstructive: increased resistive WOB. Patients compensate with slow, deep breathing (reduces turbulent flow). Intrinsic PEEP adds threshold load. Restrictive: increased elastic WOB. Patients compensate with rapid, shallow breathing (avoids high transpulmonary pressures). Both patterns increase total WOB and may lead to fatigue.", difficulty: 2 },
      { id: 1710, front: "What is the pressure-volume (P-V) curve of the lung?", back: "Plots lung volume against transpulmonary pressure. S-shaped curve. Lower inflection point (LIP): pressure where recruitment begins (historical PEEP target). Upper inflection point (UIP): pressure above which overdistension occurs. Hysteresis: deflation curve differs from inflation curve (less pressure needed to keep alveoli open than to open them). Zone of safety between LIP and UIP.", difficulty: 2 },
      { id: 1711, front: "What is hysteresis in the P-V curve?", back: "The inflation limb requires higher pressure than the deflation limb for the same volume. Due to: surface tension forces (surfactant reduces this), tissue viscosity, recruitment/derecruitment dynamics. Clinical significance: once alveoli are recruited, they stay open at lower pressure → PEEP keeps recruited alveoli open (requires less pressure than initial recruitment).", difficulty: 3 },
      { id: 1712, front: "What is LaPlace's Law and how does it apply to alveoli?", back: "P = 2T/r (pressure = 2 × surface tension / radius). Smaller alveoli need higher pressure to stay open. Without surfactant: small alveoli would collapse into larger ones (atelectasis). Surfactant reduces surface tension more in smaller alveoli → equalizes pressure → prevents collapse. Surfactant deficiency (RDS) → atelectasis.", difficulty: 2 },
      { id: 1713, front: "What is the time constant and how does it vary across the lung?", back: "τ = C × R (compliance × resistance). Time for 63% volume change. Varies across lung units. Normal: ~0.3-0.5 seconds. Fast time constant units (low C, normal R): fill quickly (ARDS). Slow time constant units (normal C, high R): fill slowly (COPD). Mismatch in time constants → uneven ventilation distribution → V/Q mismatch.", difficulty: 2 },
      { id: 1714, front: "How many time constants are needed for complete alveolar filling?", back: "1τ: 63% filled. 2τ: 86%. 3τ: 95%. 4τ: 98%. 5τ: 99% (considered complete). For exhalation: same timing applies. In COPD (long τ of 1-2 seconds): 5τ = 5-10 seconds needed for complete exhalation. If expiratory time is shorter → air trapping → auto-PEEP. This is why low respiratory rates are important in obstructive disease.", difficulty: 2 },
      { id: 1715, front: "What is the transpulmonary pressure (PL)?", back: "PL = Paw − Ppleural. Represents the actual distending pressure of the lung (separates lung from chest wall contribution). Measured using esophageal manometry (estimates pleural pressure). Target: end-inspiratory PL < 20-25 cmH₂O, end-expiratory PL > 0 (ensures alveoli remain open). Important in obese patients where Pplat may be high due to chest wall, not lung overdistension.", difficulty: 3 },
      { id: 1716, front: "What is the functional residual capacity (FRC) and its clinical importance?", back: "FRC: lung volume at end of normal exhalation (equilibrium of chest wall expansion and lung recoil). Normal: ~2.4L. O₂ reservoir between breaths. PEEP increases FRC. Decreased FRC: atelectasis, ARDS, supine position, obesity → decreased O₂ reserve → faster desaturation during apnea. Increased FRC: emphysema (hyperinflation) → flattened diaphragm.", difficulty: 1 },
      { id: 1717, front: "What is dynamic hyperinflation?", back: "Progressive air trapping during exercise or rapid breathing in obstructive disease. End-expiratory lung volume (EELV) increases above FRC as respiratory rate increases and expiratory time shortens. Results in: increased WOB, diaphragm disadvantage (shortened), decreased inspiratory capacity, dyspnea, exercise limitation. Worsens with exercise.", difficulty: 2 },
      { id: 1718, front: "What is the oxygen cost of breathing?", back: "The fraction of total body O₂ consumption used by respiratory muscles. Normal: ~5% of VO₂ (12-15 mL O₂/min). In respiratory failure: can increase to 30-50% of VO₂ → respiratory muscles 'steal' O₂ from other organs → contributes to multi-organ dysfunction. This is a key reason for mechanical ventilation — to reduce O₂ cost of breathing.", difficulty: 2 },
      { id: 1719, front: "How does COPD affect lung mechanics?", back: "Destruction of alveolar walls → loss of elastic recoil → increased compliance. Loss of radial traction on airways → early airway closure. Air trapping → hyperinflation → increased FRC, TLC, RV. Flattened diaphragm (mechanical disadvantage). Increased airway resistance (mucus, inflammation). Result: increased WOB, expiratory flow limitation, dynamic hyperinflation.", difficulty: 2 },
      { id: 1720, front: "How does ARDS affect lung mechanics?", back: "Diffuse alveolar damage → surfactant dysfunction → atelectasis → decreased compliance. 'Baby lung' concept: only 1/3 of lung aerated. Heterogeneous: some regions collapsed, some normal, some overdistended. Increased elastance (1/compliance). Result: need high pressure for small volumes, high WOB, refractory hypoxemia. Treated with low Vt, adequate PEEP.", difficulty: 2 },
      { id: 1721, front: "What is the chest wall compliance and when is it relevant?", back: "Chest wall compliance: ease of chest wall expansion. Normally ~200 mL/cmH₂O. Total respiratory system compliance = 1/(1/Clung + 1/Ccw) ≈ 100 mL/cmH₂O. Decreased Ccw: obesity, ascites, chest wall burns, kyphoscoliosis, abdominal compartment syndrome. Low Ccw → Pplat may be high even with normal lung compliance → use esophageal manometry to guide PEEP.", difficulty: 3, clinicalPearl: "In morbidly obese patients, high Pplat may reflect stiff chest wall, not overdistended lungs. Esophageal pressure monitoring separates chest wall from lung contribution." },
      { id: 1722, front: "What is the concept of stress and strain in lung mechanics?", back: "Stress: force per unit area applied to lung tissue (reflected by transpulmonary pressure). Strain: deformation relative to resting lung volume (Vt/FRC). VILI occurs when stress and/or strain exceed tissue tolerance. Lung-protective ventilation limits strain (low Vt) and stress (low Pplat). Driving pressure (Pplat − PEEP) is a clinical surrogate for strain.", difficulty: 3 },
      { id: 1723, front: "What is the elastic recoil pressure of the lung?", back: "Tendency of the lung to collapse inward. Due to: elastic fibers (elastin, collagen) and surface tension (air-liquid interface in alveoli). Balanced by outward recoil of chest wall at FRC. Decreased elastic recoil: emphysema (elastic fiber destruction) → hyperinflation. Increased elastic recoil: fibrosis → restriction. Surfactant reduces surface tension component.", difficulty: 2 },
      { id: 1724, front: "What is the equation of motion for the respiratory system?", back: "Pmus + Pvent = (Vt/C) + (R × Flow) + PEEP. Total pressure (muscle + ventilator) must overcome: elastic forces (Vt/C = elastance × volume), resistive forces (R × Flow), and PEEP. During spontaneous breathing: Pvent = 0, all work is Pmus. During full ventilatory support: Pmus = 0, all work is Pvent. Partially supported: shared.", difficulty: 3 },
      { id: 1725, front: "What is the effect of body position on lung mechanics?", back: "Upright: FRC highest, best ventilation distribution, diaphragm in optimal position. Supine: FRC decreases (abdominal contents push diaphragm up), increased closing volume, more V/Q mismatch, dependent atelectasis. Lateral: upper lung better ventilated, lower lung better perfused. Prone: more uniform ventilation, recruits dorsal lung, improves V/Q in ARDS.", difficulty: 2 }
    ]
  },
  {
    id: "resp-pharm-emergency-meds",
    name: "Respiratory Pharmacology: Emergency Medications",
    description: "ACLS drugs, vasopressors, antiarrhythmics, and emergency respiratory medications for critical care and TMC exam prep",
    category: "Respiratory Pharmacology",
    tier: "allied",
    cards: [
      { id: 1801, front: "What is the role of epinephrine in cardiac arrest?", back: "First-line vasopressor in cardiac arrest. Dose: 1 mg IV/IO q3-5 min (1:10,000 for IV). MOA: alpha-1 → vasoconstriction → increases coronary perfusion pressure; beta-1 → increases heart rate and contractility. Given in all arrest rhythms (VF/pVT, PEA, asystole). High-dose epinephrine no longer recommended.", difficulty: 1, clinicalPearl: "Epinephrine improves ROSC rates but has not been shown to improve neurologically intact survival — quality CPR and early defibrillation remain the priorities." },
      { id: 1802, front: "What is amiodarone and when is it used in respiratory/critical care?", back: "Class III antiarrhythmic. Used for VF/pVT refractory to defibrillation: 300 mg IV bolus, then 150 mg repeat. Also for stable wide-complex tachycardia: 150 mg over 10 min. Side effects: hypotension, bradycardia. Long-term: pulmonary toxicity (fibrosis), thyroid dysfunction, hepatotoxicity, corneal deposits.", difficulty: 2 },
      { id: 1803, front: "What is atropine and when is it used?", back: "Anticholinergic (muscarinic antagonist). Dose: 0.5 mg IV q3-5 min (max 3 mg) for symptomatic bradycardia. Also used pre-intubation in pediatrics to prevent vagal-mediated bradycardia. MOA: blocks parasympathetic (vagal) tone → increases heart rate, reduces secretions. Not recommended for asystole/PEA in current ACLS.", difficulty: 1 },
      { id: 1804, front: "What is the role of vasopressin in critical care?", back: "Non-adrenergic vasopressor. MOA: V1 receptor agonist → vascular smooth muscle contraction. Used in: septic shock (as adjunct to norepinephrine, dose 0.03-0.04 U/min), variceal bleeding, diabetes insipidus. Does not increase myocardial O₂ demand (unlike catecholamines). No longer recommended as alternative to epinephrine in cardiac arrest (2020 AHA).", difficulty: 2 },
      { id: 1805, front: "What is norepinephrine (Levophed) and its role in critical care?", back: "First-line vasopressor for septic shock. MOA: potent alpha-1 agonist (vasoconstriction) + beta-1 (increased contractility). Dose: 0.1-0.5 mcg/kg/min titrated to MAP ≥ 65 mmHg. Administered via central line (extravasation → tissue necrosis). Side effects: peripheral ischemia, arrhythmias, reflex bradycardia.", difficulty: 2 },
      { id: 1806, front: "What is naloxone (Narcan) and how is it used?", back: "Opioid antagonist. MOA: competitive antagonist at mu, kappa, and delta opioid receptors. Dose: 0.4-2 mg IV/IM/IN q2-3 min. Used for opioid overdose with respiratory depression. Onset: 1-2 min IV, 2-5 min IM/IN. Duration: 30-90 min (shorter than most opioids — may need repeat dosing or infusion). Can precipitate acute withdrawal.", difficulty: 1, clinicalPearl: "Titrate naloxone to respiratory rate, not consciousness — giving too much can cause acute withdrawal with vomiting, aspiration, and combativeness." },
      { id: 1807, front: "What is flumazenil (Romazicon)?", back: "Benzodiazepine antagonist. MOA: competitive antagonist at GABA-A benzodiazepine binding site. Dose: 0.2 mg IV over 15 seconds, may repeat q1 min (max 3-5 mg). Duration: 45-90 min. Caution: may precipitate seizures in chronic benzodiazepine users or mixed overdoses. Not routinely used in undifferentiated overdose.", difficulty: 2 },
      { id: 1808, front: "What is the role of sodium bicarbonate in emergency medicine?", back: "Dose: 1 mEq/kg IV. Indications: severe metabolic acidosis (pH < 7.1), hyperkalemia with ECG changes, tricyclic antidepressant overdose (sodium channel blockade), prolonged cardiac arrest. Not routine in arrest. Risks: metabolic alkalosis, hypernatremia, paradoxical intracellular acidosis, hypokalemia. Ensure adequate ventilation.", difficulty: 2 },
      { id: 1809, front: "What is adenosine and how is it used?", back: "Endogenous nucleoside. Used for SVT (supraventricular tachycardia) with narrow QRS. Dose: 6 mg rapid IV push (followed by 20 mL NS flush), then 12 mg if needed. Half-life: < 10 seconds. Causes transient AV nodal block. Side effects: flushing, chest tightness, brief asystole (warn patient). Contraindicated in wide-complex tachycardia of unknown origin.", difficulty: 2 },
      { id: 1810, front: "What is dopamine and what are its dose-dependent effects?", back: "Catecholamine with dose-dependent receptor activity. Low dose (1-5 mcg/kg/min): dopaminergic (renal vasodilation — clinically insignificant). Medium (5-10 mcg/kg/min): beta-1 → increased HR and contractility. High (10-20 mcg/kg/min): alpha-1 → vasoconstriction. Used as second-line vasopressor in septic shock (increased arrhythmia risk vs norepinephrine).", difficulty: 2 },
      { id: 1811, front: "What is dobutamine and when is it indicated?", back: "Synthetic catecholamine. Primarily beta-1 agonist with some beta-2 activity. Dose: 2-20 mcg/kg/min. MOA: increases cardiac contractility and output without significant vasoconstriction. Used for cardiogenic shock and acute decompensated heart failure with low CO. May cause hypotension (beta-2 vasodilation) and tachycardia.", difficulty: 2 },
      { id: 1812, front: "What is phenylephrine and its role in critical care?", back: "Pure alpha-1 agonist. MOA: peripheral vasoconstriction without direct cardiac stimulation. Dose: 100-500 mcg IV bolus or 0.1-0.5 mcg/kg/min infusion. Used for hypotension without cardiac dysfunction (e.g., neurogenic shock, anesthesia-induced hypotension). May cause reflex bradycardia. Useful when tachycardia limits other vasopressors.", difficulty: 2 },
      { id: 1813, front: "What is calcium chloride/gluconate and when is it used emergently?", back: "Calcium chloride 10%: 1g IV (contains 272 mg elemental Ca). Calcium gluconate: 1-3g IV (contains 93 mg elemental Ca per gram). Indications: hyperkalemia with ECG changes (stabilizes cardiac membrane), calcium channel blocker overdose, hypermagnesemia, hypocalcemia with tetany. Give slowly — can cause bradycardia/arrest if pushed too fast.", difficulty: 2 },
      { id: 1814, front: "What is lidocaine and its uses in emergency/critical care?", back: "Class IB antiarrhythmic and local anesthetic. ACLS: alternative to amiodarone for VF/pVT (1-1.5 mg/kg IV, then 0.5-0.75 mg/kg q5-10 min, max 3 mg/kg). Also used for RSI (attenuates ICP rise during laryngoscopy, 1.5 mg/kg IV). Toxicity: perioral numbness, tinnitus, seizures, cardiac arrest.", difficulty: 2 },
      { id: 1815, front: "What is the role of dextrose (D50) in emergency medicine?", back: "50% dextrose in water (25g in 50 mL). Indications: symptomatic hypoglycemia (blood glucose < 60 mg/dL with altered mental status). Dose: 25-50 mL (12.5-25g) IV push. Always check glucose before administering. Pediatric: D10W or D25W (D50 is too concentrated/hyperosmolar for children — risk of sclerosis).", difficulty: 1 }
    ]
  },
  {
    id: "resp-pharm-sedation-paralytics",
    name: "Respiratory Pharmacology: Sedation & Paralytic Agents",
    description: "ICU sedation, RSI medications, neuromuscular blocking agents, and sedation scales for ventilated patients",
    category: "Respiratory Pharmacology",
    tier: "allied",
    cards: [
      { id: 1901, front: "What is the goal of sedation in mechanically ventilated patients?", back: "Target light sedation (RASS −2 to 0) unless deep sedation is specifically required (ARDS proning, paralysis, status epilepticus). Benefits of light sedation: shorter MV duration, shorter ICU stay, less delirium, earlier mobilization. Use validated scales: RASS (Richmond Agitation-Sedation Scale) or SAS (Sedation-Agitation Scale).", difficulty: 1, clinicalPearl: "Daily sedation interruption ('wake-up trials') combined with spontaneous breathing trials (SAT/SBT protocol) reduce ventilator days and mortality." },
      { id: 1902, front: "What is propofol and what are its key properties?", back: "GABA-A receptor agonist. Onset: 15-45 seconds. Duration: 5-10 min. Dose: induction 1-2.5 mg/kg IV; infusion 5-50 mcg/kg/min. Advantages: rapid on/off, anticonvulsant, reduces ICP. Side effects: hypotension, respiratory depression, pain on injection, hypertriglyceridemia. Propofol infusion syndrome (PRIS) with high doses >48h: metabolic acidosis, rhabdomyolysis, cardiac failure.", difficulty: 2 },
      { id: 1903, front: "What is midazolam (Versed) and its use in respiratory care?", back: "Short-acting benzodiazepine. MOA: enhances GABA-A receptor activity. Onset: 1-5 min IV. Duration: 30-60 min. Dose: sedation 0.02-0.1 mg/kg; infusion 0.02-0.1 mg/kg/hr. Advantages: anxiolytic, amnestic, anticonvulsant. Disadvantages: active metabolite accumulates in renal failure, contributes to delirium, prolonged sedation with continuous infusion.", difficulty: 2 },
      { id: 1904, front: "What is dexmedetomidine (Precedex)?", back: "Alpha-2 adrenergic agonist. Dose: loading 1 mcg/kg over 10 min, infusion 0.2-1.5 mcg/kg/hr. Unique: provides sedation WITHOUT respiratory depression (patient can be extubated on it). Advantages: no respiratory depression, reduces delirium, analgesic properties. Side effects: bradycardia, hypotension. Preferred for light ICU sedation.", difficulty: 2, clinicalPearl: "Dexmedetomidine is ideal for patients being weaned from mechanical ventilation — it provides sedation while preserving respiratory drive." },
      { id: 1905, front: "What is succinylcholine and when is it used for RSI?", back: "Depolarizing neuromuscular blocker. MOA: mimics ACh at nicotinic receptors → sustained depolarization → paralysis. Dose: 1-1.5 mg/kg IV. Onset: 30-60 seconds. Duration: 5-10 min (metabolized by pseudocholinesterase). Fastest onset of any paralytic. Contraindications: hyperkalemia risk (burns >24h, crush injury, denervation, spinal cord injury), malignant hyperthermia history.", difficulty: 2 },
      { id: 1906, front: "What is rocuronium and how does it compare to succinylcholine?", back: "Non-depolarizing NMB agent (aminosteroid). MOA: competitive antagonist at nicotinic ACh receptors. Dose: RSI 1-1.2 mg/kg (modified rapid sequence). Onset: 60-90 seconds. Duration: 30-60 min. No hyperkalemia risk. Reversible with sugammadex (immediate reversal). Preferred over succinylcholine in many centers due to safer profile.", difficulty: 2 },
      { id: 1907, front: "What is sugammadex (Bridion)?", back: "Selective relaxant binding agent. MOA: encapsulates rocuronium (and vecuronium) forming inactive complex — reverses neuromuscular blockade within minutes. Dose: 2-16 mg/kg depending on depth of block. Can reverse even deep blockade. Faster and more reliable than neostigmine. Expensive. Changed RSI practice — makes rocuronium preferred over succinylcholine.", difficulty: 2 },
      { id: 1908, front: "What is cisatracurium (Nimbex) and when is it used in the ICU?", back: "Non-depolarizing NMB (benzylisoquinolinium). Dose: 0.15-0.2 mg/kg bolus; infusion 1-3 mcg/kg/min. Undergoes Hofmann elimination (organ-independent degradation) — safe in renal/hepatic failure. Used for ICU paralysis in severe ARDS (48 hours to improve oxygenation with proning/deep sedation). Always ensure adequate sedation first — paralysis without sedation is torture.", difficulty: 2 },
      { id: 1909, front: "What is the RASS (Richmond Agitation-Sedation Scale)?", back: "+4: combative. +3: very agitated. +2: agitated. +1: restless. 0: alert and calm. −1: drowsy (sustained awakening to voice). −2: light sedation (briefly awakens to voice). −3: moderate sedation (movement to voice, no eye contact). −4: deep sedation (no response to voice, movement to physical stimulation). −5: unarousable. Target: −2 to 0.", difficulty: 1 },
      { id: 1910, front: "What is ketamine and its role in respiratory care?", back: "NMDA receptor antagonist. Dissociative anesthetic. Dose: induction 1-2 mg/kg IV; procedural sedation 0.5-1 mg/kg. Unique: preserves respiratory drive, bronchodilator (releases catecholamines), maintains BP. Used in: RSI (especially in bronchospasm, hypotension), procedural sedation, refractory status asthmaticus. Side effects: emergence reactions, increased secretions, increased ICP (controversial).", difficulty: 2 },
      { id: 1911, front: "What is fentanyl and its properties relevant to respiratory therapy?", back: "Synthetic opioid, 100× more potent than morphine. Onset: 1-2 min IV. Duration: 30-60 min. Dose: 1-2 mcg/kg for analgesia/sedation; infusion 1-2 mcg/kg/hr. Advantages: hemodynamically stable, no histamine release, rapid onset. Side effects: respiratory depression, chest wall rigidity (rapid high-dose bolus), bradycardia. Reversed by naloxone.", difficulty: 1 },
      { id: 1912, front: "What are the differences between depolarizing and non-depolarizing neuromuscular blockers?", back: "Depolarizing (succinylcholine): mimic ACh, cause fasciculations then paralysis, not reversible (wait for metabolism), hyperkalemia risk. Non-depolarizing (rocuronium, cisatracurium, vecuronium): competitive ACh antagonists, no fasciculations, reversible (neostigmine or sugammadex), no hyperkalemia risk, longer duration.", difficulty: 2 },
      { id: 1913, front: "What is the train-of-four (TOF) and how is it used to monitor paralysis?", back: "Peripheral nerve stimulator delivers 4 electrical impulses. Count twitches to assess NMB depth: 4/4 twitches = minimal blockade. 2/4 twitches = moderate blockade (target for ICU paralysis). 1/4 = deep blockade. 0/4 = complete blockade (overdose risk). Monitor ulnar nerve (thumb adduction) or facial nerve. Essential to prevent over-paralysis.", difficulty: 2 },
      { id: 1914, front: "What is the ICU Liberation Bundle (A-F)?", back: "A: Assess, prevent, manage pain. B: Both SAT and SBT. C: Choice of sedation (light, avoid benzos). D: Delirium assess and manage (CAM-ICU). E: Early mobility and exercise. F: Family engagement. Evidence-based bundle to reduce ventilator days, delirium, and ICU mortality. Each element independently improves outcomes.", difficulty: 1 },
      { id: 1915, front: "What is etomidate and when is it used?", back: "Imidazole derivative. GABA-A agonist. Dose: 0.3 mg/kg IV for RSI. Onset: 15-45 seconds. Duration: 5-15 min. Advantages: hemodynamically neutral (minimal BP change — ideal for hypotensive patients needing RSI). Disadvantage: adrenal suppression (inhibits 11-beta-hydroxylase) — controversial for septic patients. Myoclonus on induction.", difficulty: 2 }
    ]
  },
  {
    id: "resp-pharm-diuretics-cv",
    name: "Respiratory Pharmacology: Diuretics & CV Agents",
    description: "Diuretics, cardiac medications, and cardiovascular agents relevant to respiratory therapy and pulmonary management",
    category: "Respiratory Pharmacology",
    tier: "allied",
    cards: [
      { id: 2001, front: "What is furosemide (Lasix) and its role in respiratory care?", back: "Loop diuretic. MOA: inhibits Na-K-2Cl co-transporter in thick ascending limb of loop of Henle. Dose: 20-80 mg IV (0.5-1 mg/kg). Onset: IV 5 min, PO 30 min. Used for: pulmonary edema (acute decompensated heart failure), fluid overload in ventilated patients. Side effects: hypokalemia, hypomagnesemia, hypotension, ototoxicity, metabolic alkalosis.", difficulty: 1, clinicalPearl: "In acute pulmonary edema, furosemide's initial benefit is venodilation (reduces preload within minutes) — the diuretic effect takes 30+ minutes." },
      { id: 2002, front: "What are the electrolyte effects of loop diuretics?", back: "Hypokalemia (K⁺ wasting — most clinically significant), hyponatremia, hypocalcemia, hypomagnesemia, hypochloremia, metabolic alkalosis (contraction alkalosis + H⁺ secretion). Monitor K⁺ closely — hypokalemia increases arrhythmia risk, especially with digoxin. Replace K⁺ and Mg²⁺ aggressively. Consider potassium-sparing diuretic addition.", difficulty: 2 },
      { id: 2003, front: "What is bumetanide and how does it compare to furosemide?", back: "Loop diuretic, 40× more potent than furosemide (1 mg bumetanide ≈ 40 mg furosemide). Same MOA: Na-K-2Cl transporter inhibition. Better oral bioavailability than furosemide (80% vs 50%). Used when furosemide resistance develops. Same side effect profile. Less ototoxic than furosemide.", difficulty: 2 },
      { id: 2004, front: "What is spironolactone and when is it used?", back: "Potassium-sparing diuretic. MOA: aldosterone receptor antagonist in collecting duct → blocks Na⁺ reabsorption and K⁺ secretion. Used for: heart failure with reduced EF (reduces mortality — RALES trial), ascites, hyperaldosteronism. Side effects: hyperkalemia (monitor K⁺), gynecomastia, menstrual irregularities. Do not combine with ACE/ARB + K⁺ supplement.", difficulty: 2 },
      { id: 2005, front: "What is the role of nitroglycerin in respiratory/cardiac emergencies?", back: "Organic nitrate. MOA: releases NO → activates guanylyl cyclase → smooth muscle relaxation. Low dose: venodilation (reduces preload). Higher dose: arteriolar dilation (reduces afterload). Used for: acute pulmonary edema, angina, hypertensive emergency. Dose: 0.4 mg SL q5 min × 3 or IV infusion 5-200 mcg/min. Side effects: hypotension, headache, tachyphylaxis.", difficulty: 2 },
      { id: 2006, front: "What are ACE inhibitors and their relevance to respiratory therapy?", back: "Angiotensin-converting enzyme inhibitors (lisinopril, enalapril, captopril). MOA: block ACE → decreased angiotensin II → vasodilation + decreased aldosterone. Used for: CHF, hypertension, post-MI. Important RT side effect: dry cough (10-15%) due to bradykinin accumulation — can mimic asthma or respiratory disease. If cough intolerable → switch to ARB.", difficulty: 2 },
      { id: 2007, front: "What is the role of beta-blockers in patients with respiratory disease?", back: "Non-selective beta-blockers (propranolol, nadolol) CONTRAINDICATED in asthma/COPD — block beta-2 receptors → bronchoconstriction. Cardioselective beta-1 blockers (metoprolol, atenolol, bisoprolol) are safer but selectivity is dose-dependent. Used cautiously in COPD patients with heart failure/post-MI. Never abruptly discontinue (rebound hypertension).", difficulty: 2 },
      { id: 2008, front: "What is acetazolamide (Diamox) and its use in respiratory medicine?", back: "Carbonic anhydrase inhibitor. MOA: inhibits HCO₃⁻ reabsorption in proximal tubule → metabolic acidosis → stimulates ventilation. Uses: altitude sickness prevention/treatment, metabolic alkalosis correction, central sleep apnea (respiratory stimulant). Side effects: metabolic acidosis, hypokalemia, paresthesias, renal stones. Stimulates breathing by lowering pH.", difficulty: 2, clinicalPearl: "Acetazolamide is useful for posthypercapnic metabolic alkalosis in COPD patients who were aggressively ventilated — it helps correct the alkalosis and improves ventilatory drive." },
      { id: 2009, front: "What is digoxin and its relevance to respiratory patients?", back: "Cardiac glycoside. MOA: inhibits Na-K-ATPase → increased intracellular Ca²⁺ → increased contractility (positive inotrope). Slows AV conduction (rate control for AF). Used for: heart failure, atrial fibrillation. Narrow therapeutic index (0.5-2.0 ng/mL). Toxicity worsened by hypokalemia (common with diuretics). Signs: nausea, visual changes, arrhythmias.", difficulty: 2 },
      { id: 2010, front: "What is the role of heparin in pulmonary embolism management?", back: "Anticoagulant. Unfractionated heparin (UFH): IV bolus 80 U/kg, then infusion 18 U/kg/hr, titrate to aPTT 1.5-2.5× control. LMWH (enoxaparin): 1 mg/kg SubQ q12h. Used for confirmed PE to prevent clot propagation. Massive PE with hemodynamic instability → consider thrombolytics (alteplase) + heparin. Monitor for HIT (heparin-induced thrombocytopenia).", difficulty: 2 }
    ]
  }
];
